-- Poems batch 407
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-972','少年游','赵鼎','宋','宋词','song-ci','少年游','[]','三月正当三十日，愁杀醉吟翁。',60,'宋词/ci.song.2000.json','["三月正当三十日，愁杀醉吟翁。", "可奈青春，太无情甚，归去苦匆匆。", "共君今夜不须睡，尊酒且从容。", "说与楼头，打钟人道，休打五更钟。"]'),
('song-ci-973','贺圣朝','赵鼎','宋','宋词','song-ci','贺圣朝','[]','花光烛影春容媚。',56,'宋词/ci.song.2000.json','["花光烛影春容媚。", "香生和气。", "纷纷儿女拜翁前，劝犀尊金醴。", "凌烟图画，王侯富贵，非翁雅意。", "愿翁早早乞身归，对青山沈醉。"]'),
('song-ci-974','贺圣朝','赵鼎','宋','宋词','song-ci','贺圣朝','[]','征鞍南去天涯路。',57,'宋词/ci.song.2000.json','["征鞍南去天涯路。", "青山无数。", "更堪月下子规啼，向深山深处。", "凄然推枕，难寻新梦，忍听伊言语。", "更阑人静一声声，道不如归去。"]'),
('song-ci-975','醉蓬莱','赵鼎','宋','宋词','song-ci','醉蓬莱','[]','破新正春到，五叶尧蓂，弄芳初秀。',120,'宋词/ci.song.2000.json','["破新正春到，五叶尧蓂，弄芳初秀。", "翦彩然膏，灿华筵如昼。", "家庆图中，老莱堂上，竟祝翁遐寿。", "喜气欢容，光生玉斝，香霏金兽。", "谁会高情，淡然声利，一笑尘寰，万缘何有。", "解组归来，访渔樵朋友。", "华发苍颜，任从老去，但此情依旧。", "岁岁年年，花前月下，一尊芳酒。"]'),
('song-ci-976','小重山','赵鼎','宋','宋词','song-ci','小重山','[]','漠漠晴霓和雨收。',70,'宋词/ci.song.2000.json','["漠漠晴霓和雨收。", "长波千万里，拍天流。", "云帆烟棹去悠悠。", "西风里，归兴满沧州。", "谩道醉忘忧。", "荡高怀远恨，更悲秋。", "一眉山色为谁愁。", "黄昏也，独自倚危楼。"]'),
('song-ci-977','惜双双・惜分飞','赵鼎','宋','宋词','song-ci','惜双双・惜分飞','[]','度陇信音谁与寄。',60,'宋词/ci.song.2000.json','["度陇信音谁与寄。", "肠断江南千里。", "深雪前村里。", "一枝昨夜传芳意。", "冷蕊暗香空旖旎。", "也应是、春来憔悴。", "风度将谁比。", "忆曾插向香罗□。"]'),
('song-ci-978','西江月','赵鼎','宋','宋词','song-ci','西江月','[]','世态浮云易变，时光飞箭难留。',58,'宋词/ci.song.2000.json','["世态浮云易变，时光飞箭难留。", "五年重见海东头。", "只有交情似旧。", "未尽别来深意，难堪老去离愁。", "青山迢递水悠悠。", "明日扁舟病酒。"]'),
('song-ci-979','行香子','赵鼎','宋','宋词','song-ci','行香子','[]','草色芊绵。',84,'宋词/ci.song.2000.json','["草色芊绵。", "雨点阑斑。", "糁飞花、还是春残。", "天涯万里，海上三年。", "试倚危楼，将远恨，卷帘看。", "举头见日，不见长安。", "谩凝眸、老泪凄然。", "山禽飞去，榕叶生寒。", "到黄昏也，独自个，尚凭阑。"]'),
('song-ci-980','醉桃园・桃源忆故人','赵鼎','宋','宋词','song-ci','醉桃园・桃源忆故人','[]','青春不与花为主。',56,'宋词/ci.song.2000.json','["青春不与花为主。", "花正开时春暮。", "花下醉眠休诉。", "看取春归去。", "莺愁蝶怨春知否。", "欲问春归何处。", "只有一尊芳醑。", "留得青春住。"]'),
('song-ci-981','浪淘沙','赵鼎','宋','宋词','song-ci','浪淘沙','[]','霜露日凄凉。',64,'宋词/ci.song.2000.json','["霜露日凄凉。", "北雁南翔。", "惊风吹起不成行。", "吊影苍波何限恨，日暮天长。", "为尔惜流光。", "还是重阳。", "故人何处舣危墙。", "寄我相思千点泪，直过潇湘。"]'),
('song-ci-982','浪淘沙','赵鼎','宋','宋词','song-ci','浪淘沙','[]','玉宇洗秋晴。',64,'宋词/ci.song.2000.json','["玉宇洗秋晴。", "凉月亭亭。", "梦回孤枕琐窗明。", "何处飞来三弄笛，风露凄清。", "曾看玉纤横。", "苦爱新声。", "由来百虑为愁生。", "此夜曲中闻折柳，都是离情。"]'),
('song-ci-983','青玉案','蒋璨','宋','宋词','song-ci','青玉案','["\u897f\u6e56"]','三年枕上吴中路。',80,'宋词/ci.song.2000.json','["三年枕上吴中路。", "遣黄耳、随君去。", "欲过松江呼小渡。", "莫惊鸥鹭，四桥都是，老子经行处。", "辋川图上看春暮。", "长忆高人右丞句。", "作个归期天未许。", "春衫犹是，小蛮针线，曾湿西湖雨。"]'),
('song-ci-984','汉宫春','李邴','宋','宋词','song-ci','汉宫春','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','潇洒江梅，向竹梢疏处，横两三枝。',118,'宋词/ci.song.2000.json','["潇洒江梅，向竹梢疏处，横两三枝。", "东君也不爱惜，雪压霜欺。", "无情燕子，怕春寒、轻失花期。", "却是有，年年塞雁，归来曾见开时。", "清浅小溪如练，问玉堂何似，茅舍疏篱。", "伤心故人去后，冷落新诗。", "微云淡月，对江天、分付他谁。", "空自忆，清香未减，风流不在人知。"]'),
('song-ci-985','洞仙歌','李邴','宋','宋词','song-ci','洞仙歌','[]','一团娇软，是将春揉做，撩乱随风到何处。',104,'宋词/ci.song.2000.json','["一团娇软，是将春揉做，撩乱随风到何处。", "自长亭、人去后，烟草萋迷，归来了、装点离愁无数。", "飘扬无个事，刚被萦牵，长是黄昏怕微雨。", "记那回，深院静，帘幕低垂，花阴下、霎时留住。", "又只恐、伊家太轻狂，蓦地和春，带将归去。"]'),
('song-ci-986','玉蝴蝶','李邴','宋','宋词','song-ci','玉蝴蝶','[]','壮岁分符方面，惠风草偃，禾稼春融。',124,'宋词/ci.song.2000.json','["壮岁分符方面，惠风草偃，禾稼春融。", "报政朝天，归去稳步鳌宫。", "望尧斝、九重绛阙，颁汉诏、五色芝封。", "湛恩浓。", "锦衣槐里，重继三公。", "雍容。", "临歧祖帐，绮罗环列，冠盖云丛。", "满城桃李，尽将芳意谢东风。", "柳烟轻、万条离恨，花露重、千点啼红。", "莫匆匆。", "且陪珠履，同醉金锺。"]'),
('song-ci-987','念奴娇','李邴','宋','宋词','song-ci','念奴娇','[]','素光练净，映秋山、隐隐修眉横绿。',120,'宋词/ci.song.2000.json','["素光练净，映秋山、隐隐修眉横绿。", "鳷鹊楼高天似水，碧瓦寒生银粟。", "千丈斜晖，奔云涌雾，飞过卢仝屋。", "更无尘气，满庭风碎梧竹。", "谁念鹤发仙翁，当年曾共赏，紫岩飞瀑。", "对影三人聊痛饮，一洗离愁千斛。", "斗转参横，翩然归去，万里骑黄鹄。", "满川霜晓，叫云吹断横玉。"]'),
('song-ci-988','小冲山・小重山','李邴','宋','宋词','song-ci','小冲山・小重山','[]','谁劝东风腊里来。',70,'宋词/ci.song.2000.json','["谁劝东风腊里来。", "不知天待雪，恼江梅。", "东郊寒色尚徘徊。", "双彩燕，飞傍鬓云堆。", "玉冷晓妆台。", "宜春金缕字，拂香腮。", "红罗先绣踏青鞋。", "春犹浅，花信更须催。"]'),
('song-ci-989','木兰花・玉楼春','李邴','宋','宋词','song-ci','木兰花・玉楼春','[]','沈吟不语晴窗畔。',64,'宋词/ci.song.2000.json','["沈吟不语晴窗畔。", "小字银钩题欲遍。", "云情散乱未成篇，花骨敧斜终带软。", "重重说尽情和怨。", "珍重提携常在眼。", "暂时得近玉纤纤，翻羡缕金红象管。"]'),
('song-ci-990','清平乐','李邴','宋','宋词','song-ci','清平乐','[]','露花烟柳。',54,'宋词/ci.song.2000.json','["露花烟柳。", "春思浓如酒。", "几阵狂风新雨后。", "满地落红铺绣。", "风流何处疏狂。", "厌厌恨结柔肠。", "又是危阑独倚，一川烟草斜阳。"]'),
('song-ci-991','满庭芳','李邴','宋','宋词','song-ci','满庭芳','[]','又喜椒觞到手，宝胜里、仍剪金花。',16,'宋词/ci.song.2000.json','["又喜椒觞到手，宝胜里、仍剪金花。"]'),
('song-ci-992','玉楼春','李邴','宋','宋词','song-ci','玉楼春','[]','一年适尽莲花漏，翠井屠苏沈冻酒。',16,'宋词/ci.song.2000.json','["一年适尽莲花漏，翠井屠苏沈冻酒。"]'),
('song-ci-993','满庭芳','李邴','宋','宋词','song-ci','满庭芳','[]','凉风吹帽，横槊试登高。',27,'宋词/ci.song.2000.json','["凉风吹帽，横槊试登高。", "想见征西旧事，龙山会、宾主俱豪。"]'),
('song-ci-994','女冠子','李邴','宋','宋词','song-ci','女冠子','[]','帝城三五。',134,'宋词/ci.song.2000.json','["帝城三五。", "灯光花市盈路。", "天街游处。", "此时方信，凤阙都民，奢华豪富。", "纱笼才过处。", "喝道转身，一壁小来且住。", "见许多、才子艳质，携手并肩低语。", "东来西往谁家女。", "买玉梅争戴，缓步香风度。", "北观南顾。", "见画烛影里，神仙无数。", "引人魂似醉，不如趁早，步月归去。", "这一双情眼，怎生禁得，许多胡觑。"]'),
('song-ci-995','调笑令','李邴','宋','宋词','song-ci','调笑令','[]','双绿。',45,'宋词/ci.song.2000.json','["双绿。", "淡匀拂。", "两脸春融光透玉。", "起来却怕东风触。", "本是一团香玉。", "飞鸾台上看未足。", "贮向阿娇金屋。"]'),
('song-ci-996','满庭芳','向子諲','宋','宋词','song-ci','满庭芳','[]','月窟蟠根，云岩分种，绝知不是尘凡。',117,'宋词/ci.song.2000.json','["月窟蟠根，云岩分种，绝知不是尘凡。", "琉璃剪叶金粟缀花繁。", "黄菊周旋避舍，友兰蕙、羞杀山樊。", "清香远，秋风十里，鼻观已先参。", "酒阑。", "听我语，平生半是，江北江南。", "经行处、无穷绿水青山。", "常被此花相恼，思共老、结屋中间。", "不因尔，芗林底事，游戏到人寰。"]'),
('song-ci-997','满庭芳','向子諲','宋','宋词','song-ci','满庭芳','[]','瑟瑟金风，团团玉露，岩花秀发秋光。',118,'宋词/ci.song.2000.json','["瑟瑟金风，团团玉露，岩花秀发秋光。", "水边一笑，十里得清香。", "疑是蕊宫仙子，新妆就、娇额涂黄。", "霜天晚，妖红丽紫，回首总堪伤。", "中央。", "孕正色，更留明月，偏照何妨。", "便高如兰菊，也让芬芳。", "输与芗林居士，微吟罢、闲据胡床。", "须知道，天教尤物，相伴老江乡。"]'),
('song-ci-998','蓦山溪','向子諲','宋','宋词','song-ci','蓦山溪','[]','瑶田银海。',102,'宋词/ci.song.2000.json','["瑶田银海。", "浩色难为对。", "琪树照人间，晓然是、华岩境界。", "万年松径，一带旧峰峦，深掩覆，密遮藏，三昧兴无碍。", "金毛狮子，打就休惊怪。", "片片上红炉，且不可、将情作解。", "有无不道，泯绝去来今，明即暗，暗还明，只个长不昧。"]'),
('song-ci-999','蓦山溪','向子諲','宋','宋词','song-ci','蓦山溪','[]','挂冠神武。',102,'宋词/ci.song.2000.json','["挂冠神武。", "来作烟波主。", "千里好江山，都尽是、君恩赐与。", "风勾月引，催上泛宅时，酒倾玉，鲙堆雪，总道神仙侣。", "蓑衣箬笠，更着些儿雨。", "横笛两三声，晚云中、惊鸥来去。", "欲烦妙手，写入散人图，蜗角名，蝇头利，着甚来由顾。"]'),
('song-ci-0','导引','无名氏','宋','宋词','song-ci','导引','[]','长乐晚彩戏莱衣。',61,'宋词/ci.song.20000.json','["长乐晚彩戏莱衣。", "奄忽梦报仙期。", "帝乡渺渺乘鸾去，啼红嫔御不胜悲。", "苍梧烟水杳难追。", "肠断处、过江时。", "银涛千万叠，不知何处是瑶池。"]'),
('song-ci-1','六州','无名氏','宋','宋词','song-ci','六州','[]','中兴运，孝治格升平。',167,'宋词/ci.song.20000.json','["中兴运，孝治格升平。", "回騩驭，弭凤驾，册宝初上鸿名。", "龙楼问寝候鸡鸣。", "更翻莱戏彩衣轻。", "坤躔夜照老人星。", "金觞上寿，长愿燕慈宁。", "乘云何处去，愁断紫箫声。", "追思金殿，椒壁丹楹。", "又谁知、勤俭仁明。", "风行化被宫庭。", "佑圣主，底明时。", "阴功暗及生灵。", "离宫晚、花卉娉婷。", "甲观高、潮海峥嵘。", "往事回头忽飘零。", "空留嫔御，掩泣望霓旌。", "会稽山翠，永祐陵高，而今便是蓬瀛。"]'),
('song-ci-2','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','炎图景运正延鸿。',173,'宋词/ci.song.20000.json','["炎图景运正延鸿。", "文思坐深宫。", "慈宁大养，乐事时奏宸聪。", "皇龄永，恩霈下，遍寰中。", "君王乘彩服，嫔御上瑶钟。", "年年诞节，就盈吉月，交庆流虹。", "欢洽意方浓。", "不觉仙游渺邈，但号泣苍穹。", "追慕念音容。", "诗书慈俭，配古追踪。", "躬行四德，谁知继、二南风。", "移盼俄空，宝鉴脂泽尘封。", "清都远，帝乡遥，杳难通。", "想云軿、还上瀛蓬。", "稽山何在，当年禹宅，万古葱葱。", "最难堪，潮头定，海波融。"]'),
('song-ci-3','导引','无名氏','宋','宋词','song-ci','导引','[]','返虞长乐，犹是忆宾天。',59,'宋词/ci.song.20000.json','["返虞长乐，犹是忆宾天。", "何事驾仙軿。", "箫笳仪卫辞宫阙，移仗入云烟。", "於皇清庙敞华筵。", "昭穆谨承先。", "千秋长奉烝尝孝，永享中兴年。"]'),
('song-ci-4','导引','无名氏','宋','宋词','song-ci','导引','[]','鼎湖龙远，九祭毕嘉觞。',59,'宋词/ci.song.20000.json','["鼎湖龙远，九祭毕嘉觞。", "遥望白云乡。", "箫笳凄咽离天阙，千仗俨成行。", "圣神昭穆盛重光。", "宝室万年藏。", "皇心追慕思无极，孝飨奉烝尝。"]'),
('song-ci-5','导引','无名氏','宋','宋词','song-ci','导引','[]','凤箫声断，缥缈溯丹邱。',59,'宋词/ci.song.20000.json','["凤箫声断，缥缈溯丹邱。", "犹是忆河洲。", "荧煌宝册来天上，何处访仙游。", "葱葱郁郁瑞光浮。", "嘉酌侑芳羞。", "雕舆绣幰归新庙，百世与千秋。"]'),
('song-ci-6','导引','无名氏','宋','宋词','song-ci','导引','[]','中兴复古，孝治日昭鸿。',59,'宋词/ci.song.20000.json','["中兴复古，孝治日昭鸿。", "原庙饰瑰宫。", "金壁千门磻万磶，楹桷竟穹崇。", "亭童芝盖拥旌龙。", "列圣俨相从。", "共锡神孙千万寿，龟鼎亘衡嵩。"]'),
('song-ci-7','导引','无名氏','宋','宋词','song-ci','导引','[]','坤仪厚载，遗德满寰中。',59,'宋词/ci.song.20000.json','["坤仪厚载，遗德满寰中。", "归御广寒宫。", "玉容如在飚舆远，长乐起悲风。", "霓旌绛节下层空。", "云阙晓瞳昽。", "真游千载安原庙，圣孝与天通。"]'),
('song-ci-8','导引','无名氏','宋','宋词','song-ci','导引','[]','深仁厚德，流泽自无穷。',59,'宋词/ci.song.20000.json','["深仁厚德，流泽自无穷。", "仙驭倏宾空。", "衣冠未返苍梧远，遥望鼎湖龙。", "人间仿佛认天容。", "缥缈五云中。", "帝城犹有遗民在，垂泪向西风。"]'),
('song-ci-9','导引','无名氏','宋','宋词','song-ci','导引','[]','金殿晚、愁结坤宁。',63,'宋词/ci.song.20000.json','["金殿晚、愁结坤宁。", "天下母、忽仙升。", "云山浩浩归何处，但闻空际彩鸾声。", "紫箫断后无踪迹，烟霭霭，夜澄澄。", "晓梦到瑶城。", "当时花木正冥冥。"]'),
('song-ci-10','六州','无名氏','宋','宋词','song-ci','六州','[]','娟娟月，初未缺，忽沈西。',170,'宋词/ci.song.20000.json','["娟娟月，初未缺，忽沈西。", "桂枝残，寒兔下，惟见露脚斜飞。", "六宫歌笑奉瑶墀。", "一朝寂寞掩褘衣。", "夜星不动玉鸾嘶。", "沈沈何处，愁雾锁金扉。", "群仙瞻道范，肃驾到蓬池。", "紫清逸辔，飞电奔驰。", "又谁知。", "一世柔仪。", "椒涂玉钮金螭。", "赞圣主，膺天命，功勤曾佐雍熙。", "瑶天隔，玉闼低迷。", "五云高、绛府参差。", "往事如今好寻思。", "留得香笺镂管、写新诗。", "但看芳猷美，宝册传徽。", "隆名万古昭垂。"]'),
('song-ci-11','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','皇家景运合无疆。',187,'宋词/ci.song.20000.json','["皇家景运合无疆。", "天子坐明堂。", "丰年多黍，四方争报时康。", "酒常清，花易好，寿君王。", "天宫见玉女，大笑亿千场。", "不知何事，椒涂暗淡，瑶殿凄凉。", "宝镜玉台光。", "可奈画眉人去，脂泽散馀芳。", "极目望潇湘。", "波遥草远，只见残阳。", "南山古阜，松柏茂，蔚苍苍。", "杳霭宫商。", "风过金殿琳琅。", "道歌繁，严鼓近，惨悲伤。", "水凝愁，山攒恨，烟淡云黄。", "神山何在，蟠桃已远，弱水何长。", "最难堪，回翟雉，返鸾凰。", "向芙蓉别殿、谩焚香。"]'),
('song-ci-12','导引','无名氏','宋','宋词','song-ci','导引','[]','紫鸾飞去，玉殿锁坤宁，珠箔俨银屏。',59,'宋词/ci.song.20000.json','["紫鸾飞去，玉殿锁坤宁，珠箔俨银屏。", "仙家不似人间世，无处觅云軿。", "金铺肃肃湛严扃，天册下彤庭。", "嘉觞好在新宫荐，万世妥神灵。"]'),
('song-ci-13','导引','无名氏','宋','宋词','song-ci','导引','[]','秋月冷、秋鹤无声。',63,'宋词/ci.song.20000.json','["秋月冷、秋鹤无声。", "清禁晓、动皇情。", "玉笙忽断今何在，不知谁报玉楼成。", "七星授辔骖鸾种，人不见、恨难平。", "何以返霓旌。", "一天风露苦凄清。"]'),
('song-ci-14','导引','无名氏','宋','宋词','song-ci','导引','[]','皇家多庆，亲寿与天长。',59,'宋词/ci.song.20000.json','["皇家多庆，亲寿与天长。", "德业播辉光。", "焜煌宝册来清禁，玉篆映金相。", "庭闱尊奉会明昌。", "佳气溢康庄。", "洪禧申辑名增衍，亿载颂无疆。"]'),
('song-ci-15','导引','无名氏','宋','宋词','song-ci','导引','[]','上皇天大，华旦焕尧文。',59,'宋词/ci.song.20000.json','["上皇天大，华旦焕尧文。", "鸿福浩无垠。", "羽龙俄驾灵輴去，空锁鼎湖云。", "稽山翠拥浙江濆。", "归旆卷缤纷。", "仙游指日严升祔，万载颂高勋。"]'),
('song-ci-16','导引','无名氏','宋','宋词','song-ci','导引','[]','虞觞奉主，仙驭返皇宫。',59,'宋词/ci.song.20000.json','["虞觞奉主，仙驭返皇宫。", "礼典极钦崇。", "云旗前导开清庙，龙管咽薰风。", "巍巍尧父告神功。", "追慕孝诚通。", "千秋万岁中兴统，宗祀与天同。"]'),
('song-ci-17','导引','无名氏','宋','宋词','song-ci','导引','[]','中兴揖逊，功德仰兼隆。',59,'宋词/ci.song.20000.json','["中兴揖逊，功德仰兼隆。", "仁泽被华戎。", "鼎湖俄痛遗弓堕，日日想威容。", "柔仪懿范与尧同。", "飚驭俨相从。", "灵宫真馆偕来燕，垂裕永无穷。"]'),
('song-ci-18','导引','无名氏','宋','宋词','song-ci','导引','[]','皇家盛事，三殿庆重重。',59,'宋词/ci.song.20000.json','["皇家盛事，三殿庆重重。", "圣主极推崇。", "瑶编宝列相辉映，归美意何穷。", "钧韶九奏度春风。", "彩仗焕仪容。", "欢声和气弥寰宇，皇寿与天同。"]'),
('song-ci-19','导引','无名氏','宋','宋词','song-ci','导引','[]','重亲万寿，八帙衍新元。',59,'宋词/ci.song.20000.json','["重亲万寿，八帙衍新元。", "礼典备文孙。", "温温和气迎长日，宝册焕瑶琨。", "徽音显号自尧门。", "德行已该存。", "更期昌算齐箕翼，愈久愈崇尊。"]'),
('song-ci-20','导引','无名氏','宋','宋词','song-ci','导引','[]','笳鼓发、云惨寒空。',64,'宋词/ci.song.20000.json','["笳鼓发、云惨寒空。", "丹旐去、卷悲风。", "忧勤六载亲几务，有巍巍、圣德仁功。", "褰裳尊处大安宫。", "荆鼎就、遽遗弓。", "仙游攀不及，臣民号恸诉苍穹。"]'),
('song-ci-21','导引','无名氏','宋','宋词','song-ci','导引','[]','龟书畀姒，历数在皇躬。',59,'宋词/ci.song.20000.json','["龟书畀姒，历数在皇躬。", "揖逊仰高风。", "鼎湖龙去遗弓堕，冠剑锁深宫。", "涂山齐德翊成功。", "仙魄蚤宾空。", "珍台闲馆栖神地，献飨永无穷。"]'),
('song-ci-22','导引','无名氏','宋','宋词','song-ci','导引','[]','思齐文母，盛德比姜任。',59,'宋词/ci.song.20000.json','["思齐文母，盛德比姜任。", "拥佑极恩深。", "汤孙归美熙鸿号，镂玉更绳金。", "虞庭万辟萃华簪。", "法仗俨天临。", "展闱庆典年年举，千古播徽音。"]'),
('song-ci-23','六州','无名氏','宋','宋词','song-ci','六州','[]','皇抚极，明德贯乾坤。',161,'宋词/ci.song.20000.json','["皇抚极，明德贯乾坤。", "信星列，卿云烂，辉亘紫微垣。", "思报贶、明诏祠宫，练时搜旷典，紫畤觚坛，昭孝德、亲御和銮。", "振鹭玉珊珊。", "精纯谒款，膋萧爌炀。", "黄流湛澹，百末布生兰。", "扣天阍，延飞驾，相彷佛，降云端。", "神光集，嘉响应，霭霭万衣冠。", "竣熙事清晓轻寒。", "恣荣观。", "华衣雾縠般般。", "乾坤并贶庆君欢。", "翘首圣恩宽。", "遵皇极，沛天泽，灵心怿，龟鼎永尊安。"]'),
('song-ci-24','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','宵景霁，河汉清夷。',158,'宋词/ci.song.20000.json','["宵景霁，河汉清夷。", "旷典讲明时。", "合祛升侑，孝德爰熙。", "陈裸閟宫，澹觞太室，来奏天仪。", "驷苍螭。", "玉辂驭蕤绥。", "觚陆展躬祠。", "长梢饰玉，翠羽秀金支。", "华始倡，雅韵出宫垂。", "神来下，云车风马，缤暗蔼、宴栖迟。", "毕觞流胙，紫烟竣事，棠梨回谒，宣室受蕃厘。", "盛德无心专飨，端为民祈。", "云恩有截，雨泽霈无涯。", "君王愉乐，和气溢瑶卮。", "寿天齐。", "长拥神基。"]'),
('song-ci-25','奉礼歌','无名氏','宋','宋词','song-ci','奉礼歌','[]','葭飞璇龠，孕初阳。',177,'宋词/ci.song.20000.json','["葭飞璇龠，孕初阳。", "云绝清台、荐景祥。", "风应律，日重光。", "岁功顺，底金穰，寿而康。", "庭壶乐无疆。", "皇展报，新礼乐，觚陛咏宾乡。", "珠幄熉黄。", "登瑞缫，陈俎豆，澹嘉觞。", "衮衣辉焕，宝佩琳琅。", "奠椒浆。", "庆阴阴，神来下，凤翥龙骧。", "灵燕喜，锡符仍降嘏，镛管琳琅。", "欢亮神之出，祓兰堂。", "辇路天香。", "轻烟半袭旗常。", "祉滂洋。", "受厘宣室，返驭斋房。", "恩与风翔。", "华封祝、皇来有庆，八荒同寿，宝历无疆。"]'),
('song-ci-26','降仙台','无名氏','宋','宋词','song-ci','降仙台','[]','星芒收采，云容放晓，羲驭渐扬明。',123,'宋词/ci.song.20000.json','["星芒收采，云容放晓，羲驭渐扬明。", "觚坛竣事，斋风袭、衮衣轻。", "銮路尘清。", "甘泉卤簿，祲威肃、回轸旋衡。", "千官道从粲簪缨。", "钧奏间韶英。", "瞻龙闱，近凤城。", "都人云会，芬茀夹道欢迎。", "宸极尊荣。", "卮玉庆熙成。", "琼楼天上起和声。", "布春泽，洪畅寰瀛。", "嵩呼万岁，鳌三抃、颂升平。"]'),
('song-ci-27','导引','无名氏','宋','宋词','song-ci','导引','[]','霜月苦、宫鼓冬冬。',63,'宋词/ci.song.20000.json','["霜月苦、宫鼓冬冬。", "霓旐启、鹤闱空。", "洞箫声断知何处，海山依约五云东。", "玉符龙节参神閟，昭圣眷、惨天容。", "千古恨无穷。", "遍山松柏撼悲风。"]'),
('song-ci-28','导引','无名氏','宋','宋词','song-ci','导引','[]','三弄晓、云黯天低。',63,'宋词/ci.song.20000.json','["三弄晓、云黯天低。", "攀六引、转悲凄。", "俭慈孝哲锺天性，深仁厚泽遍群黎。", "东西南北傒商霓。", "功甫就、别宸闺。", "臣民千古恨，几时羽卫带潮归。"]'),
('song-ci-29','六州','无名氏','宋','宋词','song-ci','六州','[]','明天子，昔日丕纂鸿图。',167,'宋词/ci.song.20000.json','["明天子，昔日丕纂鸿图。", "躬道德，崇学问，稽古训，访群儒。", "日亲广厦、论唐虞。", "讲求政治、想都俞。", "君臣一德、志交孚。", "外夷效顺，犹自选车徒。", "仁恩沾四国，固结满寰区。", "千年宗社，万岁规摹。", "重新天命出乾符。", "老癃策杖相扶。", "愿观德化遍方隅。", "幸无死须臾。", "谓宜圣寿等嵩呼。", "遽登云舆。", "上龙湖。", "宸居幽寂紫云孤。", "宸章宝画，但与日星俱。", "龙帷凤翣已载涂。", "忍听笳鼓嗟呼。"]'),
('song-ci-30','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','戈绨革舄最仁贤。',182,'宋词/ci.song.20000.json','["戈绨革舄最仁贤。", "俭德自躬全。", "忧勤庶政，三十馀年。", "金风肃，秋渐老，摄调ち。", "忱恂遍，群祀号泣诉旻天。", "缀衣将出，神凝玉几，一夜登仙。", "弓堕隔苍烟。", "七月有来同轨，引绋动灵辁。", "凄怆泪潸然。", "行号巷哭，薤露声传。", "东城去路，惊涛忍见江船。", "憔悴山川。", "不禁箫鼓咽，山阴处，茂林修竹芊芊。", "望陵宫，应弗远，金粟堆前。", "人徒慕恋，百神警待，盘翥驱先。", "戴鸿恩，空痛慕，泪珠连。", "千秋岁、功德寄华编。"]'),
('song-ci-31','导引','无名氏','宋','宋词','song-ci','导引','[]','中兴四叶，休德继昭清。',59,'宋词/ci.song.20000.json','["中兴四叶，休德继昭清。", "王度日熙平。", "气调玉烛金穰应，八表颂声腾。", "中原图籍入宸廷。", "列圣慰真灵。", "衮龙登庙游仙阙，亿万载尊承。"]'),
('song-ci-32','导引','无名氏','宋','宋词','song-ci','导引','[]','中兴五叶，天子肇明禋。',59,'宋词/ci.song.20000.json','["中兴五叶，天子肇明禋。", "一德格高旻。", "宁皇至圣功超古，万国慕深仁。", "徽称显号又还新。", "功德粲雕珉。", "乾坤绘画终难尽，遗泽在斯民。"]'),
('song-ci-33','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','若论风流，无过圆社，拐膁蹬蹑搭齐全。',122,'宋词/ci.song.20000.json','["若论风流，无过圆社，拐膁蹬蹑搭齐全。", "门庭富贵，曾到御帘前。", "灌口二郎为首，赵皇上、下脚流传。", "人都道、齐云一社，三锦独争先。", "花前。", "并月下，全身绣带，偷侧双肩。", "更高而不远，一搭打秋千。", "球落处、圆光膁拐，双佩剑、侧蹑相连。", "高人处，翻身佶料，天下总呼圆。"]'),
('song-ci-34','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','十二香皮，裁成圆锦，莫非年少堪收。',120,'宋词/ci.song.20000.json','["十二香皮，裁成圆锦，莫非年少堪收。", "绿杨深处，恣意乐追游。", "低拂花梢慢下，侵云汉、月满当秋。", "堪观处，偷头十字拐，舞袖拂银钩。", "肩尖，并拐搭，五陵公子，恣意忘忧。", "几回沈醉，低筑傍高楼。", "虽不遇文章高贵，分左右、曾对王候。", "君知否，闲中第一，占断是风流。"]'),
('song-ci-35','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','遇酒当歌酒满斟。',64,'宋词/ci.song.20000.json','["遇酒当歌酒满斟。", "一觞一咏乐天真。", "三杯五盏陶情性，对月临风自赏心。", "环列处，总佳宾。", "歌声缭亮遏行云。", "春风满座知音者，一曲教君侧耳听。"]'),
('song-ci-36','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','共庆清朝，四时欢会，贺筵开会集佳宾。',127,'宋词/ci.song.20000.json','["共庆清朝，四时欢会，贺筵开会集佳宾。", "风流鼓板，法曲献仙音。", "鼓笛令、无双多丽，十拍板、音韵宣清。", "文序子，双声叠韵，有若瑞龙吟。", "当筵，闻品令，声声慢处，丹凤微鸣。", "听清风八韵，打拍底、更好精神。", "安公子、倾杯未饮，好女儿、齐隔帘听。", "真无比、最高楼上，一曲称人心。"]'),
('song-ci-37','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','八蛮朝凤阙，四境绝狼烟。',114,'宋词/ci.song.20000.json','["八蛮朝凤阙，四境绝狼烟。", "太平无事，超烘聚哨效梨园。", "笛弄昆仑上品，筛动云阳妙选，画鼓可人怜。", "乱撒真珠迸，点滴雨声喧。", "韵堪听，声不俗，驻云轩。", "谐音节奏，分明花里遇神仙。", "到处朝山拜岳，长是争筹赌赛，四海把名传。", "幸遇知音听，一曲赞尧天。"]'),
('song-ci-38','西江月','无名氏','宋','宋词','song-ci','西江月','[]','么六把门已定，二四三五成梁。',58,'宋词/ci.song.20000.json','["么六把门已定，二四三五成梁。", "须知四六做烟梁。", "五六单行无障。", "掷得么三采出，填胲此处高强。", "到家先起妙无双。", "号曰金赢取赏。"]'),
('song-ci-39','卜算子','无名氏','宋','宋词','song-ci','卜算子','[]','我有一枝花，斟我些儿酒。',52,'宋词/ci.song.20000.json','["我有一枝花，斟我些儿酒。", "唯愿花心似我心，岁岁长相守。", "满满泛金杯。", "重把花来嗅。", "不愿花枝在我旁，付与他人手。"]'),
('song-ci-40','浪淘沙令','无名氏','宋','宋词','song-ci','浪淘沙令','[]','今日□筵中。',64,'宋词/ci.song.20000.json','["今日□筵中。", "酒侣相逢。", "大家满满泛金锺。", "自起自斟还自饮，一笑春风。", "传与主人翁。", "权且饶侬。", "侬今沈醉眼朦胧。", "此酒可怜无伴饮，付与诸公。"]'),
('song-ci-41','调笑令','无名氏','宋','宋词','song-ci','调笑令','[]','花酒。',45,'宋词/ci.song.20000.json','["花酒。", "满筵有。", "酒满金杯花在手。", "头上戴花方饮酒。", "饮罢了高叉手。", "琵琶拨尽相思调。", "更向当筵舞袖。"]'),
('song-ci-42','花酒令','无名氏','宋','宋词','song-ci','花酒令','[]','花酒。',55,'宋词/ci.song.20000.json','["花酒。", "是我平生结底亲朋友。", "十朵五枝花，三杯两盏酒。", "休问南辰共北斗。", "任从他鸟飞兔走。", "酒满金卮花在手。", "且戴花饮酒。"]'),
('song-ci-43','锦缠道','无名氏','宋','宋词','song-ci','锦缠道','[]','燕子呢喃，景色乍长春昼。',81,'宋词/ci.song.20000.json','["燕子呢喃，景色乍长春昼。", "睹园林、万花如绣。", "海棠经雨胭脂透。", "柳展宫眉，翠拂行人首。", "向郊原踏青，恣歌携手。", "醉醺醺、尚寻芳酒。", "间牧童、遥指孤村道。", "杏花深处，那里人家有。"]'),
('song-ci-44','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','水涨鱼天拍柳桥。',48,'宋词/ci.song.20000.json','["水涨鱼天拍柳桥。", "云鸠拖雨过江皋。", "一番春信入东郊。", "闲碾凤团消短梦，静看燕子垒新巢。", "又移日影上花梢。"]'),
('song-ci-45','如梦令','无名氏','宋','宋词','song-ci','如梦令','[]','莺嘴啄花红溜。',40,'宋词/ci.song.20000.json','["莺嘴啄花红溜。", "燕尾点波绿皱。", "指冷玉笙寒，吹彻小梅春透。", "依旧。", "依旧。", "人与绿杨俱瘦。"]'),
('song-ci-46','金明池','无名氏','宋','宋词','song-ci','金明池','[]','琼苑金池，青门紫陌，似雪杨花满路。',148,'宋词/ci.song.20000.json','["琼苑金池，青门紫陌，似雪杨花满路。", "云日淡、天低昼永，过三点、两点细雨。", "好花枝、半出墙头，似怅望、芳草王孙何处。", "更水绕人家，桥当门巷，燕燕莺莺飞舞。", "怎得东君长为主，把绿鬓朱颜，一时留住。", "佳人唱、金衣莫惜，才子倒、玉山休诉。", "况春来、倍觉伤心，念故国情多，新年愁苦。", "纵宝马嘶风，红尘拂面，也则寻芳归去。"]'),
('song-ci-47','眼儿媚','无名氏','宋','宋词','song-ci','眼儿媚','[]','杨柳丝丝弄轻柔。',58,'宋词/ci.song.20000.json','["杨柳丝丝弄轻柔。", "烟缕织成愁。", "海棠未雨，梨花先雪，一半春休。", "而今往事难重省，归梦绕秦楼。", "相思只在，丁香枝上，豆蔻梢头。"]'),
('song-ci-48','青玉案','无名氏','宋','宋词','song-ci','青玉案','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','一年春事都来几。',81,'宋词/ci.song.20000.json','["一年春事都来几。", "早过了、三之二。", "绿暗红嫣浑可事。", "绿杨庭院，暖风帘幕，有个人憔悴。", "买花载酒长安市。", "又争似家山见桃李。", "不枉东风吹客泪，相思难表，梦魂无据，惟有归来是。"]'),
('song-ci-49','声声令・胜胜令','无名氏','宋','宋词','song-ci','声声令・胜胜令','[]','帘移碎影，香褪衣襟。',83,'宋词/ci.song.20000.json','["帘移碎影，香褪衣襟。", "旧家庭院嫩苔侵。", "东风过尽，暮云锁、绿窗深。", "怕对人、闲枕剩衾。", "楼底轻阴。", "春信断、怯登临。", "断肠魂梦两沈沈。", "花飞水远，便从今、莫追寻。", "又怎禁、蓦地上心。"]'),
('song-ci-50','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','绿暗汀洲三月暮，落花风静帆收。',70,'宋词/ci.song.20000.json','["绿暗汀洲三月暮，落花风静帆收。", "垂杨低映木兰舟。", "半篙春水滑，一段夕阳愁。", "灞水桥东回首处，美人亲上帘钩。", "青鸾无计入红楼。", "行云归楚峡，飞梦到扬州。"]'),
('song-ci-51','怨王孙・忆王孙','无名氏','宋','宋词','song-ci','怨王孙・忆王孙','[]','梦断漏悄。',65,'宋词/ci.song.20000.json','["梦断漏悄。", "愁浓酒恼。", "宝枕生寒，翠屏向晓。", "门外谁扫残红。", "夜来风。", "玉箫声断人何处。", "春又去。", "忍把归期负。", "此情此恨此际，拟托行云。", "问东君。"]'),
('song-ci-52','凤凰阁','无名氏','宋','宋词','song-ci','凤凰阁','[]','遍园林绿暗，浑如翠幄。',82,'宋词/ci.song.20000.json','["遍园林绿暗，浑如翠幄。", "下无一片是花萼。", "可恨狂风横雨，忒煞情薄。", "尽底把、韶华送却。", "杨花无奈，是处穿帘透幕。", "岂知人意正萧索。", "春去也，这般愁、没处安著。", "怎奈向、黄昏院落。"]'),
('song-ci-53','祝英台近','无名氏','宋','宋词','song-ci','祝英台近','["\u897f\u6e56"]','剪酴醿、移红药，深院教鹦鹉。',95,'宋词/ci.song.20000.json','["剪酴醿、移红药，深院教鹦鹉。", "消遣宿酲，敧枕熏沈炷。", "自从载酒西湖，探梅南浦，久不见、雪儿歌舞。", "恨无据。", "因甚不展眉头，凝愁过百五。", "双燕见情，难寄断肠句。", "可怜泪湿青绡，怨题红叶，落花乱、一帘风雨。"]'),
('song-ci-54','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','枝上流莺和泪闻。',64,'宋词/ci.song.20000.json','["枝上流莺和泪闻。", "新啼痕间旧啼痕。", "一春鱼鸟无消息，千里关山劳梦魂。", "无一语，对芳尊。", "安排肠断到黄昏。", "甫能炙得灯儿了，雨打梨花深闭门。"]'),
('song-ci-55','长相思','无名氏','宋','宋词','song-ci','长相思','[]','红满枝。',44,'宋词/ci.song.20000.json','["红满枝。", "绿满枝。", "宿雨厌厌睡起迟。", "闲庭花影移。", "忆归期。", "数归期。", "梦见虽多相见稀。", "相逢知几时。"]'),
('song-ci-56','谒金门','韦庄','宋','宋词','song-ci','谒金门','[]','春雨足。',53,'宋词/ci.song.20000.json','["春雨足。", "染就一溪新绿。", "柳外飞来双羽玉。", "弄晴相对浴。", "楼外翠帘高轴。", "倚遍栏干几曲。", "云淡水平烟树簇。", "寸心千里目。"]'),
('song-ci-57','探春令','无名氏','宋','宋词','song-ci','探春令','[]','绿杨枝上晓莺啼，报融和天气。',62,'宋词/ci.song.20000.json','["绿杨枝上晓莺啼，报融和天气。", "被数声、吹入纱窗里。", "又惊起娇娥睡。", "绿云斜亸金钗堕。", "惹芳心如醉。", "为少年湿了，鲛绡帕上，都是相思泪。"]'),
('song-ci-58','点绛唇','无名氏','宋','宋词','song-ci','点绛唇','[]','春雨濛濛，淡烟深锁垂杨院。',50,'宋词/ci.song.20000.json','["春雨濛濛，淡烟深锁垂杨院。", "暖风轻扇。", "落尽桃花片。", "薄幸不来，前事思量遍。", "无由见。", "泪痕如线。", "界破残妆面。"]'),
('song-ci-59','点绛唇','无名氏','宋','宋词','song-ci','点绛唇','[]','莺踏花翻，乱红堆径无人扫。',50,'宋词/ci.song.20000.json','["莺踏花翻，乱红堆径无人扫。", "杜鹃来了。", "梅子枝头小。", "拨尽琵琶，总是相思调。", "知音少。", "暗伤怀抱。", "门掩青春老。"]'),
('song-ci-60','声声慢','无名氏','宋','宋词','song-ci','声声慢','[]','梅黄金重，雨细丝轻，园林雾烟如织。',119,'宋词/ci.song.20000.json','["梅黄金重，雨细丝轻，园林雾烟如织。", "殿阁风微，帘外燕喧莺寂。", "池塘彩鸳戏水，雾荷翻、千点珠滴。", "闲昼永，称潇湘竿叟，烂柯仙客。", "日午槐阴低转，茶瓯罢、清风顿生双腋。", "碾玉盘深，朱李静沈寒碧。", "朋侪闲歌白雪，卸巾纱、樽俎狼藉。", "有皓月、照黄昏，眠又未得。"]'),
('song-ci-61','大圣乐','无名氏','宋','宋词','song-ci','大圣乐','[]','千朵奇峰，半轩微雨，晓来初过。',133,'宋词/ci.song.20000.json','["千朵奇峰，半轩微雨，晓来初过。", "渐燕子、引教雏飞，菡萏暗薰芳草，池面凉多。", "浅斟琼卮浮绿蚁，展湘簟双纹生细波。", "轻纨举，动团圆素月，仙桂婆娑。", "临风对月恣乐，便好把千金邀艳娥。", "幸太平无事，击壤鼓腹，携酒高歌。", "富贵安居，功名天赋，争奈皆由时命呵。", "休眉锁。", "问朱颜去了，还更来麽。"]'),
('song-ci-62','菩萨蛮','无名氏','宋','宋词','song-ci','菩萨蛮','[]','金风簌簌惊黄叶。',52,'宋词/ci.song.20000.json','["金风簌簌惊黄叶。", "高楼影转银蟾匝。", "梦断绣帘垂。", "月明乌鹊飞。", "新愁知几许。", "欲似丝千缕。", "雁已不堪闻。", "砧声何处村。"]'),
('song-ci-63','捣练子','无名氏','宋','宋词','song-ci','捣练子','[]','心耿耿，泪双双。',32,'宋词/ci.song.20000.json','["心耿耿，泪双双。", "皓月清风冷透窗。", "人去秋来宫漏永，夜深无语对银缸。"]'),
('song-ci-64','女冠子','无名氏','宋','宋词','song-ci','女冠子','[]','同云密布。',139,'宋词/ci.song.20000.json','["同云密布。", "撒梨花、柳絮飞舞。", "楼台诮似玉。", "向红炉暖阁院宇。", "深庭广排筵会，听笙歌犹未彻，渐觉轻寒，透帘穿户。", "乱飘僧舍，密洒歌楼，酒帘如故。", "想樵人、山径迷踪路。", "料渔人、收纶罢钓归南浦。", "路无伴侣。", "见孤村寂寞，招飐酒旗斜处。", "南轩孤雁过，呖呖声声，又无书度。", "见腊梅、枝上嫩蕊，两两三三微吐。"]'),
('song-ci-65','满江红','无名氏','宋','宋词','song-ci','满江红','[]','斗帐高眠，寒窗静、潇潇雨意。',115,'宋词/ci.song.20000.json','["斗帐高眠，寒窗静、潇潇雨意。", "南楼近、更移三鼓，漏传一水。", "点点不离杨柳外，声声只在芭蕉里。", "也不管、滴破故乡心，愁人耳。", "无似有，游丝细。", "聚复散，真珠碎。", "天应分付与，别离滋味。", "破我一床蝴蝶梦，输他双枕鸳鸯睡。", "向此际、别有好思量，人千里。"]'),
('song-ci-66','秋霁','无名氏','宋','宋词','song-ci','秋霁','[]','虹影侵阶，乍雨歇长空，万里凝碧。',128,'宋词/ci.song.20000.json','["虹影侵阶，乍雨歇长空，万里凝碧。", "孤鹜高飞，落霞相映，远状水乡秋色。", "黯然望极。", "动人无限愁如织。", "又听得。", "云外数声，新雁正嘹呖。", "当此暗想，画阁轻抛，杳然殊无，些个消息。", "漏声稀、银屏冷落，那堪残月照窗白。", "衣带顿宽犹阻隔。", "算此情苦，除非宋玉风流，共怀伤感，有谁知得。"]'),
('song-ci-67','忆秦娥','无名氏','宋','宋词','song-ci','忆秦娥','[]','香馥馥。',56,'宋词/ci.song.20000.json','["香馥馥。", "樽前有个人如玉。", "人如玉。", "翠翘金凤，内家妆束。", "娇羞爱把眉儿蹙。", "逢人只唱相思曲。", "相思曲。", "一声声是，怨红愁绿。"]'),
('song-ci-68','柳梢青','无名氏','宋','宋词','song-ci','柳梢青','[]','有个人人。',61,'宋词/ci.song.20000.json','["有个人人。", "海棠标韵，飞燕轻盈。", "酒晕潮红，羞娥凝绿，一笑生春。", "为伊无限伤心。", "更说甚、巫山楚云。", "斗帐香消，纱窗月冷，著意温存。"]'),
('song-ci-69','烛影摇红','无名氏','宋','宋词','song-ci','烛影摇红','[]','乳燕穿帘，乱莺啼树清明近。',116,'宋词/ci.song.20000.json','["乳燕穿帘，乱莺啼树清明近。", "隔帘时度柳花飞，犹觉寒成阵。", "长记眉峰偷隐。", "脸桃红、难藏酒晕。", "背人微笑，半亸鸾钗，轻笼蝉鬓。", "别久啼多，眼应不似当时俊。", "满园珠翠逞春娇，没个他风韵。", "若见宾鸿试问。", "待相将、彩笺寄恨。", "几时得见，斗草归来，双鸳微润。"]'),
('song-ci-70','苏幕遮','无名氏','宋','宋词','song-ci','苏幕遮','[]','陇云沈，新月小。',76,'宋词/ci.song.20000.json','["陇云沈，新月小。", "杨柳梢头，能有春多少。", "试著罗裳寒尚峭。", "帘卷青楼，占得东风早。", "翠屏深，香篆袅。", "流水落花，不管刘郎到。", "三叠阳关声渐杳。", "断雨残云，只怕巫山晓。"]'),
('song-ci-71','昼锦堂','无名氏','宋','宋词','song-ci','昼锦堂','[]','雨洗桃花，风飘柳絮，日日飞满雕檐。',123,'宋词/ci.song.20000.json','["雨洗桃花，风飘柳絮，日日飞满雕檐。", "懊恼一春幽恨，尽属眉尖。", "愁闻双飞新燕语，更堪孤枕宿酲忺。", "云鬟乱，独步画堂，轻风暗触珠帘。", "多厌。", "晴昼永，琼户悄，香销金兽慵添。", "自与萧娘别后，事事俱嫌。", "短歌新曲无心理，凤箫龙管不曾拈。", "空惆怅，长是每年三月，病酒恹恹。"]'),
('song-ci-72','齐天乐','无名氏','宋','宋词','song-ci','齐天乐','[]','天开图画江山秀。',124,'宋词/ci.song.20000.json','["天开图画江山秀。", "怪得人间希有。", "屏岛精神，潭溪骨格，锺作名门华胄。", "满堂昼绣。", "甚禊集兰亭，竹修林茂。", "得得明朝，绂麟亲解公侯绶。", "心胸剩罗列宿。", "便能光绍，太常勋旧。", "却恋槃湖，贪求精舍，日日佳篇醇酎。", "陶朱敌富。", "更沧海双珠，掌中明透。", "赢得年年，莲龟松鹤祝公寿。"]'),
('song-ci-73','桂枝香','无名氏','宋','宋词','song-ci','桂枝香','[]','武夷九曲。',123,'宋词/ci.song.20000.json','["武夷九曲。", "甚乐响云韶，旆走星纛。", "更捧琼浆九酝，蟠桃初熟。", "元来崧岳生申旦，会群仙、献长生箓。", "岁寒堂上，冰壶影里，长跨青鹿。", "记往日、堤沙旧筑。", "有书龠金腾，勋写歌鹄。", "更化和朝，半是世臣乔木。", "明年瑞庆才经月，侍重瞳、应奉卮玉。", "此时奋建联班，却将万年齐祝。"]'),
('song-ci-74','满江红','无名氏','宋','宋词','song-ci','满江红','[]','才入新年，喜两见、希奇盛事。',111,'宋词/ci.song.20000.json','["才入新年，喜两见、希奇盛事。", "正五旦、虹流电绕，星枢呈瑞。", "方庆千秋开宝运，又今六日生名世。", "河清生圣岳生贤，风云际。", "修月手，凌云气。", "吞泽量，飞泉思。", "况声名已自，惊天动地。", "上寿不须儿女语，著鞭且展英雄志。", "北方焰焰看来年，魁名字。"]'),
('song-ci-75','贺新郎','无名氏','宋','宋词','song-ci','贺新郎','["\u9ec4\u6cb3"]','四海文章伯。',136,'宋词/ci.song.20000.json','["四海文章伯。", "自雪堂人老，有谁当得。", "馀子纷纷何足数，除是壶中仙客。", "况夺得、秋光清彻。", "笔下诗成愁鬼魅，更千军、侍帐看飞檄。", "须信道，万人杰。", "胸襟浩荡乾坤窄。", "向楼东吟笑，壮心谁识。", "直渡黄河擒颉虏，吐尽平生奇策。", "终不负、雄姿英发。", "闻说九重飞紫诏，想鸣珂、日晚朝天阙。", "鸿鹄举，楚天阔。"]'),
('song-ci-76','西江月','无名氏','宋','宋词','song-ci','西江月','[]','一派先天妙学，十年克己工夫。',58,'宋词/ci.song.20000.json','["一派先天妙学，十年克己工夫。", "割鸡聊此宰中都。", "人在春台鼓舞。", "昏垫非由已溺，拊摩不异予辜。", "万家香火祝悬弧。", "我亦无多颂语。"]'),
('song-ci-77','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','天下知名，今日刘郎，胜如旧时。',139,'宋词/ci.song.20000.json','["天下知名，今日刘郎，胜如旧时。", "记当年暮府，元戎高会，万花围席，争看题诗。", "尽道坡仙，再生尘世，有制宜烦立马挥。", "东阳小，岂容久驻，凫舄暂双飞。", "诸公荐墨交驰。", "要推上青云百丈梯。", "况平生慷慨，闻鸡起舞，中原事业，不付公谁。", "生记今朝，频将指数，较莱公争半月期。", "功名事，不输前辈，行即诏封泥。"]'),
('song-ci-78','金缕词・贺新郎','无名氏','宋','宋词','song-ci','金缕词・贺新郎','[]','瑞气重闽宇。',142,'宋词/ci.song.20000.json','["瑞气重闽宇。", "小春馀、璇霜避暖，敛威青女。", "一点阳和锺英气，崧岳今朝诞甫。", "正两荚、尚留蓂舞。", "应想宁川称寿处，听金笼、放鸽儿童语。", "愿千岁，祝慈父。", "君家自有安民谱。", "袖良规、时宽辔策，夜闲桴鼓。", "直赖汀南为保障，无复鼪鼯啸聚。", "果峻秩、升朝褒叙。", "治最行将书第一，去思碑、拟颂歌明府。", "飞诏趣，缀鸳鹭。"]'),
('song-ci-79','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','当日名驹产渥洼。',64,'宋词/ci.song.20000.json','["当日名驹产渥洼。", "追风千里堕君家。", "不辞贤路甘栖棘，来伴河阳且种花。", "梅试雪，酒潮霞。", "寿觞还捧笑声哗。", "唐朝九相青毡旧，为报新堤早筑沙。"]'),
('song-ci-80','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','标格清高，性姿雅淡，群芳独步惟梅。',119,'宋词/ci.song.20000.json','["标格清高，性姿雅淡，群芳独步惟梅。", "当年秀气，付作此奇材。", "不逐东风桃李俗，冰霜里、弹压春回。", "还应是，崧神降瑞，屈指一阳来。", "文章，推大手，关征小试，暂费筹财。", "我殷勤为寿，起舞持杯。", "鹏翮抟风再整，南枝报、管占新魁。", "从今看，和羹大用，指日主三台。"]'),
('song-ci-81','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','鹤算遗芳绩世传。',64,'宋词/ci.song.20000.json','["鹤算遗芳绩世传。", "武夷来作散神仙。", "柳营隐隐兵戎整，兰砌诜诜子舍贤。", "倾柏酒，爇沉烟。", "殷勤起舞祝长年。", "行须一札飞鸦诏，促缀银班侍九天。"]'),
('song-ci-82','西江月','无名氏','宋','宋词','song-ci','西江月','[]','一夕凉浮如水，崧高瑞世生贤。',58,'宋词/ci.song.20000.json','["一夕凉浮如水，崧高瑞世生贤。", "朅来闲伴幔亭仙。", "行副九天隆眷。", "数万范公兵甲，三千李白诗篇。", "兜鍪元许换貂蝉。", "好把平戎策献。"]'),
('song-ci-83','西江月','无名氏','宋','宋词','song-ci','西江月','[]','侯绩分从东鲁，世勋来在姬公。',58,'宋词/ci.song.20000.json','["侯绩分从东鲁，世勋来在姬公。", "桂枝少日冠蟾宫。", "枳棘暂栖鸾凤。", "报道小春来也，令辰申降高崧。", "功名富贵管无穷。", "指日经纶大用。"]'),
('song-ci-84','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','良月露浓仙掌润，郁葱佳气充闾。',70,'宋词/ci.song.20000.json','["良月露浓仙掌润，郁葱佳气充闾。", "几年重席旧师儒。", "大椿同未老，灵寿不须扶。", "江左衣冠登桂籍，蝉联四世谁如。", "琳宫昨下凤凰书。", "金闺班趣缀，禁路莫踟蹰。"]'),
('song-ci-85','醉蓬莱','无名氏','宋','宋词','song-ci','醉蓬莱','[]','庆长庚协梦，仙李蟠根，挺生名世。',120,'宋词/ci.song.20000.json','["庆长庚协梦，仙李蟠根，挺生名世。", "粉省收声，早云霄自致。", "凤掖鸾台，荷囊簪笔，久要津历试。", "红旆颁春，碧油开府，出分忧寄。", "均逸真祠，左弧开宴，璧月光澄，玉炉烟细。", "漆发冰眸，揽浮丘仙袂。", "伫看九重，迅驰三节，诏促还丹陛。", "槐府凉生，榴樽香泛，年年欢醉。"]'),
('song-ci-86','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','桐叶霜乾，芦花风软，晚来一色清秋。',118,'宋词/ci.song.20000.json','["桐叶霜乾，芦花风软，晚来一色清秋。", "碧天无际，良夜月明楼。", "瑞应长庚入梦，锺奇秀、特座贤侯。", "堪夸处，雄姿英发，连箭射双雕。", "回头。", "思往事，皂囊三进，豪气冲牛。", "记前回凤诏，空下南州。", "冷笑浮云坠甑，鲈鱼美、归老扁舟。", "祝君寿，青山不尽，绿水自悠悠。"]'),
('song-ci-87','七娘子','无名氏','宋','宋词','song-ci','七娘子','[]','暖律未回春时候。',72,'宋词/ci.song.20000.json','["暖律未回春时候。", "向旧根、腊底红先透。", "玉有冷香，粉无纤垢。", "更饶雪里还清瘦。", "琳宫拟诏风流守。", "任折来、深醮金杯酒。", "欲赏一枝，樽前为寿。", "愿公归作调羹手。"]'),
('song-ci-88','多丽','无名氏','宋','宋词','song-ci','多丽','[]','近中秋，迥然玉宇澄鲜。',172,'宋词/ci.song.20000.json','["近中秋，迥然玉宇澄鲜。", "更尧蓂、十有一叶，向人特敷妍。", "喜名家、世行阴德，有馀庆、门拥祥烟。", "梦协熊罴，间生鸑鷟，妙年攀桂振青毡。", "横飞上，金闺粉署，小试佐临川。", "翩然返，一身似叶，琳馆清闲。", "记榜下、曩尝附骥，浪萍还有夤缘。", "曳长裾、不辞还道，接漫刺、复面同年。", "邂逅佳辰，铺排雅席，金炉香袅欲何言。", "愿趣诏、入扶宗社，浩气愈纯全。", "长年少，龟龄共永，鹤算同坚。"]'),
('song-ci-89','百字令・念奴娇','无名氏','宋','宋词','song-ci','百字令・念奴娇','[]','自天锺秀，看人物谁与、君家为比。',120,'宋词/ci.song.20000.json','["自天锺秀，看人物谁与、君家为比。", "椿桂相辉年少日，事业文章如此。", "玉殿诗书，金瓯姓字，简记宸衷里。", "有三株桂，一时归耀桑梓。", "我愿寿祝南山，尊空北海，不获陪珠履。", "惟有瓣香心起敬，敢颂鲁侯燕喜。", "大厦万间，金城千里，国计如家计。", "日边有诏，苍生端望公起。"]'),
('song-ci-90','玉烛新','无名氏','宋','宋词','song-ci','玉烛新','[]','养高梓里，袖手珍祠，太平五福人物。',120,'宋词/ci.song.20000.json','["养高梓里，袖手珍祠，太平五福人物。", "自是昔年，场屋文章旧豪杰。", "诗书平生事业。", "问造物、为谁悭惜。", "谩眷怀、兰玉桂香，已露消息。", "尝试问、天公好事，鼎来家庆自因袭。", "更看绶蓝森列，映灵椿双碧。", "诸郎击鲜奏食。", "笑贾陆、一更十日。", "画堂上，鹤算延长，兕觥无极。"]'),
('song-ci-91','南柯子・南歌子','无名氏','宋','宋词','song-ci','南柯子・南歌子','[]','花萼清辉近，蓬莱紫气浓。',62,'宋词/ci.song.20000.json','["花萼清辉近，蓬莱紫气浓。", "濮园流庆与天同。", "生得名驹千里、籋秋风。", "阅武戈初偃，论文酒不空。", "摩挲铜狄灞桥东。", "看取朱衣双引、袭真封。"]'),
('song-ci-92','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','威策冰河，兵严玉帐，济时人在壶天。',118,'宋词/ci.song.20000.json','["威策冰河，兵严玉帐，济时人在壶天。", "妙龄谈笑，图画上凌烟。", "但见勋书鼎鼐，谁知道、名列高仙。", "风云会，钩陈羽卫，绿鬓映貂蝉。", "绵绵。", "流庆远，芝兰秀发，折桂争先。", "占盛一门，文武更双全。", "已饵琼英绛雪，灵龟寿、何止千年。", "年年看，笙歌丛里，金盏侧垂莲。"]'),
('song-ci-93','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','金兽袅香穗，银烛灿花枝。',114,'宋词/ci.song.20000.json','["金兽袅香穗，银烛灿花枝。", "眼前风景殊异，酌酒庆生时。", "要是祖宗流庆，方有此身此日，盍亦反其思。", "何以上雅寿，敢用此为规。", "况君家，本学业，致轻肥。", "牙签玉轴，全胜阡陌占东西。", "好把胸中一点，照破堂中万卷，五福自来宜。", "谨勿效雌伏，指日要雄飞。"]'),
('song-ci-94','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','天地锺奇秀，山泽有儒仙。',116,'宋词/ci.song.20000.json','["天地锺奇秀，山泽有儒仙。", "词锋前驱万马，三度奏捷菊花天。", "信是文场敏手，如把枭卢对掷，高叱便回旋。", "一点英雄气，四顾浩无边。", "长羡君，先我著，祖生鞭。", "今朝尊酒持劝，岂特颂长年。", "要入兰宫妙选，共向集英殿里，玉陛听胪传。", "姓字标黄甲，香墨照人鲜。"]'),
('song-ci-95','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','来复迈七日，亨泰兆三阳。',114,'宋词/ci.song.20000.json','["来复迈七日，亨泰兆三阳。", "恰逢临吉中应，浸长三阳刚。", "天地凝成正气，岳渎锺为秀杰，玉燕纪呈祥。", "莹彻冰壶操，皎月映秋霜。", "日星回，乾坤辟，再更张。", "时乘君子道长，茅茹喜生光。", "抱负黄锺大吕，资禀盐梅栋柏，施用在岩廊。", "一骑春风里，紫诏下山堂。"]'),
('song-ci-96','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','奏捷淮堧，勒功燕石，鼓吹凯旋。',140,'宋词/ci.song.20000.json','["奏捷淮堧，勒功燕石，鼓吹凯旋。", "正归班玉笋，花袍方卸，彩衣亟著，忠孝双全。", "清德独高，皇心简注，燕寝凝香朱两幡。", "君王问，录屏风姓字，趣对金銮。", "平山。", "蹑履緌冠。", "竞来庆嘉平五日间。", "是炎刘昴宿，光至再现，绛人甲子，四百新颁。", "碧麦称觞，玉枝等算，长对梅花开岁寒。", "春回也，报调羹时候，梅子微酸。"]'),
('song-ci-97','西江月','无名氏','宋','宋词','song-ci','西江月','[]','几萼红搀桃径，双茎翠舞蓂阶。',58,'宋词/ci.song.20000.json','["几萼红搀桃径，双茎翠舞蓂阶。", "小春霏霭瑞蓬莱。", "寿旦称觞青在。", "牛斗辉腾气概，风云壮入襟怀。", "年年鹤发笑颜开。", "西爽亭前戏彩。"]'),
('song-ci-98','柳梢青','无名氏','宋','宋词','song-ci','柳梢青','[]','正好江南，一分春色，梨花白雪。',61,'宋词/ci.song.20000.json','["正好江南，一分春色，梨花白雪。", "化日迟迟，文章半刺，平分风月。", "满堂花醉三千，看妙舞、六么十八。", "笑捧瑶卮，祝君归去，琼楼金阙。"]'),
('song-ci-99','西江月','无名氏','宋','宋词','song-ci','西江月','[]','一片冰霜气概，几多锦绣文章。',58,'宋词/ci.song.20000.json','["一片冰霜气概，几多锦绣文章。", "鹏抟相踵桂枝香。", "盛事争夸歆向。", "岁岁蓂敷九叶，喜催一线迎长。", "柏松祝算奉霞觞。", "事业非熊吕望。"]'),
('song-ci-100','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','何以作公寿，一纸寄讴吟。',114,'宋词/ci.song.20000.json','["何以作公寿，一纸寄讴吟。", "当年生申有兆，鸑鷟梦文禽。", "气宇虹霓万丈，胸次蟠龙七泽，锦绣萃中心。", "高谊薄云表，随处是知音。", "人俊逸，文卓荦，气雄深。", "版岩合辞故隐，霖雨慰当今。", "且把梅花酌酒，行即桂枝入手，桑荫未移阴。", "珍重此时祝，何日盍朋簪。"]'),
('song-ci-101','满江红','无名氏','宋','宋词','song-ci','满江红','[]','学富胸襟，才名擅、菊潭第一。',115,'宋词/ci.song.20000.json','["学富胸襟，才名擅、菊潭第一。", "都缘是、文星在命，光联南极。", "已向九霄横鹗荐，词埸独步花生笔。", "况而今、好事又相逢，趋朝急。", "增喜气，眉黄色。", "须还做，龙头客。", "且今朝满泛，寿觞琼液。", "自昔箕畴称五福，惟公兼备真难得。", "看明朝、夺取锦标归，头方黑。"]'),
('song-ci-102','乳燕飞・贺新郎','无名氏','宋','宋词','song-ci','乳燕飞・贺新郎','[]','指点金蕉叶。',139,'宋词/ci.song.20000.json','["指点金蕉叶。", "倩双成、十分为注，九天琼液。", "中有玉梅风露气，持寿卯金仙伯。", "听贱子、歌翻新阕。", "不作寻常儿女祝，把先生、好事从头说。", "须快饮，莫留滴。", "风流晋宋人物。", "有锦囊万首，不博小儿馆职。", "膝下双雏真伟器，足继传家事业。", "且做个、人间闲客。", "试问种春春几许，尽芝田万顷天来阔。", "天有尽，春无极。"]'),
('song-ci-103','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','眼底高年，如老曾仙，斗南一人。',139,'宋词/ci.song.20000.json','["眼底高年，如老曾仙，斗南一人。", "能持齐守戒，香山居士，乐天知命，康节先生。", "满眼儿孙，满堂金玉，多宝如来现后身。", "真堪羡，有许多福力，越见精神。", "庆公今日生申。", "喜渐近中秋对月明。", "这平生积善，三千功行，前程享福，八百椿龄。", "见说寿筵，大开佛事，煮鹤炮龙烙凤麟。", "从今后，愿年年长健，事事如心。"]'),
('song-ci-104','踏莎行','无名氏','宋','宋词','song-ci','踏莎行','[]','月朏银河，秋生玉宙。',68,'宋词/ci.song.20000.json','["月朏银河，秋生玉宙。", "金风丛桂香生袖。", "儿孙重侍戏斑兰，霞觞共庆公家寿。", "学问从心，希年谁有。", "东之行应贤良召。", "吉音先动菊花期，一门依旧夸三秀。"]'),
('song-ci-105','望江南・忆江南','无名氏','宋','宋词','song-ci','望江南・忆江南','[]','阶蓂舞，才半小春天。',64,'宋词/ci.song.20000.json','["阶蓂舞，才半小春天。", "青女霜前犹避暖，素娥月里乍羞圆。", "蓬岛降天仙。", "称寿处，琼液拍浮船。", "长伴瑶池金母宴，蟠桃花下驾云軿。", "结实看千年。"]'),
('song-ci-106','蝶恋花','无名氏','宋','宋词','song-ci','蝶恋花','[]','风雨一春寒料峭。',70,'宋词/ci.song.20000.json','["风雨一春寒料峭。", "才到中和，喜气薰晴晓。", "九叶仙茅呈瑞巧。", "青青辉映萱庭草。", "红著蟠桃春不老。", "戏彩称觞，阿母开颜笑。", "丹桂五枝年并少。", "荣亲伫下金花诰。"]'),
('song-ci-107','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','织女初秋渡鹊河。',64,'宋词/ci.song.20000.json','["织女初秋渡鹊河。", "逾旬蟾苑聘嫦娥。", "蓬莱仙子今宵降，前后神仙引从多。", "餐玉蕊，抚云璈。", "寿筵戏彩捧金荷。", "黄金照社三儿贵，他日潘舆侍绮罗。"]'),
('song-ci-108','满江红','无名氏','宋','宋词','song-ci','满江红','[]','萱草堂开，仙姿秀、金枝玉叶。',115,'宋词/ci.song.20000.json','["萱草堂开，仙姿秀、金枝玉叶。", "亲曾映、尧阶三月，蓂舒六荚。", "荣侍早随台辅鼎，长生已镂天潢牒。", "自当年、苹藻俪勋门，能循法。", "掌中贵，双珠握。", "慈训笃，家传学。", "信陶亲珪母，要还相业。", "最好鳌头攀盛事，只今鹤发承殊渥。", "任年年、王母献蟠桃，金书帖。"]'),
('song-ci-109','八声甘州','无名氏','宋','宋词','song-ci','八声甘州','[]','渐纷纷、木叶下亭皋，秋容际寒空。',119,'宋词/ci.song.20000.json','["渐纷纷、木叶下亭皋，秋容际寒空。", "庆屏山南畔、龟游绿藻，鹤舞青松。", "缥缈非烟非雾，喜色有无中。", "帘幕金风细，香篆濛濛。", "好是庭闱称寿，簇舞裙歌板，欢意重重。", "况芝兰满砌，行见黑头公。", "看升平、乌栖画戟，更重开、大国荷荣封。", "人难老，年年醉赏，满院芙蓉。"]'),
('song-ci-110','庆灵椿・摊破南乡子','无名氏','宋','宋词','song-ci','庆灵椿・摊破南乡子','[]','瑞溪庭，满闺秋色好，帘幕低垂。',74,'宋词/ci.song.20000.json','["瑞溪庭，满闺秋色好，帘幕低垂。", "一床簪笏人间盛，沉檀影里，笙歌沸处，齐捧瑶卮。", "习礼复明诗。", "胡氏清畏人知。", "寿堂已庆灵椿老，年年岁岁，重添嫩叶，频长繁枝。"]'),
('song-ci-111','万年欢','无名氏','宋','宋词','song-ci','万年欢','[]','日暖霜融，画戟门开，锦筵欲振梁尘。',121,'宋词/ci.song.20000.json','["日暖霜融，画戟门开，锦筵欲振梁尘。", "正是慈闱熙熙，庆诞佳辰。", "象服鱼轩粲烂，喜高年、福禄长新。", "承颜处，朱紫满堂，华胄诜诜。", "家声未论王谢，有禁中颇牧，江左机云。", "雁序鸳行，雍容高步金门。", "更有子孙侍列，拥阶庭、玉洁兰薰。", "持芳醑、满酌瑶觞，意祝遐寿千春。"]'),
('song-ci-112','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','泽国嫩寒月，天气小阳春。',114,'宋词/ci.song.20000.json','["泽国嫩寒月，天气小阳春。", "萱堂今朝生日，瑞霭郁轮囷。", "身佩铜章墨绶，手捧霞觞玉液，献寿太夫人。", "且喜藤舆稳，共戏彩衣新。", "发垂鹄，瞳点漆，倍精神。", "麻姑来庆，笑道沧海几扬尘。", "伫看起居八座，更好回班百辟，异数耸朝绅。", "此母生此子，再拜谢宸恩。"]'),
('song-ci-113','满江红','无名氏','宋','宋词','song-ci','满江红','[]','绣线添长，屈指隔、书云三日。',115,'宋词/ci.song.20000.json','["绣线添长，屈指隔、书云三日。", "华堂里，十分佳气，葱葱郁郁。", "一点老人星正照，千年王母桃方实。", "向绮罗、丛里酌流霞，称觞客。", "凤雏贵，名仙籍。", "鸾诰宠，恩慈极。", "萃一门盛事，皆诗书力。", "芹泮珠曹争禄养，桂林雁郡催行色。", "看明年、两处寿筵开，长生节。"]'),
('song-ci-114','醉瑶池','无名氏','宋','宋词','song-ci','醉瑶池','[]','柳拈金丝花吐绣。',67,'宋词/ci.song.20000.json','["柳拈金丝花吐绣。", "蝶拍莺歌，来献天人寿。", "一点红黄眉上秀。", "玻璃满泛长生酒。", "丁祝遐龄天样久。", "年年岁岁笙歌奏。", "早晚郎君纡紫绶。", "归来色共斑衣斗。"]'),
('song-ci-115','瑞鹤仙','无名氏','宋','宋词','song-ci','瑞鹤仙','[]','五云翔碧汉。',125,'宋词/ci.song.20000.json','["五云翔碧汉。", "望卿月光中，老人星现。", "黄堂盛华宴。", "庆君恩、许奉安舆游衍。", "鹿城壮观。", "幸王母、人间得见。", "望君侯、彩服称觞，喜溢万家欢抃。", "堪羡。", "一生福善，九表康宁，万锺尊显。", "肩舁上殿。", "封两国、未应晚。", "管阴功、何止平反，一笑钧陶惠满。", "看瑶池、手种蟠桃，著花万遍。"]'),
('song-ci-116','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','千里旌麾，万家灯火，晓来气霭佳瑞。',119,'宋词/ci.song.20000.json','["千里旌麾，万家灯火，晓来气霭佳瑞。", "宝猊烟里，龟甲锦屏张。", "尽道蓬莱仙瑞世，九霄外、鸣玉飞香。", "阴功著，恩疏三品，金诰久弥芳。", "华堂。", "丝管□，金樽齐捧，百拜称觞。", "看绕庭兰玉，济济成行。", "占尽人间五福，壶中景、日月偏长。", "春难老，芳瞳发秀，千岁寿宁康。"]'),
('song-ci-117','酹江月・念奴娇','无名氏','宋','宋词','song-ci','酹江月・念奴娇','[]','云幢凤舞，下天风、吹落轮袍仙曲。',121,'宋词/ci.song.20000.json','["云幢凤舞，下天风、吹落轮袍仙曲。", "阿母人间今百岁，两鬓犹含秋绿。", "萍小乾坤，九看日月，不用长生箓。", "一封天上，鼎来五色花轴。", "须信寿老难侔，世间无价，空有明珠千斛。", "此夕兰堂风露好，雅称飞觞支属。", "十样宫眉，两行红袖，烧烛围香玉。", "不妨沉醉，共拚月上华屋。"]'),
('song-ci-118','鹊桥仙','无名氏','宋','宋词','song-ci','鹊桥仙','[]','凤箫羽扇，霓裳云袂，谩尔人间游戏。',68,'宋词/ci.song.20000.json','["凤箫羽扇，霓裳云袂，谩尔人间游戏。", "行看两国锡鸾封，信知道、母因子贵。", "潘舆彩舞，瑶池春媚。", "笑语兰孙共醉。", "大椿一万六千年，自今日、从头数起。"]'),
('song-ci-119','玉楼春','无名氏','宋','宋词','song-ci','玉楼春','[]','戏彩堂高无溽暑。',65,'宋词/ci.song.20000.json','["戏彩堂高无溽暑。", "满座风生闻笑语。", "慈闱今日庆生申，歌遏行云香篆缕。", "万事从今休挂虑。", "儿辈行当壮门户。", "一杯祝寿比庄椿，愿长与、儿孙作主。"]'),
('song-ci-120','减字木兰花','无名氏','宋','宋词','song-ci','减字木兰花','[]','慈闱生日。',52,'宋词/ci.song.20000.json','["慈闱生日。", "恰则今年当八十。", "玉宇澄清。", "五夜分明见寿星。", "恩深鞠育。", "长愿一身全五福。", "满劝椒觞。", "岁岁今朝拜阿娘。"]'),
('song-ci-121','满江红','无名氏','宋','宋词','song-ci','满江红','[]','指日中秋，便满目、蟾光如洗。',112,'宋词/ci.song.20000.json','["指日中秋，便满目、蟾光如洗。", "又还竹溪溪上，长庚瑞世。", "事业权与韩范辈，文章拍调苏黄里。", "借北来双鹤寿芳筵，人千岁。", "羞阿买，依兰砌。", "看大阮，趋枫陛。", "这冰壶人物，蓬山地位。", "荐墨未曾乾翠剡，除书已拟封黄纸。", "把爆筵、趁取牡丹红，花前醉。"]'),
('song-ci-122','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','冬至阳生才两日，欣逢伯氏绂麟辰。',64,'宋词/ci.song.20000.json','["冬至阳生才两日，欣逢伯氏绂麟辰。", "鶺鴒原上欢声沸，棣萼堂前喜气新。", "斟九酝，劝千巡。", "华途从此问云津。", "杨前未把耆年祝，且愿青云早致身。"]'),
('song-ci-123','千秋岁','无名氏','宋','宋词','song-ci','千秋岁','[]','记当初归我，似德耀、嫁梁鸿。',123,'宋词/ci.song.20000.json','["记当初归我，似德耀、嫁梁鸿。", "算三十年间，艰难历遍，甘苦相同。", "新来有孙可抱，也添些、喜色到眉峰。", "今日又逢生日，不妨樽酒从容。", "老翁。", "只是一村农。", "欠你孺人封。", "幸儿渐知耕，妇能知织，莫问穷通。", "君看世间富贵，比浮云、缥缈过晴空。", "何似大家清健，玉林岁岁春风。"]'),
('song-ci-124','蝶恋花','无名氏','宋','宋词','song-ci','蝶恋花','[]','急鼓初锺声报晓。',70,'宋词/ci.song.20000.json','["急鼓初锺声报晓。", "楼上今朝，卷起珠帘早。", "环佩珊珊香袅袅。", "尘埃不到如蓬岛。", "何用珠玑相映照。", "韵胜形清，自有天然好。", "莫向尊前辞醉倒。", "松枝鹤骨偏宜老。"]'),
('song-ci-125','鹊桥仙','无名氏','宋','宋词','song-ci','鹊桥仙','[]','东西二府，掖垣一相，谁似硕人兄弟。',68,'宋词/ci.song.20000.json','["东西二府，掖垣一相，谁似硕人兄弟。", "骖鸾来伴紫阳仙，要同享、橘中千岁。", "银灯初试，花城不夜，铁马响冰春碎。", "来年璧月淡罘罳，看犹有、传柑归遗。"]'),
('song-ci-126','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','长至阳生，律转黄锺，门左弧垂。',139,'宋词/ci.song.20000.json','["长至阳生，律转黄锺，门左弧垂。", "记当年瑞世，梦传玉燕，今朝诞节。", "香爇金猊。", "南极星明，北山堂邃，松桧苍苍龟鹤随。", "况蟠桃下熟，仙童来献，喜介双眉。", "平生谋画多奇。", "算收拾功名须有时。", "曾指麾万骑，刍飞粟挽，折冲千里，彗扫星驰。", "荐口澜翻，宸恩鼎至，此去须还衣锦归。", "人都道，黑头卿相，慷慨男儿。"]'),
('song-ci-127','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','新月光寒昨夜霜。',64,'宋词/ci.song.20000.json','["新月光寒昨夜霜。", "三年不一奉瑶觞。", "朱颜大药知能驻，白日仙家岂计长。", "枫渐赤，橘初黄。", "五湖烟水动归航。", "且倾寿酒歌难老，便见除书出未央。"]'),
('song-ci-128','永遇乐','无名氏','宋','宋词','song-ci','永遇乐','[]','柏颂才过，梅妆方试，六秀蓂荚。',126,'宋词/ci.song.20000.json','["柏颂才过，梅妆方试，六秀蓂荚。", "恰是今朝，白花岩里，一佛生时节。", "前身再现，金城桃熟，千岁莲花重发。", "更一念、善根常在，作个在家菩萨。", "活饥好事，造桥阴骘，乐施常开金穴。", "瑶籍儿孙，玉京夫妇，庆聚神仙窟。", "从今生旦，三千纪算，常对昙华优钵。", "华严会，彩箱庆满僧宝骨。"]'),
('song-ci-129','鹊桥仙','无名氏','宋','宋词','song-ci','鹊桥仙','[]','日长槐夏，凉生冰室，又是生辰来到。',68,'宋词/ci.song.20000.json','["日长槐夏，凉生冰室，又是生辰来到。", "年年把酒对荷花，颜色比、荷花更好。", "儿歌女舞，彩衣共戏，仰祝齐眉偕老。", "欢欢喜喜八千春，更何处、蓬莱仙岛。"]'),
('song-ci-130','菩萨蛮','无名氏','宋','宋词','song-ci','菩萨蛮','[]','秋风扫尽闲花草。',52,'宋词/ci.song.20000.json','["秋风扫尽闲花草。", "黄花不逐秋光老。", "试与插钗头。", "钗头占断秋。", "簪花人有意。", "共祝年年醉。", "不用泛瑶觞。", "花先著酒香。"]'),
('song-ci-131','减字木兰花','无名氏','宋','宋词','song-ci','减字木兰花','[]','祥呈香褓。',52,'宋词/ci.song.20000.json','["祥呈香褓。", "尝记翁生当己卯。", "福禄俱添。", "绿鬓红颜七十三。", "芝兰满砌。", "争著彩衣堂下戏。", "祝寿无涯。", "王母襟期醉九霞。"]'),
('song-ci-132','鹊桥仙','无名氏','宋','宋词','song-ci','鹊桥仙','[]','才临复日，便逢生旦，料想门阑多喜。',68,'宋词/ci.song.20000.json','["才临复日，便逢生旦，料想门阑多喜。", "好将何物寿冰翁，但有个、新词为礼。", "如今已办，一千馀阕，尽按宫商角徵。", "一年一阕祝椿龄，自今日、从头数起。"]'),
('song-ci-133','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','云外青山是我家。',64,'宋词/ci.song.20000.json','["云外青山是我家。", "两年城里作生涯。", "杜陵赏月延秋桂，彭泽无钱对菊花。", "初度日，感年华。", "三杯浊酒一瓯茶。", "尊前儿女休相笑，更有人穷似汝爷。"]'),
('song-ci-134','贺新郎','无名氏','宋','宋词','song-ci','贺新郎','[]','官职从他大。',142,'宋词/ci.song.20000.json','["官职从他大。", "官大时、烦恼偏多，不如到我。", "我有数间临水屋，随分田园些个。", "也薄有、新蔬时果。", "浊酒三杯棋一局，对花前、时抱添丁坐。", "间觅句，唱仍和。", "年年生日人争贺。", "谩相期、黄扉紫闼，玉堂青琐。", "一日平章风月事，奉保永无期祸。", "只如此、有何不可。", "阁箸相疑真可笑，政事堂、日里如何□。", "似恁地，待则麽。"]'),
('song-ci-135','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','久雨忽开霁，花靥斗春娇。',114,'宋词/ci.song.20000.json','["久雨忽开霁，花靥斗春娇。", "家人笑道，老子今日是生朝。", "细数平生功行，断自狂吟之外，全不犯科条。", "心事淡如水，天合与逍遥。", "也何须，期寿算，比松乔。", "但令此去清健，到处狎渔樵。", "说与门前鸥鹭，护我山中杞菊，日日长心苗。", "世事儿戏耳，尊酒百忧消。"]'),
('song-ci-136','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','生羡鸡冠与凤仙。',64,'宋词/ci.song.20000.json','["生羡鸡冠与凤仙。", "时秋华艳遍园间。", "自怜生日悲生事，搔首吴江载月船。", "休身外，且樽前。", "喜君文彩锦相鲜。", "青云贻我长生曲，唤醒凄凉乐暮年。"]'),
('song-ci-137','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','甲子一周，织鸟相催，又还十年。',138,'宋词/ci.song.20000.json','["甲子一周，织鸟相催，又还十年。", "但诗狂酒圣，坐常有客，书痴传癖，囊不留钱。", "拍手浩歌，出门长笑，谁是知心有老天。", "犹多事，更时游艺圃，日耨情田。", "细思世事无边。", "只好把清樽对眼前。", "看槐国功名，有如戏剧，竹林宴赏，便似神仙。", "富贵危机。", "荣华作梦，早已输人一著先。", "从今去、莫将醉趣，与醒人传。"]'),
('song-ci-138','减字木兰花','无名氏','宋','宋词','song-ci','减字木兰花','[]','一丘一壑。',52,'宋词/ci.song.20000.json','["一丘一壑。", "野鹤孤云随处乐。", "篆带纱巾。", "且与筠庄作主人。", "高山流水。", "指下风生千古意。", "寿庆年年。", "长在新秋六日前。"]'),
('song-ci-139','西江月','无名氏','宋','宋词','song-ci','西江月','[]','好个马山居士，功名富贵浮云。',58,'宋词/ci.song.20000.json','["好个马山居士，功名富贵浮云。", "庵儿侧傍万杉阴。", "烟里时横小艇。", "律中林锺将半，华堂寿斝频斟。", "声声齐祝百千龄。", "坐看云仍贵盛。"]'),
('song-ci-140','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','月属重三，蓂开二六，于门车马骈阗。',121,'宋词/ci.song.20000.json','["月属重三，蓂开二六，于门车马骈阗。", "彩麟高设，金鸭喷祥烟。", "试问谁来瑞世，人都道、蓬岛神仙。", "非凡子，年才志学，勋业已精专。", "坐联。", "汤饼客，倾银注玉，盛展华筵。", "羡巍冠初冠，气宇飘然。", "底用遐龄频祝，但愿双亲未老，富贵双全。", "功名事，吾家旧物，早共复青毡。"]'),
('song-ci-141','点绛唇','无名氏','宋','宋词','song-ci','点绛唇','[]','重午日才过，又经四日逢华旦。',51,'宋词/ci.song.20000.json','["重午日才过，又经四日逢华旦。", "月娥降诞。", "春早桃花嫩。", "许字方笄，金雀屏开半。", "东床选。", "门楣壮观。", "偕老行如愿。"]'),
('song-ci-142','贺新郎','无名氏','宋','宋词','song-ci','贺新郎','[]','路入蓝桥境。',140,'宋词/ci.song.20000.json','["路入蓝桥境。", "忆当年、云英来会，玄霜捣尽。", "争似温公风流婿，一笑欢传玉镜。", "便胜似、琼浆玉饮。", "自是振振佳公子，冰肌玉骨相辉映。", "一对儿，好厮称。", "夜深银烛交红影。", "雀屏开、凤帷拥绣，鸳衾铺锦。", "雨意云情应多少，梦到巫山一枕。", "好语向、耳边频听。", "但愿来春青云路，管一枝、青桂嫦娥近。", "闻早寄，凤楼信。"]'),
('song-ci-143','百字谣・念奴娇','无名氏','宋','宋词','song-ci','百字谣・念奴娇','[]','太真姑女，问新来、谁与欢传玉镜。',120,'宋词/ci.song.20000.json','["太真姑女，问新来、谁与欢传玉镜。", "莫恨无人伸好语，人在蓝桥仙境。", "一笑樽前，欢然相与，便胜琼浆饮。", "殷勤客意，耳边说与君听。", "长记旧日君家，门阑喜动，绣褥芙蓉隐。", "回首龙门人得意，又报凤楼芳信。", "只是相传，房奁中物，好事骎骎近。", "管教人道，一双冰玉清润。"]'),
('song-ci-144','鹊桥仙','无名氏','宋','宋词','song-ci','鹊桥仙','[]','风流仙客，文章逸少，复见当年佳婿。',66,'宋词/ci.song.20000.json','["风流仙客，文章逸少，复见当年佳婿。", "夤缘端不数琼姬，向林下、亲逢道气。", "屏开金雀，床铺绣褥，多羡豪家深意。", "凭谁说阿戎，剩觅取、缠头利市。"]'),
('song-ci-145','清平乐','无名氏','宋','宋词','song-ci','清平乐','[]','繁弦急管。',54,'宋词/ci.song.20000.json','["繁弦急管。", "喜色门阑满。", "应是雀屏曾中选。", "新近东床禁脔。", "功名有分非难。", "休因女婿求官。", "幸与嫦娥为伴，直须仙桂新攀。"]'),
('song-ci-146','杏花天','无名氏','宋','宋词','song-ci','杏花天','[]','弟兄旧说河东凤。',66,'宋词/ci.song.20000.json','["弟兄旧说河东凤。", "怎得似、君家伯仲。", "一双白璧殷勤种。", "齐向金屏选中。", "乘龙去、门阑喜动。", "管取早叶、熊罴吉梦。", "儿孙不与尘埃共。", "总是龙驹凤种。"]'),
('song-ci-147','朝中措','无名氏','宋','宋词','song-ci','朝中措','[]','几年弱水望蓬莱。',57,'宋词/ci.song.20000.json','["几年弱水望蓬莱。", "心事喜同谐。", "佳婿欣逢公瑾，新婚喜近英台。", "豪家深意，芙蓉褥隐，金雀屏开。", "但愿门阑多喜，凤楼早寄书来。"]'),
('song-ci-148','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','金贴鼓腰，绣妆檐额，吾宗自昔豪奢。',118,'宋词/ci.song.20000.json','["金贴鼓腰，绣妆檐额，吾宗自昔豪奢。", "椒馨兰馥，烟雾霭横斜。", "吹管聒天今夜，香风度、罗绮光华。", "看双美，郎君俊秀，玉女更宜家。", "繁华。", "歌宴处，金盘撒果，银烛烧花。", "任芙蓉帐掩，翡翠屏遮。", "更看名传桂籍，蓬瀛近、隐泛仙槎。", "归来去，双亲绿鬓，相对饮流霞。"]'),
('song-ci-149','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','乐奏箫韶花烛夜，风流玉女才郎。',70,'宋词/ci.song.20000.json','["乐奏箫韶花烛夜，风流玉女才郎。", "同心结上桂枝香。", "如鸾如凤友，永效两双双。", "莫把画堂深处负，笙歌引入兰房。", "满斟玉斝醉何妨。", "南山堪作誓，福禄应天长。"]'),
('song-ci-150','柳梢青','无名氏','宋','宋词','song-ci','柳梢青','[]','孺子风流，孟尝门地，合下相当。',61,'宋词/ci.song.20000.json','["孺子风流，孟尝门地，合下相当。", "俏似年时，送他织女，来嫁牛郎。", "满堂珠履飞觞。", "看花烛、迎归洞房。", "海誓山盟，从今结了，永效鸾凰。"]'),
('song-ci-151','少年游','无名氏','宋','宋词','song-ci','少年游','[]','上苑莺调舌。',99,'宋词/ci.song.20000.json','["上苑莺调舌。", "暖日融融媚节。", "秦晋新婚，人间天上真奇绝。", "傅粉烟霄，倾国神仙列。", "彼此和鸣，凤楼一处明月。", "歌喉佳宴设。", "鸳帐炉香对爇。", "合卺杯深，少年相睹欢情切。", "罗带盘金缕，好把同心结。", "终取山河，誓为夫妇欢悦。"]'),
('song-ci-152','喜迁莺','无名氏','宋','宋词','song-ci','喜迁莺','[]','早梅天气，正绣户乍启，琼筵才展。',125,'宋词/ci.song.20000.json','["早梅天气，正绣户乍启，琼筵才展。", "鹊渡河桥，云游巫峡，溪泛碧桃花片。", "翠娥侍女来报，莲步已离仙苑。", "待残漏，鸳帐深处，同心双绾。", "欢宴。", "当此际，红烛影中，檀麝飘香篆。", "掷果风流，谪仙才调，佳婿想应堪羡。", "少年俊雅狂荡，蓦有人言拘管。", "镇携手，向花前月下，重门深院。"]'),
('song-ci-153','点绛唇','无名氏','宋','宋词','song-ci','点绛唇','[]','仙子仙郎，两情今是欢娱会。',50,'宋词/ci.song.20000.json','["仙子仙郎，两情今是欢娱会。", "莲花池内。", "好个鸳鸯对。", "一自芳容，一自才华最。", "真佳配。", "荣华富贵。", "寿考千秋岁。"]'),
('song-ci-154','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','烛影摇红玉漏迟。',64,'宋词/ci.song.20000.json','["烛影摇红玉漏迟。", "鹊桥仙子下瑶池。", "倾杯乐处笙歌沸，苏幕遮阑笑语随。", "醉落魄，阮郎归。", "传言玉女步轻移。", "凤凰台上深深愿，一日和鸣十二时。"]'),
('song-ci-155','卜算子','无名氏','宋','宋词','song-ci','卜算子','[]','半破玉梅春，小簇金莲炬。',52,'宋词/ci.song.20000.json','["半破玉梅春，小簇金莲炬。", "结裹风流倬底郎，直入阳台去。", "休诧鹊桥仙，说甚缑山侣。", "便合齐眉八百年，个是真仙子。"]'),
('song-ci-156','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','绛蜡银台晃绣帏。',64,'宋词/ci.song.20000.json','["绛蜡银台晃绣帏。", "一帘香雾拥金猊。", "人间欢会于飞宴，天上佳期乞巧时。", "倾合卺，醉淋漓。", "同心结了倍相宜。", "从今把做嫦娥看，好伴仙郎结桂枝。"]'),
('song-ci-157','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','人道孰为大，尚小易咸常。',114,'宋词/ci.song.20000.json','["人道孰为大，尚小易咸常。", "厥初皇极中建，扶世有三纲。", "仁义阴阳道立，父母乾坤位正，六子发辉光。", "一日不容缓，此意久弥昌。", "杯举庆，天作合，月探囊。", "十年不字以正，乃字便惟良。", "推阐家人一卦，迤逦齐家治国，鼎鼐得姬姜。", "旧物中书令，玉润继汾阳。"]'),
('song-ci-158','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','姑射琼仙，论人间世，学宫样妆。',138,'宋词/ci.song.20000.json','["姑射琼仙，论人间世，学宫样妆。", "费精神刺绣，裁成云锦，今朝喜遇，弱线添长。", "收拾云情，铺张雨态，来嫁朱门趁一阳。", "真还是，两情鱼水，并颈鸳鸯。", "登科人道无双。", "问小底何如大底强。", "幸洞房花烛，得吹箫侣，短檠灯火，伴读书郎。", "办苦工夫，求生富贵，要折丹枝天上香。", "来秋也，看载膺鹗荐，载弄之璋。"]'),
('song-ci-159','西江月','无名氏','宋','宋词','song-ci','西江月','[]','银烛晓催春漏，珠帘暮卷东风。',58,'宋词/ci.song.20000.json','["银烛晓催春漏，珠帘暮卷东风。", "乃翁相对玉楼中。", "不枉当年冰梦。", "花意似随人好，酒香难比情浓。", "夜深欲睡海棠红。", "密密骖鸾驾凤。"]'),
('song-ci-160','满江红','无名氏','宋','宋词','song-ci','满江红','[]','雪意垂垂，算天为、风流酝酿。',113,'宋词/ci.song.20000.json','["雪意垂垂，算天为、风流酝酿。", "便催得、蕊宫仙子，队移仙仗。", "明月珠连湘浦合，清风佩过秦楼响。", "带天香、郁郁碾云軿，通宵降。", "温玉枕，销金帐。", "花烛下，狨毡上。", "这英才美貌，一双不枉。", "鸾凤镜明栖彩翼，鸳鸯被阔翻新浪。", "祝君莫学画眉痴，如张敞。"]'),
('song-ci-161','贺新郎','无名氏','宋','宋词','song-ci','贺新郎','[]','贺鹊冰檐绕。',141,'宋词/ci.song.20000.json','["贺鹊冰檐绕。", "伴华堂、两催妆束，音传青鸟。", "瑞气沉烟金鸭袅。", "脆管繁弦迭奏。", "拥出个、仙娥窈窕。", "秋水芙蓉相映照。", "算人间、天上真希少。", "肌玉润，臂金瘦。", "仙郎况是青春调。", "向鸳鸯、彩丝结就，同心巧。", "料想梅花先得了。", "昨夜一枝开早。", "无地著、许多欢笑。", "准拟计台魁鹗表。", "著青衫、跃马长安道。", "一百岁，一双好。"]'),
('song-ci-162','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','柳眼偷金，梅肌晕玉，春信已催。',139,'宋词/ci.song.20000.json','["柳眼偷金，梅肌晕玉，春信已催。", "正浅寒天气，嫩晴日色，雨收巫峡，烟卷蓬莱。", "青鸟衔音，彩鸾迎驾，白昼传呼王母来。", "屏帏里，看合欢杯尽，连理花开。", "笙歌上下楼台。", "更罗绮丛中薰麝煤。", "想雪香酥暖，粉娇翠软，风流乐事，慰惬情怀。", "花帽兰袍，皂鞋槐简，谁似何郎年少才。", "人偕老，类鸳鸯匹偶，鸾凤和谐。"]'),
('song-ci-163','贺新郎','无名氏','宋','宋词','song-ci','贺新郎','[]','瑞霭笼晴晓。',139,'宋词/ci.song.20000.json','["瑞霭笼晴晓。", "正小春时候，和气十分缭绕。", "月姊精神还窈窕。", "甚似星郎年少。", "同共入、蓬莱仙岛。", "鸾凤铿铿风缥缈。", "算一双、两好真奇妙。", "天上有，世间少。", "桥门名姓掀张了。", "更那堪、榜下新婚，才名表表。", "便好相成勤夙夜，莫使脱簪遗笑。", "且早趁、青春才调。", "向去功名成就后。", "到恁时节风流好。", "胜今日，登科小。"]'),
('song-ci-164','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','阿谁煎凤髓，续此玉琴弦。',114,'宋词/ci.song.20000.json','["阿谁煎凤髓，续此玉琴弦。", "依然音调清婉，律吕互相宣。", "天使彭城姝丽，来配鲁邦才子，永作地行仙。", "况有盈门礼，百两拥骈阗。", "更临鸾，看举案，两无偏。", "从此欢谐千岁，月下与花前。", "剩长芝兰玉树，俱作蟾宫佳客，声誉振螺川。", "仍看明年去，平步上青天。"]'),
('song-ci-165','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','喜气乘龙步步春。',64,'宋词/ci.song.20000.json','["喜气乘龙步步春。", "梅花影里送君行。", "君行直到蓝桥处，一见云英便爱卿。", "鸾鹤舞，凤凰鸣。", "群仙簇拥绿衣人。", "我嗏有句叮咛话，千万时思望白云。"]'),
('song-ci-166','青玉案','无名氏','宋','宋词','song-ci','青玉案','[]','青螺江上梅花暮。',80,'宋词/ci.song.20000.json','["青螺江上梅花暮。", "有姑射、神仙侣。", "剩把明珠倾满斛。", "老仙源委，玉妃风韵，真是欺蛮素。", "彩鸾齐跨山中去。", "浑似天台旧时路。", "试问风流春几许。", "芳心嫩叶，如今时候，好景才三五。"]'),
('song-ci-167','踏莎行','无名氏','宋','宋词','song-ci','踏莎行','[]','金鼎休翻，玉壶休倒。',68,'宋词/ci.song.20000.json','["金鼎休翻，玉壶休倒。", "为伊弹彻求凰操。", "歌台舞榭没长情，不如相伴文园老。", "荆里钗宜，布边裙好。", "有缘封国还他到。", "端能一意谢红尘。", "归来便带宜男草。"]'),
('song-ci-168','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','尧历庆良月，嶰管换新冬。',114,'宋词/ci.song.20000.json','["尧历庆良月，嶰管换新冬。", "玉成西爽，五云拂晓画楼东。", "人指谢家庭砌，眼底猗兰奕叶，特地茁新丛。", "不是善根种，争得占春风。", "步鹏程，名虎榜，早收功。", "建安衣钵，定知他日属奇童。", "且说而今胜事，珠履三千称贺，相对醉颜红。", "拜贺无他语，相庆黑头公。"]'),
('song-ci-169','百字谣・念奴娇','无名氏','宋','宋词','song-ci','百字谣・念奴娇','[]','金秋行令，恰清晨、白露初交中节。',120,'宋词/ci.song.20000.json','["金秋行令，恰清晨、白露初交中节。", "勿怪西窗传好事，生个他年英杰。", "吉梦既符，知如徐子，冰玉为神骨。", "吾家有庆，阶兰喜又新发。", "如今早已生男，清樽华宴，且好延佳客。", "更自承师勤问道，门外不妨立雪。", "抗志云霄，留心简册，听我叮咛说。", "骎骎月殿，桂枝取次高折。"]'),
('song-ci-170','减字木兰花','无名氏','宋','宋词','song-ci','减字木兰花','[]','向来梅发。',52,'宋词/ci.song.20000.json','["向来梅发。", "雪袂仙裳回绛阙。", "今又梅开。", "已领熊罢好梦来。", "试将梅比。", "才著阳和争结子。", "梅子生成。", "早晚须调鼎鼐羹。"]'),
('song-ci-171','西江月','无名氏','宋','宋词','song-ci','西江月','[]','绛蜡攒宝炬，碧刍香衬金卮。',57,'宋词/ci.song.20000.json','["绛蜡攒宝炬，碧刍香衬金卮。", "东风吹下玉龙儿。", "融就满堂和气。", "此日兰汤新浴，他年桂苑同携。", "小词聊代弄璋诗。", "剩与犀钱利市。"]'),
('song-ci-172','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','菊釂萸残玉未颓。',64,'宋词/ci.song.20000.json','["菊釂萸残玉未颓。", "文星喜趁梦熊回。", "预传鲲拟南溟去，亲送魁从北斗来。", "真间世，定奇材。", "满堂欢笑动春雷。", "明年郎罢蟾宫近，更把丹枝为我栽。"]'),
('song-ci-173','长相思','无名氏','宋','宋词','song-ci','长相思','[]','潇洒江梅春早处，天然一种两般奇。',54,'宋词/ci.song.20000.json','["潇洒江梅春早处，天然一种两般奇。", "开花结子，何事恰同时。", "昨夜北枝开雪里，朝来青子又南枝。", "这般好事，消得付新词。"]'),
('song-ci-174','虞美人','无名氏','宋','宋词','song-ci','虞美人','[]','归心正似三春柳。',68,'宋词/ci.song.20000.json','["归心正似三春柳。", "试著莱衣小。", "橘怀几日向翁开。", "怀祖已嗔文度、不归来。", "禅心已断人间爱。", "只有平交在。", "笑论瓜葛一枰同。", "看取《灵光》新赋、有家风。"]'),
('song-ci-175','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','萱草阑干，杨花庭院，夜景澄虚。',139,'宋词/ci.song.20000.json','["萱草阑干，杨花庭院，夜景澄虚。", "望庚星昴宿，荧荧照室，祥烟瑞霭，郁郁充闾。", "白鹿入胎，黄龟献梦，果应君家生凤雏。", "真英物，似崑山片玉，沧海明珠。", "玳筵丝竹□□。", "有多少犀钱分座隅。", "念谢堂冷落，久无神语，淮淝骚扰，谁定边谟。", "天产英雄，地锺秀气，振起家声今有馀。", "□□□，看宫袍加鹄，玉带悬鱼。"]'),
('song-ci-176','水仙子','无名氏','宋','宋词','song-ci','水仙子','[]','晚节寒花犹带蕊。',80,'宋词/ci.song.20000.json','["晚节寒花犹带蕊。", "隐映老人星瑞世。", "绿衣初是政成归，真盛事。", "谁可比。", "那更新来孙又子。", "烟细金炉香旖旎。", "想像瑶池生绿蚁。", "酿成佳气郁葱葱，当此际。", "将一醉。", "百岁从交今日始。"]'),
('song-ci-177','喜迁莺','无名氏','宋','宋词','song-ci','喜迁莺','[]','物中双美。',127,'宋词/ci.song.20000.json','["物中双美。", "惟邺县双凫，禹门双鲤。", "太华双莲，蓝田双璧，剑丰城而已。", "争是一门双秀，又是一朝双喜。", "人总道，机云双陆，同年弧矢。", "希耳。", "会见这，双桂连芳，双鹄冲霄举，鱼诏双金，带横双玉，惟道无双国士。", "但愿双英双戏彩，且直与、双亲儿齿。", "愿岁岁，见东风双燕，满城桃李。"]'),
('song-ci-178','鹊桥仙','无名氏','宋','宋词','song-ci','鹊桥仙','[]','银河星汉，夜凉如洗。',70,'宋词/ci.song.20000.json','["银河星汉，夜凉如洗。", "要轩豁、君家庆瑞。", "果闻两两获骊珠，天付与、精神秋水。", "好是今朝，同逢盛事。", "无限欢欢喜喜。", "他年二陆看杨名，方表得、此时双美。"]'),
('song-ci-179','玉楼春','无名氏','宋','宋词','song-ci','玉楼春','[]','天上双星欢迤逦。',66,'宋词/ci.song.20000.json','["天上双星欢迤逦。", "报道一门双喜。", "果庆双弧矢，双桂连芳，双璧光华起。", "看取他时双彩戏。", "双堕号、机云才子。", "更带横双玉，鱼佩双金，作个无双字。"]'),
('song-ci-180','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','蛮柳眠风，妃棠醉日，春意方浓。',140,'宋词/ci.song.20000.json','["蛮柳眠风，妃棠醉日，春意方浓。", "怪凌晨乾鹊，欢声啧啧，充闾瑞霭，佳气葱葱。", "白鹿效灵，黄龟献梦，还应君生第二龙。", "兰房里，想犀帷晕翠，锦褓裁红。", "五峰。", "秀气攸锺。", "更头玉硗硗天性聪。", "自谪仙芳歇，久尘赋颂，江西派冷，谁嗣宗风。", "骨脉尤香，云仍载诞，衮衮公侯从此封。", "三朝满，好平分犀玉，满泛金锺。"]'),
('song-ci-181','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','明月呈规，祥烟非雾，载符梦铃。',139,'宋词/ci.song.20000.json','["明月呈规，祥烟非雾，载符梦铃。", "记前时已庆，人间鸑鷟，今番再见，天上麒麟。", "知是于门，功标紫府，夜半仙官敕五丁。", "亲送与，向君家作个，难弟难兄。", "绝奇不数徐卿。", "看他日名登千佛经。", "正翁翁矍铄，婆婆老福，薰修觉海，结果初成。", "自愧空词，不酬杯水，汤饼难充堂上宾。", "无功也，这犀钱玉果，敢望平分。"]'),
('song-ci-182','西江月','无名氏','宋','宋词','song-ci','西江月','[]','积玉堆金闲事，惊天动地虚名。',58,'宋词/ci.song.20000.json','["积玉堆金闲事，惊天动地虚名。", "算来二足是人生，有子方为吉庆。", "莫道一夔足矣，也须学著徐卿。", "我翁休笑又添丁。", "这个孩儿好命。"]'),
('song-ci-183','桃源忆故人','无名氏','宋','宋词','song-ci','桃源忆故人','[]','庭槐沐雨翻新翠。',56,'宋词/ci.song.20000.json','["庭槐沐雨翻新翠。", "叠雪香罗初试。", "铃响彩旗天坠。", "忽报徐卿二。", "帘帏坐客欢声沸。", "脱紫须烦半臂。", "借问月娥知未。", "速长蟾宫桂。"]'),
('song-ci-184','喜迁莺','无名氏','宋','宋词','song-ci','喜迁莺','[]','古今三绝。',125,'宋词/ci.song.20000.json','["古今三绝。", "惟郑国三良，汉家三杰。", "三俊才名，三儒文学，更有三君清节。", "争似一门三秀，三子三孙奇特。", "人总道，赛蜀郡三苏，河东三薛。", "庆惬。", "况正是，三月风光，杯好倾三百。", "子并三贤，孙齐三少，俱笃三馀事业。", "文既三冬用，名即三元高揭。", "亲俱庆，看宠加三命，礼膺三接。"]'),
('song-ci-185','剔银灯','无名氏','宋','宋词','song-ci','剔银灯','[]','古来五子伊谁，有唐室、五王称首。',98,'宋词/ci.song.20000.json','["古来五子伊谁，有唐室、五王称首。", "窦氏五龙，柳家五马，西晋室、陶家五柳。", "英名不朽。", "更东汉、马良并秀。", "君今也、五男还又。", "应是五星孕就。", "腹笥五经，身膺五福，指日继、五侯之后。", "个般非偶。", "好与醉、刘伶五斗。"]'),
('song-ci-186','鹊桥仙','无名氏','宋','宋词','song-ci','鹊桥仙','[]','元家道保，白家阿雀，俱生在、五旬有八。',72,'宋词/ci.song.20000.json','["元家道保，白家阿雀，俱生在、五旬有八。", "喜君得子与同年，怪檐外、鹊□嘲哳。", "我疑释老，携来付与，人尽说、眉如翠刷。", "龙门种定入龙门，且早做、韩檠生活。"]'),
('song-ci-187','木兰花・玉楼春','无名氏','宋','宋词','song-ci','木兰花・玉楼春','[]','花间棠棣。',52,'宋词/ci.song.20000.json','["花间棠棣。", "匹似人间兄与弟。", "一种花枝。", "底事当年却盛衰。", "中臧蜾蠃。", "忽遇暝蛉真类我。", "换叶移根。", "要与相辉映一门。"]'),
('song-ci-188','瑞鹧鸪','无名氏','宋','宋词','song-ci','瑞鹧鸪','[]','试问谢庭兰与芝。',64,'宋词/ci.song.20000.json','["试问谢庭兰与芝。", "根花何似接花奇。", "琼蕤不自香闺种，桂种当从月地移。", "须信祝螟成蜾蠃，那须梦虺及熊罴。", "夜来梦报蟾宫籍，新注江家五岁儿。"]'),
('song-ci-189','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','玉琯届良月，璇极炳明星。',112,'宋词/ci.song.20000.json','["玉琯届良月，璇极炳明星。", "适当季舍，有梦应麒麟。", "但愧衡门深隐，偶尔玉川添累，还解振家声。", "乐章歌一阕，笔阵扫千军。", "羡君侯，为学富，焕文清。", "青云咫尺要路，曳紫更腰金。", "顾我荆榛虽茂，其奈栋材无用，何似八千椿。", "君王行赐宴，礼重敬如宾。"]'),
('song-ci-190','酹江月・念奴娇','无名氏','宋','宋词','song-ci','酹江月・念奴娇','[]','天高气爽，正金风玉露，安排秋节。',120,'宋词/ci.song.20000.json','["天高气爽，正金风玉露，安排秋节。", "株守蓬窗无寸效，自愧才非人杰。", "那更家贫，又添丁累，料想无奇骨。", "新章褒美，天然好语还发。", "堪羡力薄无储，宾庖萧萦，乏礼延佳客。", "多谢诸公来宠贲，虽有一瓯春雪。", "玉果未圆，犀钱须办，早早为君说。", "恐辜珠玉，小词聊且权折。"]'),
('song-ci-191','虞美人','无名氏','宋','宋词','song-ci','虞美人','[]','春风吹到深深院。',66,'宋词/ci.song.20000.json','["春风吹到深深院。", "添个人针线。", "莫言生女不妒儿。", "□□二郎不做、有门楣。", "一家姊妹盈盈地。", "兄弟同欢喜。", "彩丝从此不须添。", "看取碧纱帐内、有人牵。"]'),
('song-ci-192','柳梢青','无名氏','宋','宋词','song-ci','柳梢青','[]','玉宇无尘，银蟾低转，渐觉缤纷。',61,'宋词/ci.song.20000.json','["玉宇无尘，银蟾低转，渐觉缤纷。", "还是仙娥，厌游天阙，来降蓬瀛。", "分明秋水精神。", "好嘱取、红叶殷勤。", "觅个檀郎，屏开金雀，玉润冰清。"]'),
('song-ci-193','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','象榻香篝冷宝猊。',64,'宋词/ci.song.20000.json','["象榻香篝冷宝猊。", "虺蛇吉梦寤惊时。", "缇萦生下虽无益，谢女他年或解围。", "花骨脉，雪肤肌。", "飞琼抱送下瑶池。", "弄璋错写何妨事，爱女从来甚爱儿。"]'),
('song-ci-194','清平乐','无名氏','宋','宋词','song-ci','清平乐','[]','梅兄梅弟。',54,'宋词/ci.song.20000.json','["梅兄梅弟。", "桃姊并桃妹。", "争似月临双女位。", "吉梦重占蛇虺。", "小乔应嫁周郎。", "云英定遇裴航。", "会有九男事帝，谁夸七子成行。"]'),
('song-ci-195','柳梢青','无名氏','宋','宋词','song-ci','柳梢青','[]','家近闽南。',59,'宋词/ci.song.20000.json','["家近闽南。", "三姑姊妹，秀揖仙岩。", "须女精神，玉卮标格，谪下尘凡。", "他时佳婿成双，红丝应牵第三。", "倚看樽前，团栾六子，三女三男。"]'),
('song-ci-196','一剪梅・一翦梅','无名氏','宋','宋词','song-ci','一剪梅・一翦梅','[]','太华峰头□□莲。',71,'宋词/ci.song.20000.json','["太华峰头□□莲。", "闻十丈，藕大如船。", "晓来佳气蔼飞烟。", "彩戏盈门。", "弧矢盈门。", "共把长生酒一樽。", "殷勤祝愿，耳畔低言。", "从今流庆更源源。", "子既生孙。", "孙又生孙。"]'),
('song-ci-197','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','祖德绵绵盛，家声烨烨传。',62,'宋词/ci.song.20000.json','["祖德绵绵盛，家声烨烨传。", "流光重庆子生贤。", "想见朝来庭户、起非烟。", "对客延汤饼，呼童散彩钱。", "休夸骨瘦与神全。", "看取犀庭玉角、已朝天。"]'),
('song-ci-198','满江红','无名氏','宋','宋词','song-ci','满江红','[]','月淡风轻，凉意在、碧梧修竹。',115,'宋词/ci.song.20000.json','["月淡风轻，凉意在、碧梧修竹。", "极目际，澄空似水，素秋新沐。", "夜看庚星飞下界，晓传子舍生兰玉。", "想充闾、佳气郁葱葱，香芬馥。", "裁锦褓，铺金褥。", "沉水暖，金盆浴。", "向画堂深处，拥红斟绿。", "况是天潢真相宅，定知丰采惊凡目。", "看他年、槐馆振家声，飞腾速。"]'),
('song-ci-199','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','喜见于门，子月阳生，子舍春回。',138,'宋词/ci.song.20000.json','["喜见于门，子月阳生，子舍春回。", "想释丘抱送，绝奇神骨，皙参授受，忠恕胚胎。", "跨灶参先，撞楼踵后，鼎样一门三秀才。", "应不数，那窦家五桂，王氏三槐。", "南丰门户奇哉。", "他日一声平地雷。", "若非是河东，名传三凤，也应天上，光映三台。", "莫道后时，方为贺客，且把犀钱玉果来。", "却还取，这长生一曲，富贵三杯。"]'),
('song-ci-200','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','燕分炳箕宿，鲁野照奎星。',114,'宋词/ci.song.20000.json','["燕分炳箕宿，鲁野照奎星。", "天开岳渎，储瑞重见吐书麟。", "人道兰庭生谢，我羡竹林得阮，中夜沸欢声。", "奇称符百药，童号迈终军。", "姿禀厚，骨骼异，气神清。", "好把一经为教，切莫诧籝金。", "击瓮画图休展，对日有言可听，材大等庄椿。", "年欲临志学，上国早充宾。"]'),
('song-ci-201','瑞鹧鸪','无名氏','宋','宋词','song-ci','瑞鹧鸪','[]','璇源一派接天流。',64,'宋词/ci.song.20000.json','["璇源一派接天流。", "秀毓君家公共侯。", "满月佳时近重九，生朝令节踵千秋。", "旦评指日腾佳誉，蟾苑他年快壮游。", "气宇如今复何似，相应十倍虎窥牛。"]'),
('song-ci-202','西江月','无名氏','宋','宋词','song-ci','西江月','[]','八月秋中玉律，十分月满瑶台。',58,'宋词/ci.song.20000.json','["八月秋中玉律，十分月满瑶台。", "芳姿谪下佛宫来。", "疑是东方世界。", "黛绿旋闻香发，桃红新晕芳腮。", "春风满面笑容开。", "长似观音自在。"]'),
('song-ci-203','清平乐','无名氏','宋','宋词','song-ci','清平乐','[]','天潢佳气。',54,'宋词/ci.song.20000.json','["天潢佳气。", "锺作人间瑞。", "坐对满堂珠玉贵。", "此日还当周晬。", "手持金印金戈。", "知他壮志如何。", "将相终须大用，姓名早掇巍科。"]'),
('song-ci-204','木兰花・玉楼春','无名氏','宋','宋词','song-ci','木兰花・玉楼春','[]','小春良月。',52,'宋词/ci.song.20000.json','["小春良月。", "尧砌蓂开三数叶。", "瑞启三躔。", "此夕人间诞女仙。", "寿期百岁。", "今日欢娱初庆晬。", "喜事重重。", "亦有嘉祥应梦熊。"]'),
('song-ci-205','杏花天','无名氏','宋','宋词','song-ci','杏花天','[]','画堂帘幕香风细。',63,'宋词/ci.song.20000.json','["画堂帘幕香风细。", "郁郁南阳佳气。", "欢传吉梦占蛇虺。", "此日还当一岁。", "华筵外、初随彩戏。", "早已似、文姬聪慧。", "伫看色动门阑喜。", "便有乘龙佳婿。"]'),
('song-ci-206','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','衮绣堂前，福星开度，寿星入垣。',139,'宋词/ci.song.20000.json','["衮绣堂前，福星开度，寿星入垣。", "有建隆臣普，上天宰辅，绍兴臣鼎，平地神仙。", "入秉钧衡，出分藩屏，托住东南半壁天。", "年来好，甚烽消万里，尘静三边。", "紫宸几度传宣。", "刚不肯归班押讲筵。", "纵云台勋业，已登盟府，金城筹策，犹念中原。", "好袖山河，更扶日月，色正三台第一躔。", "王韩去，愿齐休社稷，於万斯年。"]'),
('song-ci-207','六州歌头','无名氏','宋','宋词','song-ci','六州歌头','[]','扬休玉色，山立秉鸿枢。',179,'宋词/ci.song.20000.json','["扬休玉色，山立秉鸿枢。", "圣天子、方有志，会东都。", "得真儒。", "身佩安危寄，本兵柄，修军政，朝野庆，钧衡任，赖诗谟。", "天上麒麟挺，徐卿子，坐肃憸夫。", "向六阳时候，佳瑞纪门弧。", "炳炳阶符。", "照蓬壶。", "看兄枢使，弟元帅，真盛事，世间无。", "筹密边烽息，凛羌胡。", "玉音俞。", "伫正三槐位，散膏泽，福寰区。", "河如带，山如砺，巩皇图。", "金鼎调元远大，中书考，致主唐虞。", "想公门桃李，应不弃山樗。", "愿借嘘枯。"]'),
('song-ci-208','好事近','无名氏','宋','宋词','song-ci','好事近','[]','春信到梅梢，欲雪又还晴早。',53,'宋词/ci.song.20000.json','["春信到梅梢，欲雪又还晴早。", "趁得绣衣初度，作霜天清晓。", "乡来事直有天知，行拜玉皇诏。", "稳上神仙官府，听履声云杪。"]'),
('song-ci-209','念奴娇','无名氏','宋','宋词','song-ci','念奴娇','[]','素娥不老，才胜赏中秋、无边月色。',120,'宋词/ci.song.20000.json','["素娥不老，才胜赏中秋、无边月色。", "又报仙翁来桂苑，连庆生申佳节。", "玉宇无尘，金茎有露，对景成三绝。", "重阳近也，黄花香入瑶席。", "尽说湖海元龙，裕民堂上，几度吟梅雪。", "满眼阴阴甘棠树，消得寿同南极。", "八桂难留，九芝促觐，早露真消息。", "星辰听履，好看明岁今日。"]'),
('song-ci-210','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','香雾菲微笼薄晓，帘栊爱日如春。',70,'宋词/ci.song.20000.json','["香雾菲微笼薄晓，帘栊爱日如春。", "谪仙游戏到寰瀛。", "金枝推独秀，宝籍著长生。", "锦轴疏恩怡寿母，朱轮光映难兄。", "会看家庆日增荣。", "雁联鸳序立，彩戏衮衣新。"]'),
('song-ci-211','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','皂盖朱幡，玉节虎符，宏开大藩。',138,'宋词/ci.song.20000.json','["皂盖朱幡，玉节虎符，宏开大藩。", "把济川秀楫，试横碧水，擎天柱石，小驻丹山。", "麦秀两歧，棠敷千里，治最当今黄颍川。", "平章看、文词坡谷，人品欧韩。", "竭来游戏人间。", "况雅量汪汪海样宽。", "适弧垂门外，香凝燕寝，□星对照，两地交欢。", "自有青州，活民阴德，不用延年九转丹。", "人皆祝，愿黑头黄阁，绿鬓朱颜。"]'),
('song-ci-212','满江红','无名氏','宋','宋词','song-ci','满江红','[]','长风送月，近中秋、更无一点尘俗。',120,'宋词/ci.song.20000.json','["长风送月，近中秋、更无一点尘俗。", "绛阙真仙来瑞世，昨夜翔鸾飞鹄。", "奕世登科，诸昆竞秀，名盖天南北。", "持心恬退，更能韫椟藏玉。", "须信宪幕平反，据经议狱，全活阴功足。", "川泳云飞宾主意，荐剡新翻浓墨。", "一路欢声，几多和气，吹作长生曲。", "赐环促召，清班两鬓长绿。"]'),
('song-ci-213','满江红','无名氏','宋','宋词','song-ci','满江红','[]','银漏穿花，星河浅、窗胧曙色。',115,'宋词/ci.song.20000.json','["银漏穿花，星河浅、窗胧曙色。", "烧蜜炬、锦帏春煦，瑞烟濛幂。", "堂上金钗行十二，庭前珠履三千客。", "捧流霞、潋滟玉东西，歌声溢。", "全五福，知无敌。", "来百禄，知无极。", "抱龙骧勋策，小劳公力。", "袖内光藏神武剑，他年待正天西北。", "顾贱夫、何可共功名，攀麟翼。"]'),
('song-ci-214','满江红','无名氏','宋','宋词','song-ci','满江红','[]','绿鬓将军，是人道、天生韩霍。',115,'宋词/ci.song.20000.json','["绿鬓将军，是人道、天生韩霍。", "最奇处、虎头燕颔，龙韬豹略。", "卧护懒通天子诏，长驱爱把匈奴缚。", "我皇家、许样大乾坤，身难著。", "试问我，青原约。", "君合再，青油幕。", "这兵书一卷，怎生闲却。", "万里城边须饮马，八公山上多鸣鹤。", "待归来、依旧执金吾，凌烟阁。"]'),
('song-ci-215','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','箫鼓阗街巷，锦绣裹山川。',114,'宋词/ci.song.20000.json','["箫鼓阗街巷，锦绣裹山川。", "夜来南极，闪闪光射泰阶躔。", "陡觉佳祥翕集，听得闾阎笑道，蓬岛降真仙。", "香满琴堂里，人在洞壶天。", "斟凿落，歌窈窕，舞蹁跹。", "重阳虽近，莫把萸菊玷华筵。", "菲礼岂能祝寿，自有仙桃满院，一实数千年。", "早晚朝元会，苍鬓映貂蝉。"]'),
('song-ci-216','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','快阁春边，倚阑干外，东西晚晴。',139,'宋词/ci.song.20000.json','["快阁春边，倚阑干外，东西晚晴。", "有银潢公子，摩挲石刻，金华仙伯，主掌鸥盟。", "陶柳清新，潘花红嫩，早有丰年笑语声。", "还知道，是街头父老，竞说升平。", "怪来昨夜长庚。", "与一道澄江月共明。", "但寿烟起处，千山天远，寿杯满后，千尺泉清。", "兴庆宫中，长生殿里，早踏金鳌背上行。", "明年好，望紫云楼上，一点台星。"]'),
('song-ci-217','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','溪水连天秋雁飞。',64,'宋词/ci.song.20000.json','["溪水连天秋雁飞。", "藕花风细鲤鱼肥。", "阿婆一笑知何事，怀橘郎君衣锦归。", "天上月，几秋期。", "娟娟凉影画堂西。", "堂前拜月人长健，两鬓青如年少时。"]'),
('song-ci-218','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','径竹扶疏，直上青霄，玉立万竿。',139,'宋词/ci.song.20000.json','["径竹扶疏，直上青霄，玉立万竿。", "似冰壶潇洒，虚心直节，清标贞干，风月无边。", "清荫盈庭，细香满座，凡款公门皆七贤。", "称觞旦，与松梅并祝，辞表南山。", "绵延。", "龙种儿孙。", "列砌森庭栖凤鸾。", "况节楼辟命，管城草檄，计台琐试，玉笋联班。", "盛事重重，荐腾楛茧，渡蚁阴功须状元。", "燕山乐，又使符踵至，趣赴淇园。"]'),
('song-ci-219','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','有鹤东来，鸣而向余，借篇寿词。',139,'宋词/ci.song.20000.json','["有鹤东来，鸣而向余，借篇寿词。", "道临皋亭下，坡仙曾梦，锦宫城里，清献常携。", "山斗才名，冰霜节操，苏赵如今重见之。", "生申旦，正菊花开后，橙子黄时。", "自从枳棘鸾栖。", "何尚泛芙蓉绿水池。", "便来归西掖，坐看红药，也应天禄，书照青藜。", "顾我鸡群，来陪燕贺，且祝千年寿与齐。", "樽前鹤，乃翩跹起舞，来上瑶卮。"]'),
('song-ci-220','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','学易喜加数，富贵正当年。',114,'宋词/ci.song.20000.json','["学易喜加数，富贵正当年。", "谁识晚成大器，信道古来然。", "莫叹无闻不足，官政从今艾服，知命自由天。", "恰合买臣愿，好著祖生鞭。", "藏学问，通今古，冠英贤。", "管取一名一第，行折桂枝先。", "未数奉书朱穆，窃笑表微拭镜，接武引群仙。", "生日年年庆，绛老愿齐肩。"]'),
('song-ci-221','减字木兰花','无名氏','宋','宋词','song-ci','减字木兰花','[]','阿兄生日。',52,'宋词/ci.song.20000.json','["阿兄生日。", "屈指今年年五十。", "豆雨初晴。", "昨夜分明见寿星。", "槐黄已迫。", "愿言共展冲天翼。", "桂子飘香。", "看取吾家棣萼芳。"]'),
('song-ci-222','减字木兰花','无名氏','宋','宋词','song-ci','减字木兰花','[]','喜逢生日。',52,'宋词/ci.song.20000.json','["喜逢生日。", "偻指今年方六十。", "次第回春。", "甲子从头又一新。", "敬驰一曲。", "付与歌儿勤为祝。", "满劝金锺。", "试问蟠桃几度红。"]'),
('song-ci-223','西江月','无名氏','宋','宋词','song-ci','西江月','[]','葭管一阳已复，蓂阶五叶还留。',58,'宋词/ci.song.20000.json','["葭管一阳已复，蓂阶五叶还留。", "星瞻南极瑞光浮。", "知是降生时候。", "算衍恰侔周卦，福多更协箕畴。", "绿衣戏舞捧琼舟。", "满劝长生寿酒。"]'),
('song-ci-224','满江红','无名氏','宋','宋词','song-ci','满江红','[]','在昔尝闻，老彭祖、寿龄八百。',115,'宋词/ci.song.20000.json','["在昔尝闻，老彭祖、寿龄八百。", "试屈指、我公今岁，才方八八。", "乙百更添三十六，算来总是公年月。", "对梅花、时候庆生朝，真欢悦。", "儿既劝，金蕉叶。", "孙又把，沉檀爇。", "喜儿孙满目，芝兰英发。", "笑问堂前王母看，而今几度蟠桃结。", "道当时、亲手共栽培，何须说。"]'),
('song-ci-225','满江红','无名氏','宋','宋词','song-ci','满江红','[]','细读箕畴，洛书字、六旬有五。',115,'宋词/ci.song.20000.json','["细读箕畴，洛书字、六旬有五。", "试屈指、我公今岁，恰符其数。", "五福备全几坎九，既言一寿还称富。", "乃今知、好德与康宁，皆由天与。", "记当日，崧生甫。", "喜今夕，逢初度。", "看儿孙鼎盛，贺宾旁午。", "炉暖博山腾麝馥，杯擎琥珀斟香醑。", "问千秋千岁与谁同，西王母。"]'),
('song-ci-226','满江红','无名氏','宋','宋词','song-ci','满江红','[]','安乐窝中，庆华发、苍颜七十。',115,'宋词/ci.song.20000.json','["安乐窝中，庆华发、苍颜七十。", "生处好、十分清瘦，仙风道骨。", "自古天教仁者寿，只今人饮贤人德。", "更一年、两度腊嘉平，垂弧夕。", "华堂上，灵椿匹。", "兰庭下，孙枝七。", "望芹翁次第，年超八秩。", "欢伯便同分玉髓，河儿不用闰瑶笈。", "记醉时、三万六千场，从今日。"]'),
('song-ci-227','壶中天・念奴娇','无名氏','宋','宋词','song-ci','壶中天・念奴娇','[]','古来稀有，只闻道、是个人生七十。',119,'宋词/ci.song.20000.json','["古来稀有，只闻道、是个人生七十。", "还遇小春梅蕊绽，对景装排绮席。", "云帔拖霞，朱颜晕酒，瑞气明南极。", "瑶池欢宴，玉杯争劝琼液。", "堪羡玉叶名郎，天潢毓秀，梧竹生标格。", "百万貔貅归总押，霸气豪无敌。", "藩屏皇家，荣封寿母，名著金闺籍。", "融融液液，共看桃结佳实。"]'),
('song-ci-228','满江红','无名氏','宋','宋词','song-ci','满江红','[]','维岳生贤，天欲补、中兴衮职。',115,'宋词/ci.song.20000.json','["维岳生贤，天欲补、中兴衮职。", "奈圣世、朝无阙事，且令休逸。", "锦绣文章胸次贮，蓬壶岁月闲中积。", "羡人生、七十古来稀，今逾一。", "书聚府，成东壁。", "身眉寿，真南极。", "望瑞云溶处，接江山碧。", "人愿君如天上月，我期君似明朝日。", "待明朝，长至转添长，弥千亿。"]'),
('song-ci-229','最高楼','无名氏','宋','宋词','song-ci','最高楼','[]','蟾宫客、未老得清闲。',98,'宋词/ci.song.20000.json','["蟾宫客、未老得清闲。", "寿算过稀年。", "利名缰锁非关我，浮云富贵付苍天。", "且归休，对松菊，乐林泉。", "比吕望、数犹欠七。", "问师旷、恰符绛一。", "从今遐算更绵延。", "称觞欣近小春候，月当明夜又团圆。", "愿长如，天上月，地行仙。"]'),
('song-ci-230','瑞鹤仙','无名氏','宋','宋词','song-ci','瑞鹤仙','[]','正迎长佳节。',126,'宋词/ci.song.20000.json','["正迎长佳节。", "宴启华筵，有谁能说。", "子孙尽环列。", "见瑞香香袅，寿星明彻。", "丝丝华发。", "记瑶池、宴班曾接。", "笑人间、八十春秋，漫浪风花雪月。", "奇绝。", "诗书教子，陶母等伦，曹家风烈。", "鼎来阴德。", "孙枝秀，桂枝折。", "便从今、一轴金花鸾锦，十藏琅函贝叶。", "是年年、秋月圆时，长生真诀。"]'),
('song-ci-231','壶中天・念奴娇','无名氏','宋','宋词','song-ci','壶中天・念奴娇','[]','人生七十古称稀，何况寿年八十。',119,'宋词/ci.song.20000.json','["人生七十古称稀，何况寿年八十。", "试问何时逢载夙，恰在阳生七日。", "鹤发盈簪，朱颜晕酒，瑞象占南极。", "玳筵才启，欢声喜气充溢。", "好是庭下双珠，经营创置，金玉成堆积。", "况有孙枝争挺秀，次第飞齐鹏翼。", "大振家声，荣封寿母，坐看蟠桃实。", "年年今夕，玉杯争劝琼液。"]'),
('song-ci-232','西江月','无名氏','宋','宋词','song-ci','西江月','[]','剧饮犹能鲸吸，细书仍作蝇头。',58,'宋词/ci.song.20000.json','["剧饮犹能鲸吸，细书仍作蝇头。", "人间八十最风流。", "况又今年九九。", "不用蒲轮加璧，不须磻石垂钩。", "八千春更八千秋。", "但愿灵椿长寿。"]'),
('song-ci-233','水调歌・水调','无名氏','宋','宋词','song-ci','水调歌・水调','[]','雪霁万山出，和气蔼王正。',114,'宋词/ci.song.20000.json','["雪霁万山出，和气蔼王正。", "平园春事竞起，梅柳冻全醒。", "此际朝元归路，疑有真仙呈瑞，笙鹤九宵声。", "东阁识风度，南极粲光明。", "看精神，秋夜月，玉壶冰。", "淳熙相业隆盛，家自得仪刑。", "闻道君王神武，捷报胡儿宵遁，玉殿正论兵。", "行奉紫泥诏，帷幄佐中兴。"]'),
('song-ci-234','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','意一仙翁，自紫府中，出游戏身。',139,'宋词/ci.song.20000.json','["意一仙翁，自紫府中，出游戏身。", "看脊梁铁铸，担当社稷，精神玉炼，照映乾坤。", "谏省伏蒲，紫垣直笔，硬语曾惊天上人。", "福身去，建红牙兼纛，南海之滨。", "天公偏福吾闽。", "遣夜锦开藩为帅臣。", "记前回散了，几多饭碗，如今积了，千万禾囷。", "心与天通，阴功无量，直待时来秉化钧。", "年年宴，在人正次日，寿庆千春。"]'),
('song-ci-235','水调歌・水调','无名氏','宋','宋词','song-ci','水调歌・水调','[]','一札自天下，五马为民来。',114,'宋词/ci.song.20000.json','["一札自天下，五马为民来。", "潜藩久须重镇，帝命出蓬莱。", "曾侍九重笔橐，暂剖一州符竹，人谓屈公材。", "儒术要扬历，玉业待规恢。", "庆三元，才四日，寿筵开。", "夜深仰视霄汉，南极映星台。", "休说石家父子，休说窦家昆季，乔木即三槐。", "归觐玉皇案，馀事付盐梅。"]'),
('song-ci-236','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','太华峰头十丈莲。',64,'宋词/ci.song.20000.json','["太华峰头十丈莲。", "春风种种锦城边。", "只缘仙驭来人世，要作鳌头看上元。", "添宝篆，注金船，曲眉环绕侍歌筵。", "呼童快秣朝天马，后夜端门月正圆。"]'),
('song-ci-237','满江红','无名氏','宋','宋词','song-ci','满江红','[]','灯火星桥，元宵过、春□新霁。',115,'宋词/ci.song.20000.json','["灯火星桥，元宵过、春□新霁。", "潇洒处，梅梢雪暖，柳梢风细。", "嵩岳想储当日秀，麒麟来作人间瑞。", "快风流、小小住蓬瀛，千秋岁。", "书万卷，儿孙贵。", "家万顷，生涯计。", "问阴功厚德，有谁能继。", "鬓雪人间膺上寿，椒觞且尽樽前醉。", "看眼前、龟鹤伴长生，莱衣戏。"]'),
('song-ci-238','庆千秋','无名氏','宋','宋词','song-ci','庆千秋','[]','点检尧蓂，自元宵过了，两荚初飞。',116,'宋词/ci.song.20000.json','["点检尧蓂，自元宵过了，两荚初飞。", "葱葱郁郁佳气，喜溢庭闱。", "惟知降、月里姮娥，欣对良时。", "但见婺星腾瑞彩，年年辉映南箕。", "好是庭阶兰玉，伴一枝丹桂，戏舞莱衣。", "椒觞迭将捧献，歌曲吟诗。", "如王母、款对群仙，同宴瑶池。", "萱草茂长春不老，百千祝寿无期。"]'),
('song-ci-239','永遇乐','无名氏','宋','宋词','song-ci','永遇乐','[]','才过元宵，又经四日，门设弧矢。',128,'宋词/ci.song.20000.json','["才过元宵，又经四日，门设弧矢。", "信道长庚，当年降瑞，缘是诞生李。", "葱葱佳气，今朝重见，洋溢门庭多喜。", "这英贤、文章冠世，取青拾芥难比。", "那堪绿鬓、朱颜年少，暂试牛刀百里。", "迤逦黄堂，平章风月，见说清如水。", "彩庭兰玉，森然挺特，捧献椒觞归美。", "愿从今、增崇福寿，川流山峙。"]'),
('song-ci-240','步蟾宫','无名氏','宋','宋词','song-ci','步蟾宫','[]','垂弧门左当今日。',71,'宋词/ci.song.20000.json','["垂弧门左当今日。", "恰过了、元宵六夕。", "喜妙龄秀发步蟾宫，信富贵、荣华莫敌。", "纪年甲子才三七。", "即翰苑、从容西掖。", "便从兹、谈笑觅封侯，更管取、寿延千亿。"]'),
('song-ci-241','柳梢青','无名氏','宋','宋词','song-ci','柳梢青','[]','爆竹声收，烧灯节过，恰又经旬。',61,'宋词/ci.song.20000.json','["爆竹声收，烧灯节过，恰又经旬。", "闻道当年，长庚梦李，嵩岳生申。", "江淮草木知名。", "有多少、阴功在人。", "只恐称觞，棠阴未徙，促觐枫宸。"]'),
('song-ci-242','满江红','无名氏','宋','宋词','song-ci','满江红','[]','春色三分，才过一、韶华方好。',115,'宋词/ci.song.20000.json','["春色三分，才过一、韶华方好。", "庆初度、万家襦裤，满城欢笑。", "杨柳弄黄风渐软，海棠未放寒犹峭。", "况年丰、粒米不论钱，人皆饱。", "烧绛蜡，斟清醥。", "歌宛转，红围绕。", "看风光蓬岛，乐声云杪。", "白粲连樯先一路，玺书增秩新颁诏。", "看貂蝉、长在玉皇边，应难老。"]'),
('song-ci-243','百字谣・念奴娇','无名氏','宋','宋词','song-ci','百字谣・念奴娇','[]','中和节后，云翳净、向夕新蟾飞出，月姊传声，明日是、紫府神仙诞节。',121,'宋词/ci.song.20000.json','["中和节后，云翳净、向夕新蟾飞出，月姊传声，明日是、紫府神仙诞节。", "彩系麒麟，瑞腾嵩岳，喜气交洋溢。", "魁星头上，光芒仍露消息。", "好是一鹗秋风，鞭云驾雾，去作龙门客。", "看取长安花夹道，人在广寒宫阙。", "春酒千锺，秋娘一曲，大醉豪无敌。", "八千椿算，摩挲重见铜狄。"]'),
('song-ci-244','庆清朝','无名氏','宋','宋词','song-ci','庆清朝','[]','点检尧阶，阶蓂生六叶，春深桃杏花开。',118,'宋词/ci.song.20000.json','["点检尧阶，阶蓂生六叶，春深桃杏花开。", "长庚入梦，重新产谪仙才。", "事业十年灯火，文章笔下若掀雷。", "果然是，两字功名，唾手拿来。", "又况当年强仕，得志青云路，足慰高怀。", "紫泥凤诏，行须非次招徕。", "金马玉堂风月，从容九棘面三槐。", "从今看，会唐九老，它日云台。"]'),
('song-ci-245','最高楼','无名氏','宋','宋词','song-ci','最高楼','[]','中和节过，拈指又经旬。',100,'宋词/ci.song.20000.json','["中和节过，拈指又经旬。", "逢盛旦，诞生申。", "当年昴宿呈佳瑞，今朝南极见箕星。", "寿而昌，年未老，绿袍新。", "宝鸭沉烟堂上袅，珠翠捧、椒觞满斟。", "来庆贺，尽佳宾。", "彩戏斒斓多桂子，更看兰玉列阶庭。", "桓壮椿，祝遐算，八千春。"]'),
('song-ci-246','壶中天・念奴娇','无名氏','宋','宋词','song-ci','壶中天・念奴娇','[]','潇洒幽居，溪园上、新来卜筑。',115,'宋词/ci.song.20000.json','["潇洒幽居，溪园上、新来卜筑。", "况自有、一泓流水，万竿修竹。", "屈指花朝才两夜，祥烟瑞气腾芳郁。", "问辽空、何物堕人间，长庚宿。", "薰宝鸭，烧银烛。", "歌窈窕，倾醽醁。", "愿年年常恁，颜红鬓绿。", "长厚而为难老本，慈仁便是长生箓。", "看芝兰、玉树早蜚英，青毡复。"]'),
('song-ci-247','青玉案','无名氏','宋','宋词','song-ci','青玉案','[]','柳阴花底春将半。',80,'宋词/ci.song.20000.json','["柳阴花底春将半。", "吹不断、祥烟散。", "何处绮罗丝竹乱。", "天孙星里，老人星畔，昨夜光芒现。", "绿衣好把斑衣换。", "照新渥、金花满。", "酌斗深深频祝愿。", "凤池它日，莺花此景，春酒年年劝。"]'),
('song-ci-248','青玉案','无名氏','宋','宋词','song-ci','青玉案','[]','红娇绿软芳菲遍。',81,'宋词/ci.song.20000.json','["红娇绿软芳菲遍。", "正荏苒、春方半。", "帘幕任垂花影乱。", "年年此日，月娥仙子，来赴瑶池宴。", "绮罗暗帘成行满。", "尽酌金樽十分劝。", "愿指松椿为寿算。", "北堂深处，朱颜绿鬓，赢得此身强健。"]'),
('song-ci-249','汉宫春','无名氏','宋','宋词','song-ci','汉宫春','[]','四舞阶蓂，花朝节后，二月阳春。',114,'宋词/ci.song.20000.json','["四舞阶蓂，花朝节后，二月阳春。", "观音降诞，当年对此良辰。", "谁知好日，固多同、重现前身。", "已壮门楣全四德，富将偕老卿卿。", "天意不如人愿，坚柏舟节义，安富尊荣。", "徐君两雏，戏彩歌舞莱庭。", "勤教子、不厌三迁，何异轲亲。", "福寿麻姑伴侣，长笑傲武陵春。"]'),
('song-ci-250','西江月','无名氏','宋','宋词','song-ci','西江月','[]','蓂褪尧阶八叶，桃翻禹浪三层。',58,'宋词/ci.song.20000.json','["蓂褪尧阶八叶，桃翻禹浪三层。", "欢传崧岳挺生申。", "儿女团栾争庆。", "名注长生仙籍，未须仰祝龟龄。", "芳联子舍早蜚声。", "富贵荣华鼎盛。"]'),
('song-ci-251','念奴娇','无名氏','宋','宋词','song-ci','念奴娇','[]','池塘风暖，算流觞盛集，恰迟旬日。',120,'宋词/ci.song.20000.json','["池塘风暖，算流觞盛集，恰迟旬日。", "晓听儿童传好语，瑞气华堂充溢。", "天产英雄，封侯骨相，才气千人敌。", "暂游尘世，妙名已上仙籍。", "争羡金紫盈门，灵椿正茂，荣庆谁能及。", "会展龙韬并豹略，重把山河开辟。", "鼻祖汾阳，佐唐勋业，管取今犹昔。", "旬垂彝鼎，寿龄更比箕翼。"]'),
('song-ci-252','鹊桥仙','无名氏','宋','宋词','song-ci','鹊桥仙','[]','玉叶流芳，金枝孕秀。',67,'宋词/ci.song.20000.json','["玉叶流芳，金枝孕秀。", "那更婺星临照。", "果然谪降月宫仙，四叶蓂、留春半后。", "双麟奇妙，传若速肖。", "彩戏萱庭右。", "行膺世宠更轩昂，看存锡、金花鸾诰。"]'),
('song-ci-253','满江红','无名氏','宋','宋词','song-ci','满江红','[]','今日明朝，三月旦、又将来了。',114,'宋词/ci.song.20000.json','["今日明朝，三月旦、又将来了。", "欣岳降、宝香薰夜，玉麟颁晓。", "一面久劳公镇抚，三年活却人多少。", "幸借留、重许镇西河，新颁诏。", "人共乐，春光好。", "环翠袖，斟清醥。", "记题诗宝扇，屡陪天笑。", "无限金陵怀古意，春寒依旧谁能道。", "看白头红颊本天人，真难老。"]'),
('song-ci-254','解佩令','无名氏','宋','宋词','song-ci','解佩令','[]','曾妙年拾芥功名易。',81,'宋词/ci.song.20000.json','["曾妙年拾芥功名易。", "暂栖鸾、何厌小试。", "迤逦哦松，便整顿、河阳桃李。", "寿几许、也犹固未。", "归来谩、学个陶潜志。", "遇诞辰、昴宿降瑞。", "春色三分才过二。", "寿觞沉醉。", "祝等彭祖八百岁。"]'),
('song-ci-255','齐天乐','无名氏','宋','宋词','song-ci','齐天乐','[]','百花香里莺声好，晴日暖风天气。',123,'宋词/ci.song.20000.json','["百花香里莺声好，晴日暖风天气。", "诗境春融，壶天昼永，今日祥开弧矢。", "疏帘约翠。", "想歌遏行云，暖薰沉水。", "羽扇纶巾，寿星因甚降尘世。", "那堪流觞节近，一樽相庆处，何用辞醉。", "管领溪山，平章风月，从此身心无累。", "明年此际。", "愿添个孙枝，伴君娱戏。", "举案齐眉，更同龟鹤□。"]'),
('song-ci-256','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','罗袜凌波洛浦仙。',64,'宋词/ci.song.20000.json','["罗袜凌波洛浦仙。", "谪来潭府话夤绿。", "应嫌曲水香尘涴，诞降兰亭禊事前。", "歌窈窕，舞婵娟。", "芝兰满室庆团圆。", "殷勤试问刘郎看，阿母蟠桃种几年。"]'),
('song-ci-257','木兰花・玉楼春','无名氏','宋','宋词','song-ci','木兰花・玉楼春','[]','蓂开五叶。',52,'宋词/ci.song.20000.json','["蓂开五叶。", "正是瑶池逢诞节。", "昨夜观星。", "南极边头婺女明。", "家邻九曲。", "寿比群仙何待祝。", "满劝金锺。", "但问蟠桃几度红。"]'),
('song-ci-258','满江红','无名氏','宋','宋词','song-ci','满江红','[]','曲水兰亭，陪宴后、又还三日。',115,'宋词/ci.song.20000.json','["曲水兰亭，陪宴后、又还三日。", "最好是，风檐月观，堕红堆碧。", "乔木故家今有数，太平人物年几百。", "看扶藜、行处乱花飞，神仙宅。", "天地外，逍遥客。", "谈笑里，文章伯。", "是富贵渊明，洞天彭泽。", "老鹤蹁跹摩汉翮，灵龟燕息支床力。", "看一时、长傍寿星边，天南极。"]'),
('song-ci-259','木兰花・玉楼春','无名氏','宋','宋词','song-ci','木兰花・玉楼春','[]','晓烟生绿树，听叶底、数声莺。',121,'宋词/ci.song.20000.json','["晓烟生绿树，听叶底、数声莺。", "正节届清明，蓂开七荚，梦叶长庚。", "桥门旧时冠带，念短檠、读尽夜深灯。", "文价乾坤推重，世紏父子同登。", "莹然玉雪做精神。", "野鹤见长身。", "算婉画崇台，活人多少，自合长生。", "荆襄暂烦佐幕，听秋风鼓角夜连营。", "唤起隆中豪杰，共图盖世功名。"]'),
('song-ci-260','满江红','无名氏','宋','宋词','song-ci','满江红','[]','曲水流觞，又过了、良辰十二。',112,'宋词/ci.song.20000.json','["曲水流觞，又过了、良辰十二。", "好是融融院落，晚春天气。", "天上麒麟呈瑞彩，人间鸑鷟呈祥瑞。", "气飘飘、仙种有其人，汾阳裔。", "金屋里，歌声沸。", "琼斝献，休辞醉。", "问风流人物，螺川能几。", "内翰兰孙衣钵富，外台桂子簪缨贵。", "愿双亲膝下戏斑衣，千秋岁。"]'),
('song-ci-261','虞美人','无名氏','宋','宋词','song-ci','虞美人','[]','贰车领却生朝客。',66,'宋词/ci.song.20000.json','["贰车领却生朝客。", "风月都全得。", "山城小试已馨香。", "真个相家风烈、不寻常。", "寿春一语和戎了。", "阴德知多少。", "年年三月近双旬。", "把酒祝君恩宠、一番新。"]'),
('song-ci-262','福寿千春・自度曲','无名氏','宋','宋词','song-ci','福寿千春・自度曲','[]','柳暗三眠，蓂翻七荚，禀昴萧生时叶。',119,'宋词/ci.song.20000.json','["柳暗三眠，蓂翻七荚，禀昴萧生时叶。", "信道凤毛池上种，却胜河东鸑鷟。", "笃志典坟，经旨素得欧阳学。", "妙文章，赴飞黄，姓名即登雁塔。", "要成发轫勋业。", "便先教济川，整顿舟楫。", "兆朕于今，须从此超迁，荣膺异渥。", "它日趣装事，待还乡欢洽。", "颂椒觞，祝遐算，寿同龟鹤。"]'),
('song-ci-263','千秋岁','无名氏','宋','宋词','song-ci','千秋岁','[]','园林翠幄。',85,'宋词/ci.song.20000.json','["园林翠幄。", "妆点青春色。", "犹觉蓂留七叶。", "崧神今日降，产此真英杰。", "蟾宫客，尽推一代文章伯。", "富贵何心得。", "积善多阴德。", "那管青衫白发。", "儿孙俱满目，诗礼传衣钵。", "长不老，蓝桥是个神仙宅。"]'),
('song-ci-264','庆清朝','无名氏','宋','宋词','song-ci','庆清朝','[]','节过重三，日逢四六，真贤应昴初生。',117,'宋词/ci.song.20000.json','["节过重三，日逢四六，真贤应昴初生。", "元来鼻祖，降瑞应长庚。", "今喜重逢旧事，固宜依旧复青毡。", "果然是、双雕一箭，雁塔书名。", "大器也须小试，鸾凤暂栖，荆棘若为荣。", "从容钜竹双松，足畅吟情。", "行种河阳桃李，即飞诏、入厕朝绅。", "从兹看、箕星上应，南极长明。"]'),
('song-ci-265','满江红','无名氏','宋','宋词','song-ci','满江红','[]','五五芳辰，园林遍、十分春景。',112,'宋词/ci.song.20000.json','["五五芳辰，园林遍、十分春景。", "见瑞香喷兽，烛摇红影。", "知道文星初度旦，细腰歌舞娇姿逞。", "颂椒觞、捧献更殷勤，君拚饮。", "英雄威，风凛凛。", "文章腹，千机锦。", "看青毡复旧，父风挺挺。", "桂子兰孙齐彩戏，祝教寿比天难尽。", "况深居、潭府胜蓬莱，真仙境。"]'),
('song-ci-266','杏花天','无名氏','宋','宋词','song-ci','杏花天','[]','婺星呈瑞，对春馀几许，日临三九。',120,'宋词/ci.song.20000.json','["婺星呈瑞，对春馀几许，日临三九。", "正属我姑初度旦，帨设当年门右。", "绿鬓犹新，红颜未改，真月宫仙友。", "柏舟节义，富而荣贵长守。", "况有诜桂青春，潜心黄卷，指日功名就。", "女郎乘龙全四德，未老得闲仁寿。", "天命方知，岁饥常赈，阴德还多有。", "麻姑王母，年年同宴春酒。"]'),
('song-ci-267','百字歌・自度曲','无名氏','宋','宋词','song-ci','百字歌・自度曲','[]','清和天气，月方生，报道曲江生日。',120,'宋词/ci.song.20000.json','["清和天气，月方生，报道曲江生日。", "一点奎星腾瑞彩，降作人间英杰。", "曾记当时，平分玉果，今已年多历。", "才华拔萃，早宜仙桂高折。", "自是鹗表连登，功收三箭，人羡真无敌。", "雁塔题名方惬意，暂作鸾栖枳棘。", "整顿籍书，紫泥封下，即召归西掖。", "寿膺五福，请君长对箕翼。"]'),
('song-ci-268','步蟾宫','无名氏','宋','宋词','song-ci','步蟾宫','[]','蓂开四叶祥光发。',68,'宋词/ci.song.20000.json','["蓂开四叶祥光发。", "又还是、清和时节。", "昴星呈瑞夜来明，庆此日、挺生英杰。", "少年玉树神清澈。", "未说到、龟龄鹤发。", "愿言鹗荐早蜚声，任丹桂、一枝高折。"]'),
('song-ci-269','千秋岁','无名氏','宋','宋词','song-ci','千秋岁','[]','麟垂绂秀。',87,'宋词/ci.song.20000.json','["麟垂绂秀。", "天纵今司寇。", "朱明景，清和候。", "缙云开帝乐，括苍锺神秀。", "人争羡，昨生一佛今朝又。", "璧水声华茂。", "玉殿天香袖。", "姑小试，陶甄手。", "行为黄阁老，屹立丹墀右。", "名不朽，斯文名脉从君寿。"]'),
('song-ci-270','归朝欢','无名氏','宋','宋词','song-ci','归朝欢','[]','才鼓虞弦薰早入。',122,'宋词/ci.song.20000.json','["才鼓虞弦薰早入。", "昴日三分今恰一。", "清和时节天气佳，绿树莺簧巧调律。", "祥云舒好色。", "瑞气珑葱满籝室。", "又争知、长庚叶梦，太白生今夕。", "快上星辰听履舄。", "州县劳人空役役。", "暂辞朱皂养冲和，绿野堂延蓬岛客。", "华筵倾玉液。", "难老细听歌永锡。", "寿何其，松椿不数，自可齐箕翼。"]'),
('song-ci-271','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','申伯嵩神，李白长庚，萧何昴精。',139,'宋词/ci.song.20000.json','["申伯嵩神，李白长庚，萧何昴精。", "恰先公三日，金仙氏降，后公三日，吕洞宾生。", "五百仙班，一千佛号，喜听胪声传集英。", "君恩重，早升华监寺，扬厉朝廷。", "金瓯已覆香名。", "正天下苍生须太平。", "看黄麻一命，难留五马，蟠桃三熟，会庆千龄。", "一尉凄凉，有官守者，莫到公堂称寿觥。", "三熏沐，但焚香清夜，遥拜台星。"]'),
('song-ci-272','千秋岁引','无名氏','宋','宋词','song-ci','千秋岁引','[]','词赋伟人，当代一英杰。',103,'宋词/ci.song.20000.json','["词赋伟人，当代一英杰。", "信独步儒林蟾宫客。", "名登雁塔正青春，更不历郡县徒劳力。", "即趋朝，典文衡，居花掖。", "得俦词科推第一。", "便掌丝纶天上尺。", "见说庆生辰，当此日。", "翠蓂三四叶方新，朱明正属清和节。", "行作个，黑头公，专调燮。"]'),
('song-ci-273','好事近','无名氏','宋','宋词','song-ci','好事近','[]','记紫极真人，前日是他生日。',53,'宋词/ci.song.20000.json','["记紫极真人，前日是他生日。", "颍水有兹风骨，弥诞当今夕。", "等闲来现宰官身，任凫飞双舄。", "治狱阴功多少，是长生妙术。"]'),
('song-ci-274','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','仙吕已生，真才方产，较迟五日差强。',118,'宋词/ci.song.20000.json','["仙吕已生，真才方产，较迟五日差强。", "谁知天意，孕秀待储祥。", "秋水精神玉骨，向妙龄、富妙文章。", "高轩过，儒林独步，腾踏趁飞黄。", "玉堂。", "金马客，蓬莱事业，花掖圭璋。", "更词科卓冠，时号无双。", "大展经纶有日，须恬退、待趣曹装。", "称觞处，西山风月，南极老人昌。"]'),
('song-ci-275','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','结夏骎寻逾六日，蓬壶纪瑞生辰。',70,'宋词/ci.song.20000.json','["结夏骎寻逾六日，蓬壶纪瑞生辰。", "祥烟葱郁蔼门庭。", "骖鸾双女侍，毓凤二雏新。", "暂尔勾稽淹大手，声名已彻枫宸。", "行膺当路荐章荣。", "璇源添喜庆，椿算祝遐龄。"]'),
('song-ci-276','百字歌・自度曲','无名氏','宋','宋词','song-ci','百字歌・自度曲','[]','清和天气，正风入舜弦，七飞蓂叶。',120,'宋词/ci.song.20000.json','["清和天气，正风入舜弦，七飞蓂叶。", "见说蓝田曾产玉，骨骼瑰奇卓荦。", "志气虹霓，丰姿熊凤，文足倾三峡。", "皇朝伟器，济川有待舟楫。", "要知发轫亲民，栖鸾展骥，五马归台阁。", "退省谦尊防锐进，谁识终南径捷。", "笑傲东山，从容南极，兰桂同欢洽。", "称觞未老，绛人须共年甲。"]'),
('song-ci-277','水仙子','无名氏','宋','宋词','song-ci','水仙子','[]','浮家泛宅生涯好。',80,'宋词/ci.song.20000.json','["浮家泛宅生涯好。", "聚米堆盐多积宝。", "烟波得趣乐江湖，宜乘兴，寻安道。", "不负轩辕当日造。", "初度喜逢维夏早。", "孔释昔曾亲送抱。", "下弦良日是生朝，称觞献，金樽倒。", "惟愿寿筵长不老。"]'),
('song-ci-278','念奴娇','无名氏','宋','宋词','song-ci','念奴娇','["\u957f\u6c5f"]','绿云霁雨，倚晴空千尺，长江澄縠。',120,'宋词/ci.song.20000.json','["绿云霁雨，倚晴空千尺，长江澄縠。", "十里薰低、绣幕四叶，其馀华屋。", "怪得清都，奔云拥鹤，环佩声相续。", "朝来无是，有人初降仙箓。", "且与小试民曹，梅花岭外，雪片三冬足。", "眼底承家人物在，楚楚珪璋兰玉。", "雾阁云窗，翠眉红颊，解唱长生曲。", "壶中难老，定应两鬓长绿。"]'),
('song-ci-279','贺新郎','无名氏','宋','宋词','song-ci','贺新郎','[]','鸾凤初成匹。',139,'宋词/ci.song.20000.json','["鸾凤初成匹。", "想桃源、刘郎仙女，新欢稠密。", "昨夜文星从天降，孕作凡器质。", "却正属、梅黄时日。", "三九良辰佳气蔼，听重重相贺欢声溢。", "又复见，嘉宾集。", "满堂笑语罗筵席。", "道称觞、宴你双庆，有谁能及。", "好事鼎来惬人意，看看功名在即。", "况先得、凤楼消息。", "祈遂与君偕老愿，劝樽前且饮长生液。", "增福寿，至千□。"]'),
('song-ci-280','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','律转蕤宾，星流大火，尧阶蓂荚初开。',118,'宋词/ci.song.20000.json','["律转蕤宾，星流大火，尧阶蓂荚初开。", "当年此日，降下谪仙才。", "见说鸾池荐瑞，蚌珠又、复产渊崖。", "真堪羡，龙生龙子，双庆甚奇哉。", "寄言，汤饼客，好称觞索，玉果倾杯。", "无新亦无旧，事事俱谐。", "他日同筵为寿，彩戏处、酬酢樽罍。", "瞻南极，灵椿丹桂，相继践公台。"]'),
('song-ci-281','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','玉斧折丹桂，锦绣拂银河。',114,'宋词/ci.song.20000.json','["玉斧折丹桂，锦绣拂银河。", "蟠胸虹气千丈，捧砚唤宫娥。", "三度花攒五马，一笑毫挥万字，何处不恩波。", "试问老仙寿，铜狄几摩挲。", "舞槐龙，垂艾虎，弄清和。", "湖山风月，且与吟笑侧金荷。", "明岁端阳时节，人在薰风殿阁，凉意入赓歌。", "宣劝滟昌歜，叠雪赐香罗。"]'),
('song-ci-282','柳梢青','无名氏','宋','宋词','song-ci','柳梢青','[]','荷绽花繁。',60,'宋词/ci.song.20000.json','["荷绽花繁。", "蓂开六荚，喜溢门阑。", "好是骖鸾，特离月殿，来驻人间。", "儿童歌舞衣班。", "接踵升堂视笑颜。", "祝颂勤拳，将何比况，只个南山。"]'),
('song-ci-283','酹江月・念奴娇','无名氏','宋','宋词','song-ci','酹江月・念奴娇','[]','仙翁初度，遇端阳佳节，又还两日。',120,'宋词/ci.song.20000.json','["仙翁初度，遇端阳佳节，又还两日。", "怪得箕星光倍正，凌晓独辉南极。", "料想当年，储祥荐瑞，兆见开先吉。", "称觞此旦，华堂佳气葱郁。", "好看斑戏庭前，芬芳双桂，行作蟾宫客。", "况有瑶池王母在，重庆举杯欢怿。", "络秀赐觞，孟光举案，姑妇贤相敌。", "与君品寿，蓬壶长见仙集。"]'),
('song-ci-284','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','饮了蒲觞五日期。',64,'宋词/ci.song.20000.json','["饮了蒲觞五日期。", "彩丝还系玉麟儿。", "台云荐瑞生香褓，菡萏飘香入寿卮。", "占骨相，孕清奇。", "秋风雁序看齐飞。", "卿家奕世青毡在，况是双亲未老时。"]'),
('song-ci-285','醉蓬莱','无名氏','宋','宋词','song-ci','醉蓬莱','[]','后端阳六日，梅雨收晴，乍炎天气。',120,'宋词/ci.song.20000.json','["后端阳六日，梅雨收晴，乍炎天气。", "阿母当年，罢瑶池佳会。", "排遣双成，屏除青羽，自降居尘世。", "为帝生贤，储祥孕秀，作文章瑞。", "自古人言，陶孟母贤，文行曹家，衣冠苗裔。", "谁似夫人，子龙头鼎贵。", "此去相从，道山蓬岛，镇长生久视。", "却笑问平反，但不作，汉家严吏。"]'),
('song-ci-286','乳燕飞・贺新郎','无名氏','宋','宋词','song-ci','乳燕飞・贺新郎','[]','垛翠云峰远。',140,'宋词/ci.song.20000.json','["垛翠云峰远。", "日乌高、炎官直午，暑风微扇。", "二六尧蓂开秀荚，跨海冰轮待满。", "怪院落、笙箫如剪。", "太乙燃藜天际下，庆卯金仙子生华旦。", "依日月，近云汉。", "经时持橐明光殿。", "问江乡、年来有几，只君方见。", "入座夫人难老甚，炯炯金霞照眼。", "笑指点、琼觞教劝。", "但得调元勋业就，为江泉石磴轻轩冕。", "归共作，赤松伴。"]'),
('song-ci-287','踏莎行','无名氏','宋','宋词','song-ci','踏莎行','[]','花县来迎，瓜期欣至。',68,'宋词/ci.song.20000.json','["花县来迎，瓜期欣至。", "大贤初度今朝是。", "蕤宾律应又将中，明宵圆月光腾瑞。", "兰玉称觞，斑斓舞戏。", "椒浆聊壮君行志。", "看看人已在鹏程，趋朝指日为舟济。"]'),
('song-ci-288','菩萨蛮','无名氏','宋','宋词','song-ci','菩萨蛮','[]','宫样迎春髻。',48,'宋词/ci.song.20000.json','["宫样迎春髻。", "玉步金莲细。", "初度是今朝。", "嫦娥降九宵。", "兰玉行荣贵。", "德备共姜义。", "夏半月团圆。", "称觞祝寿筵。"]'),
('song-ci-289','念奴娇','无名氏','宋','宋词','song-ci','念奴娇','["\u897f\u6e56"]','垂弧纪节，正尧天日永，蓂飞双绿。',120,'宋词/ci.song.20000.json','["垂弧纪节，正尧天日永，蓂飞双绿。", "岳渎锺灵来瑞世，孕出精神冰玉。", "九曲溪山，一船烟雨，物外谁拘束。", "钓头香饵，只愁牵动周卜。", "好是红藕池边，双房毓秀，瑞霭浮崑轴。", "记得君家流庆远，几见祥开陆续。", "来岁花时，西湖十里，叶映恩袍绿。", "竹林小阮，不妨傍借馀馥。"]'),
('song-ci-290','壶中天・念奴娇','无名氏','宋','宋词','song-ci','壶中天・念奴娇','[]','乘鸾驾鹤，问神仙何日，崧高生甫。',121,'宋词/ci.song.20000.json','["乘鸾驾鹤，问神仙何日，崧高生甫。", "飞下琼台，因报道，恰是今年夏五。", "饮了蒲觞，才经半月，昴宿行初度。", "荣华富贵，一时都由分付。", "曾记三月春浓，花风烂熳，吹散鸳鸯侣。", "虽则烧香遥祝寿，争似手斟香醑。", "便驾云軿，去登绣阁，说个诚心语。", "蟠桃熟未，请伊亲问王母。"]'),
('song-ci-291','望远行','无名氏','宋','宋词','song-ci','望远行','[]','青钱流地，更积满籝金玉。',100,'宋词/ci.song.20000.json','["青钱流地，更积满籝金玉。", "斡运营谋，无过是、老郎惯熟。", "利收万倍，归来喜色津津，家道从兹，十分富足。", "好庆生辰，正属蕤宾月半馀。", "六飞蓂荚庭除。", "举盏祝寿，何如子孙，荣贵须臾。", "长是赖你，作个陆地仙客，行乐蓬壶。"]'),
('song-ci-292','感皇恩','无名氏','宋','宋词','song-ci','感皇恩','[]','天水浴英姿，精神清彻。',80,'宋词/ci.song.20000.json','["天水浴英姿，精神清彻。", "偏向蕤宾奈炎热。", "瑞蓂飘飘，却是生贤吉日。", "凌云志气，飘飘无敌。", "头角轩昂，作霖在即。", "谁识功名待时立，一朝腾踏，国赖维城力。", "庆萱堂齐寿，延千亿。"]'),
('song-ci-293','满江红','无名氏','宋','宋词','song-ci','满江红','[]','万甲胸中，问谁似、延安范老。',115,'宋词/ci.song.20000.json','["万甲胸中，问谁似、延安范老。", "当家事，出藩入相，黑头俱了。", "绿野徜徉聊雅志，紫宸寤寐思英表。", "向修门、何日衮衣归，天教早。", "诹吉卜，维熊兆。", "徵瑞梦，长庚耀。", "正尧蓂仲夏，八飞叶小。", "千日早从菑疾退，一觞恰趁笙歌绕。", "算灵椿、何似栎堂春，他犹少。"]'),
('song-ci-294','点绛唇','无名氏','宋','宋词','song-ci','点绛唇','[]','五月如秋，日临四六都无暑。',50,'宋词/ci.song.20000.json','["五月如秋，日临四六都无暑。", "列仙初度。", "听足商岩雨。", "三载都曹，利泽留南浦。", "崆峒路。", "种花无数。", "行对延英主。"]'),
('song-ci-295','谒金门','无名氏','宋','宋词','song-ci','谒金门','[]','文章士。',54,'宋词/ci.song.20000.json','["文章士。", "秀气岳神锺聚。", "看雕鹏、秋风高举。", "上青天平步。", "五五日临夏五。", "堂上称觞笑语。", "桂子兰孙齐彩舞。", "祝寿同彭祖。"]'),
('song-ci-296','朝中措','无名氏','宋','宋词','song-ci','朝中措','[]','天休令节庆生申。',57,'宋词/ci.song.20000.json','["天休令节庆生申。", "喜动满城民。", "十万儿童踊跃，祝公寿等庄椿。", "人生最贵，荣登五马，千里蒙恩。", "只恐促归廊庙，去思有脚阳春。"]'),
('song-ci-297','喜迁莺','无名氏','宋','宋词','song-ci','喜迁莺','[]','生贤时协。',124,'宋词/ci.song.20000.json','["生贤时协。", "正炎官直午，日周三浃。", "门左垂弧，眉间喜色，尽道降神嵩岳。", "百里葱葱和气，总向蓝田会合。", "称庆旦，见吏民鼓舞，欢声和洽。", "玉叶。", "斟劝处，一饮流霞，红艳生双颊。", "钜竹槐松吟哦乐，指日荣膺异渥。", "皇上渴思经济，环召为霖作楫。", "快人望，愿长生，须与绛人同甲。"]'),
('song-ci-298','庆清朝','无名氏','宋','宋词','song-ci','庆清朝','[]','朏月生西，杓星建未，画堂昼景偏长。',115,'宋词/ci.song.20000.json','["朏月生西，杓星建未，画堂昼景偏长。", "天生英杰，独向此炎光。", "超卓凡尘表物，精神秋水自清凉。", "真奇特，清沟挺秀，敌国传芳。", "好是少年折桂，唾手功名就，腾踏飞黄。", "君王眷厚，皇华绣斧还乡。", "士贵姜谟盛事，未容专美独夸唐。", "称觞处，颂闽境、斑戏公堂。"]'),
('song-ci-299','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','六月炎天收火伞，南薰洗尽烦蒸。',70,'宋词/ci.song.20000.json','["六月炎天收火伞，南薰洗尽烦蒸。", "尧蓂七荚又争青。", "问知陈仲举，元是此时生。", "别驾功名清暇日，题兴尚带屏星。", "黑头非晚到公卿。", "且倾浮蚁酒，来听祝龟龄。"]'),
('song-ci-300','贺圣朝','无名氏','宋','宋词','song-ci','贺圣朝','[]','阶蓂八叶当炎赫。',56,'宋词/ci.song.20000.json','["阶蓂八叶当炎赫。", "此际公生日。", "金炉香爇起祥烟，气佳哉葱郁。", "称觞兰玉真无敌。", "尘簪缨世袭。", "鸾栖枳棘暂淹留，即黄扉召入。"]'),
('song-ci-301','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','喜镇龙藩，厌调金鼎，薄言衣锦为荣。',116,'宋词/ci.song.20000.json','["喜镇龙藩，厌调金鼎，薄言衣锦为荣。", "天生申甫，欣对此良辰。", "自是神清气爽，风姿潇洒却炎蒸。", "称觞日，双叶翠蓂，犹未展尧庭。", "帲幪知有赖，国家柱石，须待扶倾。", "暂留公燕逸，抚及瓯闽。", "君念旧人共政，即环召、再秉钧衡。", "平章了，佑王万岁，齐寿永康宁。"]'),
('song-ci-302','百字歌・自度曲','无名氏','宋','宋词','song-ci','百字歌・自度曲','[]','庚金入伏，细推来、明日又还三五。',120,'宋词/ci.song.20000.json','["庚金入伏，细推来、明日又还三五。", "见说帅垣佳气蔼，天降崧神生甫。", "礼乐词章，甲兵韬略，素备文兼武。", "称觞华旦，颂声交赞台府。", "好是比启元戎，剿除逋寇，不许奸偷侮。", "有此奇功高渤海，足慰湖湘生聚。", "暂统十连，折冲万里，行即驱残虏。", "九重环召，万年永佐天子。"]'),
('song-ci-303','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','律纪林锺月，兔魄夜来圆。',114,'宋词/ci.song.20000.json','["律纪林锺月，兔魄夜来圆。", "彩麟入梦，天教英物出人间。", "志气平生浩荡，欲试经纶大手，赞画向名藩。", "见说齐瓜熟，鹏路快扶抟。", "称寿处，歌齿皓，戏衣斑。", "辉联甥馆，那堪一笑共团栾。", "好看蜚声霹雳，使有蒲轮迎召，催入侍龙颜。", "却待功成后，归伴幔亭仙。"]'),
('song-ci-304','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','昴宿储祥，奎星荐瑞，元来天产英姿。',116,'宋词/ci.song.20000.json','["昴宿储祥，奎星荐瑞，元来天产英姿。", "都缘鼻祖，织女与支机。", "自是流芳垂庆，仙风道骨果清奇。", "称觞旦，任从伏暑，三荚看蓂飞。", "文章，谁与敌，欲成大器，殊未为迟。", "况年方强仕，政入官时。", "暂领广文庠序，即超身入凤凰池。", "同经济，云龙风虎，千载庆休期。"]'),
('song-ci-305','西江月','无名氏','宋','宋词','song-ci','西江月','[]','隆暑正当三伏，明朝又是双旬。',58,'宋词/ci.song.20000.json','["隆暑正当三伏，明朝又是双旬。", "崧高孕秀降生申。", "再捧瑶觞称庆。", "督府赞猷英俊，难淹大展经纶。", "倚需召入秉洪钧。", "上佐万年明圣。"]'),
('song-ci-306','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','六月翠蓂飞六荚，流空大火将西。',70,'宋词/ci.song.20000.json','["六月翠蓂飞六荚，流空大火将西。", "当年名世间生时。", "似光风霁月，神爽更精奇。", "三十成名登上第，芙蓉照水真犀。", "难淹逸步造丹墀。", "经纶须大手，谈笑入黄扉。"]'),
('song-ci-307','如意令・如梦令','无名氏','宋','宋词','song-ci','如意令・如梦令','[]','炎暑尚馀八日。',80,'宋词/ci.song.20000.json','["炎暑尚馀八日。", "火老金柔时节。", "闻道间生贤，储秀降神崧极。", "无敌。", "无敌。", "当代人伦准的。", "射策当为第一。", "高跃龙门三级。", "荣著绿袍新，帝渥必加宠锡。", "良弼。", "良弼。", "真个国家柱石。"]'),
('song-ci-308','百字歌・自度曲','无名氏','宋','宋词','song-ci','百字歌・自度曲','[]','乾坤孕秀，正人间六月，下弦时节。',120,'宋词/ci.song.20000.json','["乾坤孕秀，正人间六月，下弦时节。", "生此清奇潇洒客，秋水精神玉骨。", "才吐天芳，毫挥月颖，更彬彬文质。", "图南得志，抟风高展鹏翼。", "好是大器难淹，暂陪庾使，赞画光原隰。", "台省即须登衮衮，黄阁平章有日。", "崔室称觞，莱庭戏彩，中外欢声溢。", "祝君延寿，箕星上应南极。"]'),
('song-ci-309','念奴娇','无名氏','宋','宋词','song-ci','念奴娇','[]','先秋四日，正祥开弧矢，生申佳节。',120,'宋词/ci.song.20000.json','["先秋四日，正祥开弧矢，生申佳节。", "天上彩麟曾入梦，锺作人间英杰。", "袭庆盘坡，流芳星渚，家世绵簪绂。", "昨宵凝眺，老人星现天阙。", "鼎创庭馆连云，宴仙停棹，咫尺尘凡隔。", "好把蟠桃庭外种，坐看花开花结。", "秀长孙枝，辉联子舍，蟾桂行攀折。", "它年称寿，满堂朱紫罗列。"]'),
('song-ci-310','水晶帘・南歌子','无名氏','宋','宋词','song-ci','水晶帘・南歌子','[]','谁道秋期远，正旬浃、双星相见。',121,'宋词/ci.song.20000.json','["谁道秋期远，正旬浃、双星相见。", "雨足西帘，正玉井莲开，寿筵初展。", "麈尾呼风袢暑净，那更著、纶巾羽扇。", "殢清歌，不记杯行，任深任浅。", "湖边小池苑。", "渐苔痕竹色，青青如染。", "辨橘中荷屋，晚芳自占。", "蜗角虚名身外事，付骰子、纷纷戏选。", "喜时平、公道开明，话头正转。"]'),
('song-ci-311','满江红','无名氏','宋','宋词','song-ci','满江红','[]','风露轻清，更十日、却逢七夕。',114,'宋词/ci.song.20000.json','["风露轻清，更十日、却逢七夕。", "庆初度、槐阴初静，藕花凉湿。", "太乙真人曾夜伴，青莲居士何年谪。", "□双凫、游戏宰花封，恩波溢。", "甘雨酿，丰年得。", "和气满，弦歌室。", "向烛花光里，且斟醽醁。", "菊水清於天水净，寿山高似东山峙。", "看诏归天上侍虚皇，骑箕翼。"]'),
('song-ci-312','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','诗礼传家，不名则利，谁能袖手安常。',134,'宋词/ci.song.20000.json','["诗礼传家，不名则利，谁能袖手安常。", "惟君宽厚，无较短论长。", "且自深居简出，清闲处、管甚炎凉。", "年未老，方逾强仕，家富更平康。", "秋声，风欲作，蓂留一荚，伏暑将藏。", "大贤初度日，对此称觞。", "叹凤帏虽冷落，喜御兰、得宠专房。", "见说宁馨少长，螟雏箕、学更高强。", "得闲趣，山中宰相，何必事侯王。"]'),
('song-ci-313','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','此夕薰风息舜弦。',64,'宋词/ci.song.20000.json','["此夕薰风息舜弦。", "明朝早振蓐收权。", "鹊饶喜舌喧华屋，烛富祥光耀绮筵。", "宣玉旨，敕炎官。", "月宫催诞跨鸾仙。", "福如沧海无穷极，寿比灵椿过八千。"]'),
('song-ci-314','壶中天・念奴娇','无名氏','宋','宋词','song-ci','壶中天・念奴娇','[]','秋才三日，听画檐外，数声乌鹊。',119,'宋词/ci.song.20000.json','["秋才三日，听画檐外，数声乌鹊。", "元是嫦娥迎巧夕，预驾横空仙鹤。", "翠鬓生云，朱颜晕酒，□□难描摸。", "优游渤海，玉琴重理弦索。", "曾记乃祖刘晨，天台归后，留得长生药。", "兼有蟠桃三五颗，尽付女孙收著。", "分了仙翁，更分儿息，同作蓬莱约。", "年年今日，大家欢笑为乐。"]'),
('song-ci-315','满江红','无名氏','宋','宋词','song-ci','满江红','[]','一叶知秋，正玉律、新砍夷则。',115,'宋词/ci.song.20000.json','["一叶知秋，正玉律、新砍夷则。", "迟三日、双星齐会，又逢七夕。", "先送天孙来乞巧，姓氏已在长生籍。", "喜华堂、今日庆生辰，排筵席。", "歌金缕，斟琼液。", "听祝寿，环佳客。", "看寿星明灿，祥烟葱郁。", "剩种庭萱春不老，年年嘉会如今日。", "辨一词、一岁一称觞，期千百。"]'),
('song-ci-316','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','[]','填河鹊喜，巧夕来时候。',102,'宋词/ci.song.20000.json','["填河鹊喜，巧夕来时候。", "深院瑞烟浓，隐隐听、梨园清奏。", "兰车玉佩，飞下蕊宫仙，春鬓绿，醉颜红，不减年时旧。", "金杯争劝，尽是闺房秀。", "试问寿何如，与天孙、相为长久。", "看看子舍，添个捧觞人，从此去，尽欢娱，庆事年年有。"]'),
('song-ci-317','鹊桥仙','无名氏','宋','宋词','song-ci','鹊桥仙','[]','星桥才罢，嫩凉如水，一夕祥烟萦绕。',68,'宋词/ci.song.20000.json','["星桥才罢，嫩凉如水，一夕祥烟萦绕。", "欢传玉母宴西池，正绿发、斑衣称寿。", "儿孙鼎贵，弟兄同相，辉映貂蝉前后。", "六宫宣劝锡金桃，看盛事、明年重又。"]'),
('song-ci-318','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','天佑炎图生国瑞，蓝田暂屈英僚。',70,'宋词/ci.song.20000.json','["天佑炎图生国瑞，蓝田暂屈英僚。", "始知昴宿降璇宵。", "中元前五日，七夕后三朝。", "江教风流临此政，少年潇洒奇标。", "行看峻擢相熙朝。", "功名前稷契，寿算等松乔。"]'),
('song-ci-319','千秋岁','无名氏','宋','宋词','song-ci','千秋岁','[]','金陵秋早。',87,'宋词/ci.song.20000.json','["金陵秋早。", "四日中元到。", "天降诞，真英表。", "长庚腾瑞气，箕宿增辉耀。", "膺帝渥，十连镇抚民多少。", "莫惜椒觞倒。", "祝寿称难老。", "分帅阃，江东小。", "看看飞诏下，早趣黄扉召。", "平章了，长生学取神仙道。"]'),
('song-ci-320','水调歌・水调','无名氏','宋','宋词','song-ci','水调歌・水调','[]','称彼兕觥后，三日是中元。',114,'宋词/ci.song.20000.json','["称彼兕觥后，三日是中元。", "地官较善，龙章玉珮压仙班。", "自是德星孕秀，直与寿星争耀，茨福正绵绵。", "堂已富金玉，屣踪视王官。", "趣清闲，心洒落，在花间。", "桃培万岁，千年仙种又栽莲。", "静对秋香菊耐，长共岁寒松老，生意满西园。", "待看椿同桂，洗馥迈燕山。"]'),
('song-ci-321','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','长记秋来多好处，清凉遍满人间。',70,'宋词/ci.song.20000.json','["长记秋来多好处，清凉遍满人间。", "天教收拾孕真贤。", "何时初度日，明日是中元。", "喜与莱公同盛旦，官居鼎鼐相传。", "未应此地借蕃宣。", "来年开宴处，人在凤池边。"]'),
('song-ci-322','瑞鹧鸪','无名氏','宋','宋词','song-ci','瑞鹧鸪','[]','中元过后恰三朝，因甚庭闱喜气飘。',64,'宋词/ci.song.20000.json','["中元过后恰三朝，因甚庭闱喜气飘。", "李谪若非当此夕，申生应是在今宵。", "满斟绿醑歌檀口，慢拍红牙舞柳腰。", "富贵荣华谁得似，祝公千岁乐逍遥。"]'),
('song-ci-323','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','彭郡宗盟，屏山德裔，儒科闻望流传。',119,'宋词/ci.song.20000.json','["彭郡宗盟，屏山德裔，儒科闻望流传。", "不贪世禄，雁塔占先登。", "锦绣文章瑞彩，若披云、快睹青天。", "称觞日，蓂留四叶，葵菽正宜烹。", "星枢，方上应，推君甲子，好问绛人年。", "更遐龄多祝，五福兼全。", "此去沙堤步稳，调金鼎、衮绣貂蝉。", "人皆仰，一门相业，清白子孙贤。"]'),
('song-ci-324','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','秋至人间灏气清。',64,'宋词/ci.song.20000.json','["秋至人间灏气清。", "蓂馀三荚映阶庭。", "挺生豪杰为时瑞，来至簪缨亨世荣。", "天付与，寿康宁。", "不须举酒祝椿龄。", "楼头昨夜瞻南极，偏向梅峰分外明。"]'),
('song-ci-325','折丹桂','无名氏','宋','宋词','song-ci','折丹桂','[]','初秋两两留蓂荚。',68,'宋词/ci.song.20000.json','["初秋两两留蓂荚。", "算恰是、生申佳节。", "祝君寿阅八千秋，岁岁对、长空皓月。", "威宣比部推刚决。", "气凛凛、秋霜争烈。", "滩头双鶒看飞来，便有诏、催归天阙。"]'),
('song-ci-326','水调歌・水调','无名氏','宋','宋词','song-ci','水调歌・水调','[]','两只补天手，一片济时心。',114,'宋词/ci.song.20000.json','["两只补天手，一片济时心。", "信道相门再相，现此宰官身。", "涤洗乾坤都了，填压华戎既定，治世庆升平。", "中外为冠冕，闻望耸簪缨。", "星昴降，蓬矢挂，属芳辰。", "黄阁一秋来早，明日又三旬。", "庭戏莱衣双桂，砌列谢兰无数，廊庙会风云。", "愿衍庄椿算，长沛傅岩霖。"]'),
('song-ci-327','西江月','无名氏','宋','宋词','song-ci','西江月','[]','伴我鹿车鱼釜，从伊裙布钗荆。',58,'宋词/ci.song.20000.json','["伴我鹿车鱼釜，从伊裙布钗荆。", "年年七月甫三旬，今日生朝资庆。", "二女长俱麻绩，三男俱读书声。", "吾年五十不多争，好事且宜少等。"]'),
('song-ci-328','蝶恋花','无名氏','宋','宋词','song-ci','蝶恋花','[]','透户凉生初暑退。',70,'宋词/ci.song.20000.json','["透户凉生初暑退。", "正是尧蓂，六叶方开砌。", "昴宿腾辉来瑞世。", "华堂清晓笙歌沸。", "锦幕花裀生舞袂。", "妙态殊姿，祝寿眉峰翠。", "从此玉觞拼一醉。", "功成名遂千秋岁。"]'),
('song-ci-329','瑞鹤仙','无名氏','宋','宋词','song-ci','瑞鹤仙','[]','朔朝逾六后。',126,'宋词/ci.song.20000.json','["朔朝逾六后。", "正章调南吕，迎寒时候。", "香薰瑞烟袅。", "见门阑喜色，荣生多少。", "元来仙子，拥骖鸾、月宫飞到。", "会人间庆诞，风流俊杰，结成佳偶。", "官好。", "班簪玉笋，名播中都，宠加宸诏。", "金瓯覆。", "黄扉青琐须环召。", "待平章事了，归来养浩，齐眉相对祝寿。", "愿长如、庆会双星，千秋偕老。"]'),
('song-ci-330','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','西掖南宫，黄扉青琐，年来有分终须。',118,'宋词/ci.song.20000.json','["西掖南宫，黄扉青琐，年来有分终须。", "从容曳履，衣锦赋归欤。", "暂乐终南佳处，供笑傲、松菊庭除。", "行看取，一封诏下，装趣入潭居。", "称觞，逢谷旦，千秋节过，三叶蓂舒。", "且冷眼嗤笑，笼鸟池鱼。", "识破林泉朝市，经行处、等是蘧庐。", "知谁似，一杯寿酒，一卷养生书。"]'),
('song-ci-331','洞仙歌','无名氏','宋','宋词','song-ci','洞仙歌','[]','桂风高处，渐近中秋节。',105,'宋词/ci.song.20000.json','["桂风高处，渐近中秋节。", "屈指推来先六日。", "对芳辰、符吉梦，知降神、崧极应诞，主作人间英杰。", "文章逾晁董，学擅卿云，高揭声猷缙绅列。", "上瀛洲册府，师表宗藩，推第一、即黄扉召入。", "佐君王、经邦整顿乾坤，愿寿等广成，更延千百。"]'),
('song-ci-332','壶中天・念奴娇','无名氏','宋','宋词','song-ci','壶中天・念奴娇','[]','才经四日，是中秋，次第月圆如玉。',120,'宋词/ci.song.20000.json','["才经四日，是中秋，次第月圆如玉。", "一点光浮南极上，储作人间五福。", "长厚慈仁，清高恬澹，爱水清山绿。", "溪园竹里，日来新就华屋。", "好是五马传家，芝兰挺秀，早勉群经读。", "将相公侯绵衮衮，重见当年符竹。", "富贵荣华，康宁寿考，聪我殷勤祝。", "更祈王母，共看桃结桃熟。"]'),
('song-ci-333','水调歌・水调','无名氏','宋','宋词','song-ci','水调歌・水调','[]','八月秋欲半，后夜月将圆。',114,'宋词/ci.song.20000.json','["八月秋欲半，后夜月将圆。", "天潢当日流润，馀派落人寰。", "尘扫长淮千里，威振南蛮八郡，梓里绣衣还。", "芳毓燕山桂，庆衍谢庭兰。", "小山阴，长松下，白云间。", "壶中自有天地，闻早挂蓬冠。", "笑指横空丹坚。", "闲倚拿云竹杖，佳处日跻攀。", "山色既无尽，公寿亦如山。"]'),
('song-ci-334','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','宴罢中秋恰四朝。',64,'宋词/ci.song.20000.json','["宴罢中秋恰四朝。", "金炉因甚把香烧。", "若非金母生今日，应是麻姑降此宵。", "歌窈窕，舞娇娆。", "迭将寿酒酌金蕉。", "椿龄柏算何须祝，名列仙班亦孔昭。"]'),
('song-ci-335','好事近','无名氏','宋','宋词','song-ci','好事近','[]','王母庆生辰，方过中秋五日。',54,'宋词/ci.song.20000.json','["王母庆生辰，方过中秋五日。", "子舍文场鏖战，想功名来逼。", "看看喜德捷音传，果信名登桂籍。", "行拜君恩爵赏，寿萱堂永锡。"]'),
('song-ci-336','如意令・如梦令','无名氏','宋','宋词','song-ci','如意令・如梦令','[]','久羡庞眉鹤发。',80,'宋词/ci.song.20000.json','["久羡庞眉鹤发。", "闻望孔堂煊赫。", "信得彭乔仙，秘授长生真诀。", "奇特。", "奇特。", "吕望师周时节。", "才过中秋六日。", "对此称觞欣怿。", "双凤戏莱衣，金缕轻调莺舌。", "难得。", "难得。", "九九算犹千百。"]'),
('song-ci-337','壶中天・念奴娇','无名氏','宋','宋词','song-ci','壶中天・念奴娇','[]','清凉天气，正中秋过后，恰才七日。',120,'宋词/ci.song.20000.json','["清凉天气，正中秋过后，恰才七日。", "岳降生申逢令旦，听得欢声洋溢。", "戏彩堂前，两行珠翠，酒劝杯浮碧。", "祝君遐算，寿星长对南极。", "仰羡性地宽闲，平生酷爱，占断倾城色。", "好展少年攀桂手，同作蟾宫□客。", "料想嫦娥，一枝留待，已得真消息。", "馨香满袖，凤楼人尽怜惜。"]'),
('song-ci-338','百字歌・自度曲','无名氏','宋','宋词','song-ci','百字歌・自度曲','[]','蓂飞十荚，觉九分秋色，六分将极。',121,'宋词/ci.song.20000.json','["蓂飞十荚，觉九分秋色，六分将极。", "桂子风高时更好，天产英贤同日。", "桥梓齐芳，一慈一孝，夺建真奇特。", "称觞华旦，但将老少分别。", "且看戏彩堂前，酒须双献，饮侍严君侧。", "清赏阿戎防跨灶，大小欧□相敌。", "疏曰贤哉，古云有是，作个家家声烈。", "无先无后，寿齐延应□翼。"]'),
('song-ci-339','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','谷旦垂弧矢，兰阃梦熊罴。',114,'宋词/ci.song.20000.json','["谷旦垂弧矢，兰阃梦熊罴。", "称觞内外相庆，同日又同时。", "有此重重盛事，未羡石门奋建，韦氏信名齐。", "珠履赴汤饼，玉果酌琼卮。", "斗枢转，金瓯覆，筑沙堤。", "争推是父是子，相继入黄扉。", "方叔歌猷元老，复见少年黄琬，前后拜丹墀。", "金日寿星现，再祝寿庞眉。"]'),
('song-ci-340','寿星明・沁园春','无名氏','宋','宋词','song-ci','寿星明・沁园春','[]','玉露迎寒，金风荐冷，正兰桂香。',137,'宋词/ci.song.20000.json','["玉露迎寒，金风荐冷，正兰桂香。", "觉秋光过半，日临三九，葱葱佳气，蔼蔼琴堂。", "见说当年，申生谷旦，梦叶长庚天降祥。", "文章伯，英声早著，腾踏飞黄。", "双凫暂驻东阳。", "已种得春阴千种棠。", "有无边风月，几多事业，安排青琐，入与平章。", "百里民歌，一樽春酒，争劝殷勤称寿觞。", "愿此去，龟龄难老，长侍君王。"]'),
('song-ci-341','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','北斗将移，西风已半，蓂馀一叶阶前。',117,'宋词/ci.song.20000.json','["北斗将移，西风已半，蓂馀一叶阶前。", "左弧呈瑞，非雾亦非烟。", "见说长庚入梦，当年此际产英贤。", "谁知得，平生高尚，五福自然全。", "肯堂，夸盛事，一新轮奂，适际荣迁。", "有重重喜庆，贺客骈阗。", "从此燕居笑语，称觞处，好展华筵。", "频祝愿，室家相庆，富寿百千年。"]'),
('song-ci-342','应天长','无名氏','宋','宋词','song-ci','应天长','[]','萱堂积庆，桂苑流芳，于门瑞蔼佳气。',121,'宋词/ci.song.20000.json','["萱堂积庆，桂苑流芳，于门瑞蔼佳气。", "正属仲秋弥月，称觞对此际。", "西王母、来人世。", "拥佩从、尽皆珠翠。", "彩庭下，争看蓝袍，衬斑斓戏。", "富贵有谁同，四德躬全，五福由来备。", "况善断机迁教，轲亲实无异。", "看看仕无淹滞。", "即召入、佐君经济。", "愿延寿，鸾轴金花，年年加赐。"]'),
('song-ci-343','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','露白风清，菊黄萸紫，重阳五日先期。',118,'宋词/ci.song.20000.json','["露白风清，菊黄萸紫，重阳五日先期。", "煌煌郎宿，南极两交辉。", "天上飞凫仙伯，当初度、开宴瑶池。", "民谣里，劝分音德，百姓饱无饥。", "画帘，香篆永，城山堂上，红袖蛾眉。", "任满斟高唱，祝寿新词。", "况是辟书到也，乘别驾、直上横蜚。", "青毡在，看看复见，孝肃旧家时。"]'),
('song-ci-344','醉蓬莱','无名氏','宋','宋词','song-ci','醉蓬莱','[]','正香茱试紫，嫩菊敷黄，九秋佳致。',120,'宋词/ci.song.20000.json','["正香茱试紫，嫩菊敷黄，九秋佳致。", "峻岳生申，运启千龄瑞。", "玉宇澄清，金盘沆瀣，融结锺冲粹。", "地位须还，粉垣薇省，木天蓬秘。", "锦政慈祥，琴堂安静，万里丰年，一同和气。", "斗大雷封，难久蒙私惠。", "半刺平分，剡书交上，逸驾开骅骥。", "来岁称觞，人归清禁，班联丹陛。"]'),
('song-ci-345','风入松','无名氏','宋','宋词','song-ci','风入松','[]','晓来凉气满芙蓉。',90,'宋词/ci.song.20000.json','["晓来凉气满芙蓉。", "日到竹阴东。", "称觞歌袖三千指，屏星畔、绕绿围红。", "茱糁百杯秋色，桂华十里西风。", "生朝对饮菊花丛。", "九日一樽同。", "文章歆向家声旧，便应去、黄阁从容。", "唤起仙翁为寿，种成千岁椿松。"]'),
('song-ci-346','满江红','无名氏','宋','宋词','song-ci','满江红','[]','瑞霭长安，京城里、非烟非雾。',115,'宋词/ci.song.20000.json','["瑞霭长安，京城里、非烟非雾。", "须信道、岳锺神秀，再生商傅。", "节过重阳才一日，祥开蓬岛群仙聚。", "见箕星、昴宿辉文昌，欣初度。", "五马贵，荣朝著。", "人品异，多文富。", "况清廉如水，襦歌督府。", "伫想君正烦燮理，一封召入为霖雨。", "指庄椿、祝寿八千春，从今数。"]'),
('song-ci-347','满江红','无名氏','宋','宋词','song-ci','满江红','[]','一片秋光，看天宇、修眉浮绿。',115,'宋词/ci.song.20000.json','["一片秋光，看天宇、修眉浮绿。", "都怪问、今朝爽气，十分堪掬。", "梅岳仙翁来瑞世，年年好景人间足。", "醉黄花、三日却称觞，锺天禄。", "不用把，香为祝。", "身自有，长生箓。", "只宽平六考，几多戬谷。", "袖手珍祠为足计，急流勇退宁随俗。", "把庄椿、从此计春秋，无穷福。"]'),
('song-ci-348','瑞鹤仙','无名氏','宋','宋词','song-ci','瑞鹤仙','[]','正秋高气肃。',127,'宋词/ci.song.20000.json','["正秋高气肃。", "过重阳四日，蓝田生玉。", "锺英自川渎。", "果文章锦绣，琅玕披腹。", "从容启沃。", "侍甘泉、无用推毂。", "急流勇退，向琳宫养浩，无荣无辱。", "享福。", "欣逢华旦，对此倾觞，满倾醽醁。", "西园晚菊。", "尚堪摘、取馀馥。", "有仙风道骨，康强仁寿，长生何时更祝。", "愿谢公、复起经纶，曹装已促。"]'),
('song-ci-349','满江红','无名氏','宋','宋词','song-ci','满江红','[]','王母当年，瑶池会、曾充坐客。',111,'宋词/ci.song.20000.json','["王母当年，瑶池会、曾充坐客。", "对良辰为寿，复逢佳节。", "屈指重阳才五，明朝月已圆如璧。", "这夫人、真与柏舟姜，同年德。", "佳气霭，看葱郁。", "称觞处，多欣色。", "更萱庭斑戏，桂芳品列。", "未逊轲亲机教力，且如络秀声煊赫。", "问金花、锡宠自谁加，河东薛。"]'),
('song-ci-350','贺新郎','无名氏','宋','宋词','song-ci','贺新郎','[]','喜动神仙屋。',141,'宋词/ci.song.20000.json','["喜动神仙屋。", "正三秋、长空月满，又逾一宿。", "传道垂弧当此日，缘是蓝田生玉。", "更子舍、新归婉淑。", "好事重重欣逢遇，合称觞、宴席倾醽醁。", "拼一醉，欢娱足。", "桃源庆婿歌新曲。", "想蓬莱、仙洞又献，长生真箓。", "看一点、老人照耀，牛女莱庭祝福。", "合长幼、芝兰满目。", "总向来秋高折桂，麻衣换取蓝袍绿。", "永遇乐，食天禄。"]'),
('song-ci-351','千秋岁','无名氏','宋','宋词','song-ci','千秋岁','[]','律调无射。',86,'宋词/ci.song.20000.json','["律调无射。", "月望才逾日。", "昴宿呈祥南极。", "称觞祈五福，膺聘陈双璧。", "彩堂上，老人婺宿光交集。", "龟鹤年相敌。", "孔雀屏开侧。", "喜与寿，俱逢吉。", "门楣他日作，椒觞歌今日。", "看父子，乘龙跨鹤皆仙匹。"]'),
('song-ci-352','鹊桥仙','无名氏','宋','宋词','song-ci','鹊桥仙','[]','龙山宴罢，又经旬日，还报生辰来也。',68,'宋词/ci.song.20000.json','["龙山宴罢，又经旬日，还报生辰来也。", "今年祝寿胜年时，须满劝、十分玉斝。", "鱼书已报，凤帏知道，已备鸾骖鹤驾。", "不须寻药访桃源，且做个、风流驸马。"]'),
('song-ci-353','生查子','无名氏','宋','宋词','song-ci','生查子','[]','才生申十日，便小春时候。',48,'宋词/ci.song.20000.json','["才生申十日，便小春时候。", "硕果已含生，一缕微阳透。", "贞固见天机，寿脉滋培厚。", "菊后早梅前，不尽长生酒。"]'),
('song-ci-354','满江红','无名氏','宋','宋词','song-ci','满江红','[]','万里无云，天同色、祥光满目。',110,'宋词/ci.song.20000.json','["万里无云，天同色、祥光满目。", "见婺星一点，辉联箕宿。", "果是月宫仙子降，诞生乐国人如玉。", "六飞蓂、正属九秋高，清霜肃。", "丹桂盛，蓝袍绿。", "芝兰秀，森如簇。", "庆簪缨几代，家毡欣复。", "萱草长春殊未老，君恩加锡金花轴。", "款陪王母宴瑶池，蟠桃熟。"]'),
('song-ci-355','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','["\u9ec4\u6cb3"]','菊花新过，秋蕊香犹媚。',102,'宋词/ci.song.20000.json','["菊花新过，秋蕊香犹媚。", "三八燕山亭，贺圣朝、申生明世。", "肃霜天晓，正快活年时，庆新寿，万年欢，人醉蓬莱里。", "红衫儿歌，水调夸多丽。", "仰祝寿星明，指黄河、清年可拟。", "欢同鱼水，永遇乐倾杯，风流子、洞仙歌，曲唱千秋岁。"]'),
('song-ci-356','满朝欢','无名氏','宋','宋词','song-ci','满朝欢','[]','一点箕星，近天边，光彩辉耀南极。',122,'宋词/ci.song.20000.json','["一点箕星，近天边，光彩辉耀南极。", "竹马儿童，尽道使君生日。", "元是凤池仙客。", "曾曳履、持荷簪笔。", "称觞处，晚节花香，月周犹待五夕。", "谁道久拘禁掖。", "任双旌五马，暂从游逸。", "九棘三槐，都是等闲亲植。", "见说玉皇侧席。", "但早晚、促归调燮。", "功成了，笑傲南山，寿如南山松柏。"]'),
('song-ci-357','瑞鹤仙','无名氏','宋','宋词','song-ci','瑞鹤仙','[]','过重阳三九。',127,'宋词/ci.song.20000.json','["过重阳三九。", "正日行析木，方移旦柳。", "天公爱黔首。", "念整顿乾坤，须还大手。", "蚌珠才剖。", "玉麒麟、世间希有。", "想当年，玉燕投怀，瑞气应冲牛斗。", "非偶。", "节逢庆会，华渚虹流，北枢电绕。", "明良须偶。", "盈月第、分前后。", "念元鸟生商，嵩神孕甫，两听管弦新奏。", "愿年年，主圣臣贤，与天长久。"]'),
('song-ci-358','醉蓬莱','无名氏','宋','宋词','song-ci','醉蓬莱','[]','望秋高梨岭，星下莆阳，庆生贤哲。',116,'宋词/ci.song.20000.json','["望秋高梨岭，星下莆阳，庆生贤哲。", "问瑞蓂留两荚。", "小试宏才，暂劳雕邑，布阳春仁泽。", "庭有驯禽，村无吠犬，稻黄连陌。", "最是邦人，合掌顶戴，萱草年华，蟠桃春色。", "却笑仙翁，觅丹砂金诀。", "德满人间，诏来天上，看寿名俱得。", "岁岁霞觞，凤凰池畔，贺生辰节。"]'),
('song-ci-359','真珠帘','无名氏','宋','宋词','song-ci','真珠帘','[]','隔云一雁衔秋去。',123,'宋词/ci.song.20000.json','["隔云一雁衔秋去。", "苏堤上、听得游人相语。", "疏影暗香中，谁与花为主。", "满目有山无限意。", "跨白鹤、云霄飞舞。", "飞舞。", "正断桥流水，苍苔生处。", "应羡地暖江南，近小春时节，南枝先吐。", "人似此花清，人比花尤苦。", "移向樽前须识取。", "只许与、松篁为侣。", "为侣。", "待金鼎调羹，百花红紫。"]'),
('song-ci-360','上阳春・蓦山溪','无名氏','宋','宋词','song-ci','上阳春・蓦山溪','[]','两日梅开，先占阳春小。',99,'宋词/ci.song.20000.json','["两日梅开，先占阳春小。", "鸾凤偶雁行，飞舞画堂交绕。", "称觞盛旦，二老同年少。", "夫劝妇，弟酬兄，四喜人希有。", "灵椿萱草，青翠俱长久。", "棠棣戏斑斓，对立齐上长生酒。", "有亲有序，慈孝兼恭友。", "登科日，未老时，共享南山寿。"]'),
('song-ci-361','西江月','无名氏','宋','宋词','song-ci','西江月','[]','才入冬来三日，人都道小春来。',57,'宋词/ci.song.20000.json','["才入冬来三日，人都道小春来。", "生生一脉早胚胎。", "消息南枝大。", "好向腊前冬后，贞元接处滋培。", "调羹手段栋梁材。", "直待文明嘉会。"]'),
('song-ci-362','西江月','无名氏','宋','宋词','song-ci','西江月','[]','良月才经四日，彭城庆诞真贤。',58,'宋词/ci.song.20000.json','["良月才经四日，彭城庆诞真贤。", "从来斗酒百诗篇。", "锦绣文章灿烂。", "自合宰官身现，谁知富贵由天。", "但教福寿喜双全。", "直看子孙荣显。"]'),
('song-ci-363','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','瑞霭非烟，小春良月，翠开五叶阶蓂。',118,'宋词/ci.song.20000.json','["瑞霭非烟，小春良月，翠开五叶阶蓂。", "补陀现相，今日庆生辰。", "江夏芳流秀国，芝兰茂、世袭簪缨。", "天恩厚，金花屡锡，偕老共卿卿。", "画堂，歌舞处，香浮宝鸭，寿酒频斟。", "愿朱颜绿鬓，常似青春。", "待得蟠桃三熟，与群仙、会宴西清。", "台星照，婺星箕耀，南极镇长明。"]'),
('song-ci-364','鱼水同欢・蝶恋花','无名氏','宋','宋词','song-ci','鱼水同欢・蝶恋花','[]','棣萼楼前佳气蔼。',70,'宋词/ci.song.20000.json','["棣萼楼前佳气蔼。", "欣遇称觞，正斗杓移亥。", "三两日来连庆会。", "贺宾喜色增加倍。", "未逊徐雏分小大。", "好比晋朝，二陆休声在。", "更祝灵椿颜不改。", "三苏相继居台宰。"]'),
('song-ci-365','一箩金・蝶恋花','无名氏','宋','宋词','song-ci','一箩金・蝶恋花','[]','新冬十叶蓂添一。',52,'宋词/ci.song.20000.json','["新冬十叶蓂添一。", "良辰喜是翁生日。", "金鸭爇沉香。", "祥烟绕画堂。", "遐龄方五十。", "厚福犹千百。", "看取小甥孙。", "年年捧寿樽。"]'),
('song-ci-366','满江红','无名氏','宋','宋词','song-ci','满江红','[]','好景欣逢，须记取、小阳春暖。',112,'宋词/ci.song.20000.json','["好景欣逢，须记取、小阳春暖。", "算夜来浃日，今朝生旦。", "对此称觞春酒献，郁葱佳气琴堂满。", "问使君、记纪绛人年，耆颐半。", "天付与，文章灿。", "牛刀试，风流县。", "笑陶情松菊，主人懒散。", "谁识东山真捷径，银章博取新貂衮。", "愿潭居、槐府展经纶，延椿算。"]'),
('song-ci-367','感皇恩','无名氏','宋','宋词','song-ci','感皇恩','[]','明夜月团圆，小春霜早。',81,'宋词/ci.song.20000.json','["明夜月团圆，小春霜早。", "今日由来佳气好。", "都城传道，翰苑称觞欢笑。", "知是当年，诞生元老。", "新来曾见，金莲送到。", "一任芳樽频醉倒。", "判花西掖，独掞春华词藻。", "召归紫闼，永为师保。"]'),
('song-ci-368','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','冰壑平生，如伯伦狂，似希乐豪。',139,'宋词/ci.song.20000.json','["冰壑平生，如伯伦狂，似希乐豪。", "喜观书不用、菊茶明眼，登山不倩、藜杖扶腰。", "豆粥萍齑，脍羹鳞脯，湖海人常折简招。", "谁云老，有满怀风月，藏在诗瓢。", "凌晨向鹄冲霄。", "道昴宿于今又应萧。", "记垂弧令节，恰当后日，下元好景，正属前朝。", "冷胆如天，刚肠如剑，须把千杯寿酒浇。", "那堪更，是梅花时月，烂熳溪桥。"]'),
('song-ci-369','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','橘记一年景，梅泄小春英。',114,'宋词/ci.song.20000.json','["橘记一年景，梅泄小春英。", "见说彭成仙隐，对此庆生辰。", "寿比太公欠一，年并楚丘逾九，益壮异常人。", "细数称觞日，信宿两弥旬。", "戏莱衣，桥梓列，桂兰荣。", "一门盛事难得，一子两层孙。", "休论若儿渠父，差胜杨椿黄琬，四代眼前亲。", "积善有馀庆，享福百千春。"]'),
('song-ci-370','玉楼春','无名氏','宋','宋词','song-ci','玉楼春','[]','姑苏台上春光泄。',64,'宋词/ci.song.20000.json','["姑苏台上春光泄。", "菊老寒轻香未歇。", "人言太守是龚黄，天为吾君生稷契。", "明良庆会俱良月。", "万岁千秋同瑞节。", "明朝仙领趣持鳌，十万人家齐卧辙。"]'),
('song-ci-371','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','良月霜晴，小春寒浅，瑞蓂九叶朝飞。',118,'宋词/ci.song.20000.json','["良月霜晴，小春寒浅，瑞蓂九叶朝飞。", "岭梅香度，初发向南枝。", "此际高门袭庆，真贤降、金璧争辉。", "传瀛海，向歆父子，相望姓名垂。", "广寒，仙籍在，笔驱造化，文照虹霓。", "暂徘徊莲幕，名誉英驰。", "行簉夔龙步武，蓬山静，玉宇春熙。", "当清夜，神交太乙，相对照青藜。"]'),
('song-ci-372','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','[]','月惟四日。',102,'宋词/ci.song.20000.json','["月惟四日。", "又转黄锺律。", "好景会生辰，是天降、真儒无敌。", "称觞设席，香雾腾葱郁。", "霜天晓，笙歌彻，玉斝倾仙液。", "当年桂子，元是蓬莱客。", "任留宿蓬莱，道山试、玉堂翰墨。", "一封飞下，趣召入黄扉，台星照，寿星明，相映居南极。"]'),
('song-ci-373','洞仙歌','无名氏','宋','宋词','song-ci','洞仙歌','[]','潭潭仙隐，婺宿光联地。',105,'宋词/ci.song.20000.json','["潭潭仙隐，婺宿光联地。", "喜见门阑蔼佳气。", "对芳辰，诮一似、王母会瑶池，又却是、夫人诞生明世。", "普陀见真相，淑德温柔，更比嫦娥又何异。", "小春吉月，日数推来，成七四好景，杯觞须记。", "况荣贵，见青紫满门，争戏舞莱衣，祝千秋岁。"]'),
('song-ci-374','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','今日小春月，后日是周正。',114,'宋词/ci.song.20000.json','["今日小春月，后日是周正。", "瑞蔼挹仙堂上，崧岳喜生申。", "文物师垣宅相，诗礼枢庭世胄，冰骨玉精神。", "浩气凌牛斗，胸次敻凡尘。", "郭中书，广成子，李长庚。", "勋业词章福寿，直上等三人。", "松菊亭前诗酒，梅竹园中翰墨，时复萃嘉宾。", "人指屏山下，双桂一灵椿。"]'),
('song-ci-375','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','三叶翠蓂开子月，九天降诞文星。',70,'宋词/ci.song.20000.json','["三叶翠蓂开子月，九天降诞文星。", "满堂佳气蔼祥云。", "称觞椒有颂，介寿酒浮春。", "强仕宜为攀折客，须知富贵催人。", "看看雁塔即联名。", "一门夸盛事，棠棣对灵椿。"]'),
('song-ci-376','醉蓬莱','无名氏','宋','宋词','song-ci','醉蓬莱','[]','正霜融日暖，两两蓂开，阳生时候。',117,'宋词/ci.song.20000.json','["正霜融日暖，两两蓂开，阳生时候。", "喜见文星，上有箕星照。", "须信岳神，储降，诞作儒林秀。", "一举登科，蟾宫稳步，桂香满袖。", "天赋麒麟，奇骨尽羡，德耀宗盟，有谁居右。", "宠擢珍图，龙序褒勋厚。", "两郡棠阴，一封芝检，飞来到如。", "结束曹装，入居黄阁，双亲未老。"]'),
('song-ci-377','木兰花慢','无名氏','宋','宋词','song-ci','木兰花慢','[]','腊前冬至后，报春意、动南坡。',119,'宋词/ci.song.20000.json','["腊前冬至后，报春意、动南坡。", "见葭管浮灰，梅英缀玉，漏泄阳和。", "阶蓂呈瑞五叶，祥开崧岳耸嵯峨。", "笑拥两行珠翠，欢腾一曲笙歌。", "试将铜狄细摩挲。", "问寿富如何。", "道寿等冈陵，富连阡陌，福禄多多。", "德门最堪羡处，有乔松丹桂映婆娑。", "管取脱身簿领，即登奕世儒科。"]'),
('song-ci-378','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','宝历契昌运，岳渎启珍符。',114,'宋词/ci.song.20000.json','["宝历契昌运，岳渎启珍符。", "汾阳忠义勋阅，此际挂蓬弧。", "正属阳生子月，始见蓂敷六荚，宝剑出昆吾。", "芒射斗牛分，光彩照坤舆。", "备文武，宏器量，足谋谟。", "世传韬略，出专阃制誓平胡。", "尽护貔貅百万，仰副九重委注，指日复舆图。", "祝寿如山阜，进位陟洪枢。"]'),
('song-ci-379','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','月琯循环届仲冬。',64,'宋词/ci.song.20000.json','["月琯循环届仲冬。", "蓂生十叶气葱葱。", "梅花香里开华宴，柏酒樽前拜寿翁。", "檀乍爇，烛微笼。", "儿孙罗列劝金锺。", "点头更问儿孙看，慈母蟠桃几度红。"]'),
('song-ci-380','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','鲁观书云方在候，颍川家庆非常。',70,'宋词/ci.song.20000.json','["鲁观书云方在候，颍川家庆非常。", "望前四日上椒觞。", "北堂人未老，南极夜增光。", "借问遐龄今几许，希年恰喜相当。", "愿同王母寿延长。", "蟠桃看屡熟，萱草镇长芳。"]'),
('song-ci-381','百字谣・念奴娇','无名氏','宋','宋词','song-ci','百字谣・念奴娇','[]','一阳来复，正日临三四，梅英露白。',120,'宋词/ci.song.20000.json','["一阳来复，正日临三四，梅英露白。", "玉燕当年曾入梦，瑞应果生人杰。", "金玉文章，圭璋闻望，早作蟾宫客。", "来趋莲幕，片言珍重能决。", "自知阴德居多，仕途应显，州县何劳力。", "况有儿孙俱挺特，管取桂枝高折。", "桥梓齐芳，芝兰并秀，甚盛家声籍。", "祝君长寿，一门荣贵无极。"]'),
('song-ci-382','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','要问南枝消息早，一阳恰喜方回。',70,'宋词/ci.song.20000.json','["要问南枝消息早，一阳恰喜方回。", "望前二日验云台。", "祥光呈五色，瑞彩上三台。", "生机一脉何尝息，正看用世真才。", "调羹手段此胚胎。", "文明观盛会，直待六阳来。"]'),
('song-ci-383','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','阳复今朝，月圆明日，渭溪改观风光。',119,'宋词/ci.song.20000.json','["阳复今朝，月圆明日，渭溪改观风光。", "今枝孕秀，馀庆衍天潢。", "诞降真英间世，群仙贺、喜萃华堂。", "那勘见，灵椿未老，丹桂两芬芳。", "烛摇，香雾拥，翠蛾歌舞，齐上椒觞。", "且殷勤仰祝，华算等天长。", "况蕴智谋韬略，维城志、屏翰君王。", "待收取、平戎功业，军国赖平章。"]'),
('song-ci-384','满江红','无名氏','宋','宋词','song-ci','满江红','[]','阳律方回，月圆后、又逾两日。',115,'宋词/ci.song.20000.json','["阳律方回，月圆后、又逾两日。", "想当年，秀锺峻岳，复生申□。", "重庆蓬弧呈瑞旦，盈门喜气先洋溢。", "羡璇穹、箕宿动祥光，辉南极。", "延遐算，希年及。", "康宁富，无亏一。", "论箕畴五福，总全天锡。", "鹤发未教垂雪彩，凤毛行展冲霄翼。", "愿彩庭、岁岁捧霞觞，倾仙液。"]'),
('song-ci-385','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','关中有萧相，江左见夷吾。',114,'宋词/ci.song.20000.json','["关中有萧相，江左见夷吾。", "中兴帝赉良弼，休运应乾符。", "百五期过一日，十万声号半夜，南极灿晴虚。", "崧岳生申甫，河洛出图书。", "领坡仙，陪橐从，镇潜都。", "九重作夜有梦，问到北岩无。", "须信建溪桃李，难驻商川舟楫，归去伴都俞。", "岁伴南山寿，日拱北辰居。"]'),
('song-ci-386','万年欢','无名氏','宋','宋词','song-ci','万年欢','[]','律应黄锺，蓂飞六荚，今朝是、嵩岳生申。',137,'宋词/ci.song.20000.json','["律应黄锺，蓂飞六荚，今朝是、嵩岳生申。", "似山堂里，氤氲瑞气先春。", "笙歌度曲，依然在、紫府黄庭。", "拥出癯仙冰玉洁，梅花个样精神。", "堪羡处，行藏信道，出处无心。", "莫把闲中日月，替了调元公案，袖手经纶。", "黄扉虚左，休顾平泉花石盟。", "好看来年八帙，渭川叟、故事重新。", "寿星与、三台齐色，政地拜生辰。"]'),
('song-ci-387','鹊桥仙','无名氏','宋','宋词','song-ci','鹊桥仙','[]','朱门列戟。',68,'宋词/ci.song.20000.json','["朱门列戟。", "华堂鼎食。", "那更康强八十。", "渭川遇主恰年同，怎得似、累朝良弼。", "冬殷仲律。", "六蓂飞日。", "一点星辉南极。", "祝公经济出调元，遍寰宇、同跻寿域。"]'),
('song-ci-388','瑞鹤仙','无名氏','宋','宋词','song-ci','瑞鹤仙','[]','正迎长时节。',131,'宋词/ci.song.20000.json','["正迎长时节。", "细数来、两旬已浃，两朝方越。", "画堂人笑悦。", "见瑞烟香袅，寿星明彻。", "丝丝华发。", "问瑶池会客，几见桃结。", "才经八十，春秋不记，绛人年月。", "奇绝。", "诗书教子，陶母等伦，曹家风烈。", "鼎来□德。", "儿孙尽、蓝袍客。", "便从今，一轴金花鸾锦，十藏琅函贝叶。", "愿常如、秋月圆时，长生真诀。"]'),
('song-ci-389','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','律按黄锺馀七日，左扉弧矢呈祥。',70,'宋词/ci.song.20000.json','["律按黄锺馀七日，左扉弧矢呈祥。", "好看一点上眉黄。", "台星还又照，相映寿星光。", "今岁生辰应迥别，趋朝已趣曹装。", "姓名稳稳造鸳行。", "来年三四月，衣锦早还乡。"]'),
('song-ci-390','菩萨蛮','无名氏','宋','宋词','song-ci','菩萨蛮','[]','蓂留四叶书云后。',66,'宋词/ci.song.20000.json','["蓂留四叶书云后。", "此日孙枝秀。", "爱他风味似吾人。", "却是笔头能篆、又能文。", "青青两鬓年方壮。", "儿女俱成长。", "要添富寿共荣华。", "教取一庭兰玉，共成家。"]'),
('song-ci-391','江神子・江城子','无名氏','宋','宋词','song-ci','江神子・江城子','[]','一阳来复气回新。',86,'宋词/ci.song.20000.json','["一阳来复气回新。", "对芳辰。", "庆生申。", "月满惟迟、三日又三旬。", "入仕致身知是早，年弱冠，正青春。", "文章笔下扫千军。", "擢铨衡。", "袭簪缨。", "荣捧宸恩，来镇此邦民。", "行历华途须煊赫，添寿酒，祝椿龄。"]'),
('song-ci-392','上阳春・蓦山溪','无名氏','宋','宋词','song-ci','上阳春・蓦山溪','[]','疏梅点白，漏泄先春信。',102,'宋词/ci.song.20000.json','["疏梅点白，漏泄先春信。", "律欲变黄锺，但两日、一阳月尽。", "龙头望族，挺挺振家声，窗下业，月中枝，雁塔书名姓。", "琴堂拟步，早发梅仙轫。", "台阁待风生，想咫尺、天颜已近。", "壮行未老，便作黑头公，还未定，祝千春，看子孙昌盛。"]'),
('song-ci-393','醉蓬莱','无名氏','宋','宋词','song-ci','醉蓬莱','[]','看梅腮妆腊，柳眼缄春，小寒交候。',119,'宋词/ci.song.20000.json','["看梅腮妆腊，柳眼缄春，小寒交候。", "蓂荚双开，庆生贤毓秀。", "早著蜚声，荣登鹗表，正是当年少。", "大器能藏，待当富贵，功名还就。", "暂试鸾栖，需期瓜约，未试经伦手。", "料想黄扉须有分，看玺书飞到。", "州县无劳，沙堤已筑，跃马长安道。", "岁岁今朝，斑斓品戏，举觞称寿。"]'),
('song-ci-394','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','数朵寒梅方破腊，良宵新月初生。',70,'宋词/ci.song.20000.json','["数朵寒梅方破腊，良宵新月初生。", "晓来闺阁庆生辰。", "天孙应降诞，德迈孟光贤。", "喜配伯鸾真得耦，乘龙产凤齐名。", "称觞岁岁祝长年。", "瑶池桃未熟，南极婺星明。"]'),
('song-ci-395','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','梅拆数枝，蓂舒四荚，二阳始觉来临。',117,'宋词/ci.song.20000.json','["梅拆数枝，蓂舒四荚，二阳始觉来临。", "五云呈瑞，渤海复生申。", "信道当年庆诞，人推天上石麒麟。", "果然是，名驰雁塔，弱冠绿袍新。", "鸾栖，虽小试，仕途发轫，现宰官身。", "信倚需一札，飞下天庭。", "自是调羹大手，环召也、快展经纶。", "称觞处，彩堂具庆，芳桂对萱椿。"]'),
('song-ci-396','壶中天・念奴娇','无名氏','宋','宋词','song-ci','壶中天・念奴娇','[]','嘉平时候，算尧阶蓂叶，才方开六。',120,'宋词/ci.song.20000.json','["嘉平时候，算尧阶蓂叶，才方开六。", "婺女当年曾降瑞，产作仙姿清淑。", "金玉满堂，儿孙满目，心事今都足，嘻嘻嗃嗃，一门和气可掬。", "何幸诞节称觞，湖山堂上，燕集皆亲族。", "犹子不能歌盛美，但借湖山为祝。", "福比湖深，寿齐山耸，岁岁颜如玉。", "好陪王母，共看几度桃熟。"]'),
('song-ci-397','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','称觞喜对二阳临。',20,'宋词/ci.song.20000.json','["称觞喜对二阳临。", "况当弦月上，一醉祝千春。"]'),
('song-ci-398','千秋岁','无名氏','宋','宋词','song-ci','千秋岁','[]','斗杓建丑。',19,'宋词/ci.song.20000.json','["斗杓建丑。", "蓂叶初开九。", "贤哲降，千龄偶。"]'),
('song-ci-399','满江红','无名氏','宋','宋词','song-ci','满江红','[]','十荚尧蓂开翠羽，一番潘貌蒸红颊。',16,'宋词/ci.song.20000.json','["十荚尧蓂开翠羽，一番潘貌蒸红颊。"]'),
('song-ci-400','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','欣遇月圆先两日，称觞对二阳来。',15,'宋词/ci.song.20000.json','["欣遇月圆先两日，称觞对二阳来。"]'),
('song-ci-401','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','今日雪飞六出，明夜月圆三五，梅腊正传芳。',31,'宋词/ci.song.20000.json','["今日雪飞六出，明夜月圆三五，梅腊正传芳。", "恰值生申节，共献椒觞。"]'),
('song-ci-402','壶中天・念奴娇','无名氏','宋','宋词','song-ci','壶中天・念奴娇','[]','霜月团圆天似水，还是神仙诞日。',15,'宋词/ci.song.20000.json','["霜月团圆天似水，还是神仙诞日。"]'),
('song-ci-403','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','腊月初开一荚蓂。',16,'宋词/ci.song.20000.json','["腊月初开一荚蓂。", "祥开崧岳庆生申。"]'),
('song-ci-404','满江红','无名氏','宋','宋词','song-ci','满江红','[]','雪压梅敧，写不就、岁寒清绝。',29,'宋词/ci.song.20000.json','["雪压梅敧，写不就、岁寒清绝。", "正阆苑、五分里过了，三分腊月。"]'),
('song-ci-405','乳燕飞・贺新郎','无名氏','宋','宋词','song-ci','乳燕飞・贺新郎','[]','问讯绂麟何日是，腊月生辰十九。',15,'宋词/ci.song.20000.json','["问讯绂麟何日是，腊月生辰十九。"]'),
('song-ci-406','瑞鹤仙','无名氏','宋','宋词','song-ci','瑞鹤仙','[]','户庭浮瑞气。',16,'宋词/ci.song.20000.json','["户庭浮瑞气。", "八日馀寒，新春来至。"]'),
('song-ci-407','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','瑞溢飞猿峤，秀毓凤凰山。',26,'宋词/ci.song.20000.json','["瑞溢飞猿峤，秀毓凤凰山。", "腊馀六日春到，人间世庆生贤。"]'),
('song-ci-408','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','应三元，先五日，庆生申。',12,'宋词/ci.song.20000.json','["应三元，先五日，庆生申。"]'),
('song-ci-409','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','年春里，归去凤凰池上，国号恰新颁。',29,'宋词/ci.song.20000.json','["年春里，归去凤凰池上，国号恰新颁。", "玉立诸郎秀，丹桂看齐樊。"]'),
('song-ci-410','小木兰花・木兰花','无名氏','宋','宋词','song-ci','小木兰花・木兰花','[]','日逢三九。',52,'宋词/ci.song.20000.json','["日逢三九。", "相对梅花倾寿酒。", "次第回春。", "甲子从头又一新。", "敬翻一曲。", "付与歌儿勤为祝。", "为问仙翁。", "今岁蟠桃几度红。"]'),
('song-ci-411','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','淮海知名，今日刘郎，胜如旧时。',139,'宋词/ci.song.20000.json','["淮海知名，今日刘郎，胜如旧时。", "记当年幕府，从容赞画，云从万骑，电掣千麾。", "威震新塘，气吞涟楚，涤扫妖氛但指期。", "论功处，载骖鸾鹤，衣锦赋荣归。", "九重诏已封泥。", "看稳上青云万丈梯。", "况平生慷慨，闻鸡起舞，中原事业，不付公谁。", "昨夜颁春。", "明朝献岁，且对椒盘奉寿卮。", "功名事，不输前辈，行到凤凰池。"]'),
('song-ci-412','千秋岁','无名氏','宋','宋词','song-ci','千秋岁','[]','欢盈万屋。',87,'宋词/ci.song.20000.json','["欢盈万屋。", "声杂当庭竹。", "腾宝篆，辉银烛。", "东君将到处，祗隔邮亭宿。", "谁知道，此时诞个人如玉。", "红叶题宫墨。", "流入人间曲。", "天香在，犹芬馥。", "满斟眉寿醑，共劝千龄福。", "情未足，来朝更把酴酥祝。"]'),
('song-ci-413','贺新郎','无名氏','宋','宋词','song-ci','贺新郎','[]','父老持杯水。',139,'宋词/ci.song.20000.json','["父老持杯水。", "叹世间、公论无情，是非易位。", "来饯花封贤令尹，籍籍攀辕耳语。", "留不住、青原抚字。", "蓦地风波平地起，算十常、八九乖人意。", "无处著，不平气。", "浩然一曲歌归去。", "问城郭田园，曾荒尤未。", "亲旧过从同一笑，不羡浮云富贵。", "任造物、小儿厮戏。", "失马安知非是福，况庙庭、侑祀方思魏。", "天定也，诏书至。"]'),
('song-ci-414','蝶恋花','无名氏','宋','宋词','song-ci','蝶恋花','[]','名播乡闾人素许。',70,'宋词/ci.song.20000.json','["名播乡闾人素许。", "科诏相催，又趁槐花举。", "谈笑挥成金玉句。", "贤书果见登天府。", "阔步青霄今得路。", "脚底生云，拥入蟾宫去。", "好是来年三月暮。", "琼林宴处人争睹。"]'),
('song-ci-415','桂枝香','无名氏','宋','宋词','song-ci','桂枝香','[]','恩袍草色。',124,'宋词/ci.song.20000.json','["恩袍草色。", "望满目青青，光动阡陌。", "拂拂鞭丝散漫，锦鞯玉勒。", "君王赐与琼林宴，玩丹桂、香浮仙籍。", "舜韶清雅，尧觞泛溢，欢意何极。", "湛露久、需云未饰。", "更星使传呼，天上消息。", "槐幄阴移，上苑淡烟凝碧。", "归来渐近平康路，骤香尘、倒载连璧。", "马蹄轻驶，宫花半亸，艳欺斜日。"]'),
('song-ci-416','西江月','无名氏','宋','宋词','song-ci','西江月','[]','忆昔钱塘话别，十年社燕秋鸿。',58,'宋词/ci.song.20000.json','["忆昔钱塘话别，十年社燕秋鸿。", "今朝忽遇暮云东。", "对坐旗亭说梦。", "破帽手遮西日，练衣袖卷寒风。", "芦花江上两衰翁。", "消得几番相送。"]'),
('song-ci-417','少年游','无名氏','宋','宋词','song-ci','少年游','[]','新竿界断一天游。',59,'宋词/ci.song.20000.json','["新竿界断一天游。", "万弩向云头。", "彩羽飞星，红心破日，胜集总名流。", "好手业中施好，利物敢轻酬。", "捧杆箭多，旗花饯少，快请办头筹。"]'),
('song-ci-418','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','谁识飞竿巧艺全。',48,'宋词/ci.song.20000.json','["谁识飞竿巧艺全。", "儿童群戏艳阳天。", "十分险处却安然。", "海燕舞空萦弱絮，岭猿连臂下层颠。", "算来真个肉飞仙。"]'),
('song-ci-419','菩萨蛮','无名氏','宋','宋词','song-ci','菩萨蛮','[]','宝刀迎面摇寒雪。',52,'宋词/ci.song.20000.json','["宝刀迎面摇寒雪。", "琼梳掠鬓横新月。", "红颊驻长春。", "绿鬟轻绾云。", "解飘并括敛。", "到处题名遍。", "飞诏待追还。", "荣居供奉班。"]'),
('song-ci-420','满江红','无名氏','宋','宋词','song-ci','满江红','[]','旧日皆春，气象、又重妆束。',112,'宋词/ci.song.20000.json','["旧日皆春，气象、又重妆束。", "做得新丰酒肆，济康堂局。", "老杜误传人酝酿，许公手种时科目。", "自两公、一去已经年，君今续。", "商家醴，须君曲。", "怀英笼，须君蓄。", "且饶人大卖，呼么喝六。", "佶倬家人三两辈，药王菩萨丹青轴。", "更於中、添得个当炉，十分足。"]'),
('song-ci-421','失调名','无名氏','宋','宋词','song-ci','失调名','[]','燕子重来寻旧巢。',8,'宋词/ci.song.20000.json','["燕子重来寻旧巢。"]'),
('song-ci-422','贺新郎','无名氏','宋','宋词','song-ci','贺新郎','[]','苏子秋七月。',141,'宋词/ci.song.20000.json','["苏子秋七月。", "向凉宵、扁舟与客，共游赤壁。", "清吹徐来波不动，举酒诵诗属客。", "白露与、水光相接。", "万顷茫茫风浩浩，飘飘乎、遗世而独立。", "棹兰桨，沂空阔。", "正襟危坐而言曰。", "客知夫、天地之间，久长无物。", "惟有清风与明月，万古用之不竭。", "寓耳目、为声为色。", "客笑欣然重酌酒，忽盘肴既尽杯狼籍。", "□□□，东方白。"]'),
('song-ci-423','贺新郎','无名氏','宋','宋词','song-ci','贺新郎','[]','十月临皋暮。',136,'宋词/ci.song.20000.json','["十月临皋暮。", "客从予、黄泥之坂，凛然霜露。", "相与行歌而言曰，月白风清如许。", "念无酒、归谋诸妇。", "妇曰斗酒藏之已久，可携为、赤壁之游否。", "江水落，出洲渚。", "登龙踞虎幽宫俯。", "啸一声、山鸣谷应，寂寥四顾。", "有鹤东来西去也，梦道士、揖予而语。", "赤壁之游乐乎否，问其名、不答予惊悟。", "开户视，不知处。"]'),
('song-ci-424','满江红','无名氏','宋','宋词','song-ci','满江红','[]','不作三公，归来钓、桐庐江侧。',115,'宋词/ci.song.20000.json','["不作三公，归来钓、桐庐江侧。", "刘文叔、眼青不改，故人头白。", "风节傥能关社稷，云台何必图颜色。", "使阿瞒、临死尚称臣，伊谁力。", "登钓石，初相识。", "鱼竿老，羊裘窄。", "除江山风月，更谁消得。", "烟雨一川双桨急，转头不忿青山隔。", "叹鼻端、不省利名醒，京华客。"]'),
('song-ci-425','踏莎行','无名氏','宋','宋词','song-ci','踏莎行','[]','孤馆深沉，晓寒天气。',68,'宋词/ci.song.20000.json','["孤馆深沉，晓寒天气。", "解鞍独自阑干倚。", "暗香浮动月黄昏，落梅风送沾衣袂。", "待写红笺，凭谁与寄。", "先教觅取嬉游地。", "到家正是晚春时，小桃花下拼沉醉。"]'),
('song-ci-426','青玉案','无名氏','宋','宋词','song-ci','青玉案','[]','征鞍不见邯郸路。',78,'宋词/ci.song.20000.json','["征鞍不见邯郸路。", "莫便匆匆去，秋风萧条何以度。", "明窗小酌，暗灯清话，最好留连处。", "相逢各自伤迟暮，犹把新诗诵奇句。", "盐絮家风人所许。", "如今憔悴，但馀衰泪，一似黄梅雨。"]'),
('song-ci-427','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','法从西清，雅志山东，超然燕怡。',138,'宋词/ci.song.20000.json','["法从西清，雅志山东，超然燕怡。", "笑洛城卢老，贫来屋破，花溪杜叟，雨里床移。", "晚乃经营，欢言结架，夭矫晴虹朝已跻。", "开山了，一灯灯相续，第一宗师。", "乘闲小隐幽栖。", "天与人谋应此时。", "算春霆震响，不教龙蛰，甘霖布润，待倩云飞。", "宥密思贤，明谟经远，共指神州克复归。", "归来也，更身名煊赫，锦绣光辉。"]'),
('song-ci-428','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','蹑足半天下，作意赋归欤。',114,'宋词/ci.song.20000.json','["蹑足半天下，作意赋归欤。", "燕申经始不日，胸次出规模。", "千古神峰拥护，万古横江缭绕，佳致足方壶。", "一饮一词美，还得似君无。", "十步楼、五步阁，恣安居。", "薰蒸和气，袭人盎盎觉春如。", "况是庄椿不老，那更徐鸡并秀，父子看名俱。", "驷马高车盖，不减汉之于。"]'),
('song-ci-429','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','三径当松竹，五亩足烟霞。',114,'宋词/ci.song.20000.json','["三径当松竹，五亩足烟霞。", "个中卜宅，蓬山佳致足君家。", "前有书江环绕，后有横岗崪嵂，万象总森罗。", "输奂翬飞处，此屋岂无华。", "绿窗开，朱户敞，绣帘遮。", "燕闲自适，百篇斗酒是生涯。", "种善善根未绝，延桂桂枝可待，谁子为君夸。", "佳嗣一夔足，荣耀必多嘉。"]'),
('song-ci-430','金缕衣・贺新郎','无名氏','宋','宋词','song-ci','金缕衣・贺新郎','[]','帝遣司花女。',141,'宋词/ci.song.20000.json','["帝遣司花女。", "炯琼琚瑶佩，新来满空飞舞。", "飞到水晶宫阙处，还被六丁迎住。", "唤月娣、天孙说与。", "道是云溪新洞府，粲玉虹、拥出神仙宇。", "齐星汉，切云雾。", "朝来细把虹梁举。", "命日兄、催上金鸦，高高腾翥。", "云母卷帘三万数，不碍风斤月斧。", "真个是、去天尺五。", "恰则紫皇香案近，那砖花、院柳宜年少。", "双鬓绿，朝天去。"]'),
('song-ci-431','失调名','无名氏','宋','宋词','song-ci','失调名','[]','金猊香冷。',5,'宋词/ci.song.20000.json','["金猊香冷。"]'),
('song-ci-432','失调名','无名氏','宋','宋词','song-ci','失调名','[]','宝鸭香凝袖。',6,'宋词/ci.song.20000.json','["宝鸭香凝袖。"]'),
('song-ci-433','失调名','无名氏','宋','宋词','song-ci','失调名','[]','梅传春信。',5,'宋词/ci.song.20000.json','["梅传春信。"]'),
('song-ci-434','失调名','无名氏','宋','宋词','song-ci','失调名','[]','海棠著雨透胭脂。',8,'宋词/ci.song.20000.json','["海棠著雨透胭脂。"]'),
('song-ci-435','失调名','无名氏','宋','宋词','song-ci','失调名','[]','碧玉堂前金粟斗。',8,'宋词/ci.song.20000.json','["碧玉堂前金粟斗。"]'),
('song-ci-436','失调名','无名氏','宋','宋词','song-ci','失调名','[]','王孙去后多芳草。',8,'宋词/ci.song.20000.json','["王孙去后多芳草。"]'),
('song-ci-437','江城梅花引','无名氏','宋','宋词','song-ci','江城梅花引','["\u897f\u6e56"]','逋仙千载独知心。',108,'宋词/ci.song.20000.json','["逋仙千载独知心。", "别无人。", "泪痕深。", "长是自开自落自成阴。", "白石后来疏影句，饶绮丽，总输他、清浅吟。", "伤情。", "伤情。", "角中声。", "夜沉沉。", "更捣砧。", "欲雪未雪、天欲老，云气昏昏。", "梦绕西湖路渐不堪行。", "人已骑驴毡笠去，留恨也，仗梅花、说与君。"]'),
('song-ci-438','踏莎行','无名氏','宋','宋词','song-ci','踏莎行','[]','瘦影横斜，断桥路小。',69,'宋词/ci.song.20000.json','["瘦影横斜，断桥路小。", "如今梦断孤山了。", "冷魂趁鹤不归来，荒山没尽深深草。", "月下罗浮，一樽自笑。", "旧枝尚记幽禽抱。", "王令人梦里说相思，被谁惊破霜天晓。"]'),
('song-ci-439','满江红','无名氏','宋','宋词','song-ci','满江红','[]','雪后郊原，烟林静、梅花初拆。',114,'宋词/ci.song.20000.json','["雪后郊原，烟林静、梅花初拆。", "春初半、犹自探春消息。", "一眼平芜看不尽，夜来小雨催新碧。", "笑去年、携酒折花时，君应识。", "兰舟漾，城南陌。", "云影淡，天容窄。", "绕风漪十顷，遥浮晴色。", "恰似槎头收钓处，坐中仍有江南客。", "试与问、何如两桨下苕溪，吞梦泽。"]'),
('song-ci-440','失调名','无名氏','宋','宋词','song-ci','失调名','[]','月宫仙桂、被嫦娥试手，移来山谷。',16,'宋词/ci.song.20000.json','["月宫仙桂、被嫦娥试手，移来山谷。"]'),
('song-ci-441','献仙桃','无名氏','宋','宋词','song-ci','献仙桃','[]','元宵嘉会赏春光。',64,'宋词/ci.song.20000.json','["元宵嘉会赏春光。", "盛事当年忆上阳。", "尧颡喜瞻天北极，舜衣深拱殿中央。", "欢声浩荡连韶曲，和气氤氲带御香。", "壮观大平何以报，蟠桃一朵献千祥。"]'),
('song-ci-442','献天寿慢・献天寿','无名氏','宋','宋词','song-ci','献天寿慢・献天寿','[]','日暖风和春更迟。',56,'宋词/ci.song.20000.json','["日暖风和春更迟。", "是太平时。", "我从蓬岛整容姿。", "来降贺丹墀。", "幸逢灯夕真佳会，喜近天威。", "神仙寿算远无期。", "献君寿、万千斯。"]'),
('song-ci-443','献天寿令','无名氏','宋','宋词','song-ci','献天寿令','[]','阆苑人间虽隔，遥闻圣德弥高。',61,'宋词/ci.song.20000.json','["阆苑人间虽隔，遥闻圣德弥高。", "西离仙镜下云霄。", "来献千岁灵桃。", "上祝皇龄齐天久，犹舞蹈、贺贺圣朝。", "梯航交凑四方遥。", "端拱永保宗祧。"]'),
('song-ci-444','金盏子慢・金盏子','无名氏','宋','宋词','song-ci','金盏子慢・金盏子','[]','丽日舒长，正葱葱瑞气，遍满神京。',125,'宋词/ci.song.20000.json','["丽日舒长，正葱葱瑞气，遍满神京。", "九重天上，五云开处，丹楼碧阁峥嵘。", "盛宴初开，锦帐绣幕交横。", "应上元佳节，君臣际会，共乐升平。", "广庭。", "罗绮纷盈。", "动一部、笙歌尽新声。", "蓬莱宫殿神仙景。", "浩荡春光，逦迤王城。", "烟收雨歇，天色夜更澄清。", "又千寻火树，灯山参差，带月鲜明。"]'),
('song-ci-445','金盏子令','无名氏','宋','宋词','song-ci','金盏子令','[]','东风报暖，到头嘉气渐融怡。',58,'宋词/ci.song.20000.json','["东风报暖，到头嘉气渐融怡。", "巍峨凤阙，起鳌山万仞，争耸云涯。", "梨园弟子，齐奏新曲，半是埙篪。", "见满筵、簪绅醉饱，颂鹿鸣诗。"]'),
('song-ci-446','瑞鹧鸪慢・瑞鹧鸪','无名氏','宋','宋词','song-ci','瑞鹧鸪慢・瑞鹧鸪','[]','海东今日太平天。',64,'宋词/ci.song.20000.json','["海东今日太平天。", "喜望龙云庆会筵。", "尾扇初开明黼座，画帘高卷罩祥烟。", "梯航交凑端门外，玉帛森罗殿陛前。", "妾献皇龄千万岁，封人何更祝遐年。"]'),
('song-ci-447','瑞鹧鸪慢・瑞鹧鸪','无名氏','宋','宋词','song-ci','瑞鹧鸪慢・瑞鹧鸪','[]','北暴东顽，纳款慕义争来。',56,'宋词/ci.song.20000.json','["北暴东顽，纳款慕义争来。", "日新君德更明哉。", "歌咏载衢街。", "清宁海宇无馀事，乐与民同燕春台。", "一年一度上元回。", "愿醉万年杯。"]'),
('song-ci-448','寿延长中腔令・寿延长','无名氏','宋','宋词','song-ci','寿延长中腔令・寿延长','[]','彤云映彩色相映，御座中、天簇簪缨。',65,'宋词/ci.song.20000.json','["彤云映彩色相映，御座中、天簇簪缨。", "万花铺锦满高庭。", "庆敞需宴欢声。", "千龄启统乐功成。", "同意贺、元珪丰擎。", "宝觞频举侠群英。", "万万载、乐升平。"]'),
('song-ci-449','寿延长破字令','无名氏','宋','宋词','song-ci','寿延长破字令','[]','青春玉殿和风细。',63,'宋词/ci.song.20000.json','["青春玉殿和风细。", "奏箫韶络绎。", "瑞绕行云飘飘曳。", "泛金尊、流霞艳溢。", "瑞日晖晖临丹扆。", "广布慈德宸遐迩。", "愿听歌声舞缀。", "万万年、仰瞻宴启。"]'),
('song-ci-450','步虚子令','无名氏','宋','宋词','song-ci','步虚子令','[]','碧烟笼晓海波闲。',70,'宋词/ci.song.20000.json','["碧烟笼晓海波闲。", "江上数峰寒。", "佩环声里，异香飘落人间。", "弭绛节、五云端。", "宛然共指嘉禾瑞，开一笑、破朱颜。", "九重嶢阙，望中三祝高天。", "万万载、对南山。"]'),
('song-ci-451','破字令','无名氏','宋','宋词','song-ci','破字令','[]','缥缈三山岛。',61,'宋词/ci.song.20000.json','["缥缈三山岛。", "十万岁、方分昏晓。", "春风开遍碧桃花，为东君一笑。", "祥飙暂引香尘到。", "祝高龄、后天难老。", "瑞烟散碧，归云弄暖，一声长啸。"]'),
('song-ci-452','抛球乐折花令・抛球乐','无名氏','宋','宋词','song-ci','抛球乐折花令・抛球乐','[]','翠幕华筵，相将正是多欢宴。',67,'宋词/ci.song.20000.json','["翠幕华筵，相将正是多欢宴。", "举舞袖、回旋遍。", "罗绮簇宫商，共歌清羡。", "当琼浆泛泛满金尊，莫惜沉醉，莫惜沉醉，永日长游衍。", "愿乐嘉宾，嘉宾式燕。"]'),
('song-ci-453','抛球乐水龙吟令・抛球乐','无名氏','宋','宋词','song-ci','抛球乐水龙吟令・抛球乐','[]','洞天景色常春，嫩红浅白开轻萼。',124,'宋词/ci.song.20000.json','["洞天景色常春，嫩红浅白开轻萼。", "琼筵镇起，金炉烟重，香凝锦幄。", "窈窕神仙，妙呈歌舞，攀花相约。", "彩云月转，朱丝网徐在，语笑抛球乐。", "绣袂风翻凤举，转星眸、柳腰柔弱。", "头筹得胜，欢声近地，光容约。", "满座佳宾，喜听仙乐，交传觥爵。", "龙吟欲罢，彩云摇曳，相将归去寥廓。"]'),
('song-ci-454','抛球乐小抛球乐・抛球乐','无名氏','宋','宋词','song-ci','抛球乐小抛球乐・抛球乐','[]','两行花窍占风流。',32,'宋词/ci.song.20000.json','["两行花窍占风流。", "缕金罗带系抛球。", "玉纤高指红丝网，大家著意胜头筹。"]'),
('song-ci-455','失调名','无名氏','宋','宋词','song-ci','失调名','[]','满庭箫鼓簇飞球。',16,'宋词/ci.song.20000.json','["满庭箫鼓簇飞球。", "丝竿红网总台头。"]'),
('song-ci-456','失调名','无名氏','宋','宋词','song-ci','失调名','[]','频歌覆手抛将过，两行人待看回筹。',16,'宋词/ci.song.20000.json','["频歌覆手抛将过，两行人待看回筹。"]'),
('song-ci-457','失调名','无名氏','宋','宋词','song-ci','失调名','[]','五花心里看抛球。',16,'宋词/ci.song.20000.json','["五花心里看抛球。", "香腮红嫩柳烟稠。"]'),
('song-ci-458','失调名','无名氏','宋','宋词','song-ci','失调名','[]','清歌叠鼓连催促，这里不让第三头。',16,'宋词/ci.song.20000.json','["清歌叠鼓连催促，这里不让第三头。"]'),
('song-ci-459','失调名','无名氏','宋','宋词','song-ci','失调名','[]','箫鼓声声且莫催。',16,'宋词/ci.song.20000.json','["箫鼓声声且莫催。", "彩球高下意难裁。"]'),
('song-ci-460','失调名','无名氏','宋','宋词','song-ci','失调名','[]','恐将脂粉均妆面，羞被狂毫抹污来。',16,'宋词/ci.song.20000.json','["恐将脂粉均妆面，羞被狂毫抹污来。"]'),
('song-ci-461','清平令破子・清平乐','无名氏','宋','宋词','song-ci','清平令破子・清平乐','[]','满庭罗绮流粲。',62,'宋词/ci.song.20000.json','["满庭罗绮流粲。", "清朝画楼开宴。", "似初发芙蓉正烂熳。", "金尊莫惜频劝。", "近看柳腰似折。", "更看舞回流雪。", "是欢乐、宴游时节。", "且莫催、欢歌声阕。"]'),
('song-ci-462','惜奴娇','无名氏','宋','宋词','song-ci','惜奴娇','[]','春早皇都冰泮。',60,'宋词/ci.song.20000.json','["春早皇都冰泮。", "宫沼东风布轻暖。", "梅粉飘香，柳带弄色，瑞霭祥烟凝浅。", "正值元宵，行乐同民总无闲。", "肆情怀，何惜相邀，是处里容款。"]'),
('song-ci-463','惜奴娇','无名氏','宋','宋词','song-ci','惜奴娇','[]','无算。',64,'宋词/ci.song.20000.json','["无算。", "仗委东君遍。", "有风光、占五陵闲散。", "从把千金，五夜继赏，并彻春宵游玩。", "借问花灯，金琐琼瑰果曾罕。", "洞天里，一掠蓬瀛，第恐今宵短。"]'),
('song-ci-464','惜奴娇','无名氏','宋','宋词','song-ci','惜奴娇','[]','夸帝里。',90,'宋词/ci.song.20000.json','["夸帝里。", "万灵咸集，永卫紫陌青楼，富臻既庶矣。", "四海升平，文武功勋盖世。", "赖圣主，兴贤佐，恁致理。", "气绪凝和，会景新、访雅致。", "列群公锡宴在迩。", "上元循典，胜古高超荣异。", "望绛霄、龙香飘飘旖旎。"]'),
('song-ci-465','惜奴娇','无名氏','宋','宋词','song-ci','惜奴娇','[]','景云披靡。',49,'宋词/ci.song.20000.json','["景云披靡。", "露浥轻寒若水。", "尽是游人美。", "陌尘润、宝沉递。", "笑指扬鞭，多少高门胜会。", "况是。", "只有今夕誓无寐。"]'),
('song-ci-466','惜奴娇','无名氏','宋','宋词','song-ci','惜奴娇','[]','盛日凝理。',48,'宋词/ci.song.20000.json','["盛日凝理。", "羽巢可窥。", "阆苑金关启扉。", "烬连宵、宁防避。", "暗尘随马，明月逐人无际。", "调戏。", "相歌秾李末阑已。"]'),
('song-ci-467','惜奴娇','无名氏','宋','宋词','song-ci','惜奴娇','[]','骋轮纵勒，翠羽花钿比织。',51,'宋词/ci.song.20000.json','["骋轮纵勒，翠羽花钿比织。", "并雅同陪，共越九衢遍，尽遨逸。", "料峭云容，香惹风、萦怀袂。", "遍寓目，几处瑶席绣帟。"]'),
('song-ci-468','惜奴娇','无名氏','宋','宋词','song-ci','惜奴娇','[]','莫如胜慨，景压天街际。',44,'宋词/ci.song.20000.json','["莫如胜慨，景压天街际。", "彩鳌举、百仞耸倚。", "凤舞龙骧，满目红光宝翠。", "动霁色，馀霞映，散成绮。"]'),
('song-ci-469','惜奴娇','无名氏','宋','宋词','song-ci','惜奴娇','[]','渐灼兰膏，覆满青烟罩地。',45,'宋词/ci.song.20000.json','["渐灼兰膏，覆满青烟罩地。", "簇宫花、撋荡纷委。", "万姓瞻仰，苒苒云龙香细。", "共稽首，同乐与，众方纪。"]'),
('song-ci-470','惜奴娇','无名氏','宋','宋词','song-ci','惜奴娇','[]','楼起霄宫里。',102,'宋词/ci.song.20000.json','["楼起霄宫里。", "五福中天纷绛瑞。", "弦管齐谐，清宛振逸天外。", "万舞低回纷绕，罗纨摇曳。", "顷刻转轮归去，念感激天意。", "幸列熙台，洞天遥遥望圣梓。", "五夕华胥，鱼钥并开十二。", "圣景难逢无比。", "人间动且经岁。", "娩婉踌躇，再拜五云迤逦。"]'),
('song-ci-471','万年欢慢・万年欢','无名氏','宋','宋词','song-ci','万年欢慢・万年欢','[]','禁篽初晴，见万年枝上，工啭莺声。',122,'宋词/ci.song.20000.json','["禁篽初晴，见万年枝上，工啭莺声。", "藻殿连云，萍曦高照檐楹。", "好是帘开丽景，袅金炉、香暖烟轻。", "传呼道、天跸来临，两行拱引簪缨。", "看看筵敞三清。", "洞宝玉杯中，满酌犀觥。", "烂熳芳葩，斜簪庆快春情。", "更有箫韶九奏，簇鱼龙、百戏俱呈。", "吾皇愿、永保洪图，四方长乐升平。"]'),
('song-ci-472','万年欢慢・万年欢','无名氏','宋','宋词','song-ci','万年欢慢・万年欢','[]','当今圣主，理化感四塞，永减狼烟。',60,'宋词/ci.song.20000.json','["当今圣主，理化感四塞，永减狼烟。", "太平朝野无征战，国内晏然。", "风调雨顺歌声喧。", "箫韶韵，九奏钧天。", "愿王永寿，比南山、更奏延年。"]'),
('song-ci-473','万年欢慢・万年欢','无名氏','宋','宋词','song-ci','万年欢慢・万年欢','[]','婥妁要肢轻婀娜。',129,'宋词/ci.song.20000.json','["婥妁要肢轻婀娜。", "学内样、深深梳果。", "如五凤双鸾相对舞，随腰带、乍游琐。", "莺幕、满头花，见绿杨摸蔌。", "金阶献，一庭细管繁弦里，谁把ㄉ抛过。", "舞鸾双翥，香兽低。", "散瑞景烟微。", "投袂翩翩，趁拍迟迟。", "按曲度瑶池。", "曲遍新声，敛绣衣跪。", "彩袖高捧琼卮。", "指月中丹桂。", "春难老，祝仙寿维祺。"]'),
('song-ci-474','忆吹箫慢・凤凰台上忆吹箫','无名氏','宋','宋词','song-ci','忆吹箫慢・凤凰台上忆吹箫','[]','血洒霜罗，泪薄艳锦，伊方教我成行。',119,'宋词/ci.song.20000.json','["血洒霜罗，泪薄艳锦，伊方教我成行。", "渐望断、斜桥暮柳，曲水归云。", "月暗风高露冷，独自才抵孤城。", "江南远，今夜就中，愁损行人。", "愁人。", "旧香遗粉，空淡淡馀暖，隐隐残痕。", "到这里、思量是我，忒□无情。", "水更无情侣我，催画航、一日三程。", "休烦恼，相见定约新春。"]'),
('song-ci-475','月华清慢・月华清','无名氏','宋','宋词','song-ci','月华清慢・月华清','[]','雨洗天开，风将云去，极目都无纤翳。',123,'宋词/ci.song.20000.json','["雨洗天开，风将云去，极目都无纤翳。", "当遇中秋夜，静月华如水。", "素光晃、金屋楼台，清气彻、玉壶天地。", "此际。", "比无常三五，婵娟特异。", "因念玉人千里。", "待尽把愁肠，分付沉醉。", "只恐难当漏尽，又还经岁。", "最堪恨、独守书帏，空对景、不成欢意。", "除是。", "问姮娥觅取，一枝仙桂。"]'),
('song-ci-476','感皇恩令・感皇恩','无名氏','宋','宋词','song-ci','感皇恩令・感皇恩','[]','和袖把金鞭，腰如束素。',81,'宋词/ci.song.20000.json','["和袖把金鞭，腰如束素。", "骑介驴儿过门去。", "禁街人静，一阵香风满路。", "凤鞋宫样小，弯弯露。", "蓦地被他，回眸一顾。", "便是令人断肠处。", "愿随鞭镫，又被名缰勒住。", "恨身不做个，闲男女。"]'),
('song-ci-477','醉太平','无名氏','宋','宋词','song-ci','醉太平','[]','厌厌闷着。',54,'宋词/ci.song.20000.json','["厌厌闷着。", "厌厌闷着。", "奴儿近日听人咬，把初心忘却。", "教人病深谩摧拙。", "凭谁与我分说破，仔细思量怎奈何，见了伏些弱。"]'),
('song-ci-478','还宫乐','无名氏','宋','宋词','song-ci','还宫乐','[]','喜贺我皇，有感蓬莱，尽降神仙。',62,'宋词/ci.song.20000.json','["喜贺我皇，有感蓬莱，尽降神仙。", "到乘鸾驾鹤御楼前。", "来献长寿仙丹。", "玉殿阶前排筵会，今宵秋日到神仙。", "笙歌寥亮呈玉庭，为报圣寿万年。"]'),
('song-ci-479','清平乐','无名氏','宋','宋词','song-ci','清平乐','[]','真主玉历成康。',68,'宋词/ci.song.20000.json','["真主玉历成康。", "德睿宁安国中良。", "时和岁丰稔，民阜乐、何情泚，瑞木呈日五色，月华重有光。", "更羽鹤来仪凤凰。", "万邦乡。", "齐供明皇。", "祝遐龄、圣寿无疆。"]'),
('song-ci-480','荔子丹','无名氏','宋','宋词','song-ci','荔子丹','[]','斗巧宫妆扫翠眉。',63,'宋词/ci.song.20000.json','["斗巧宫妆扫翠眉。", "相唤折花枝。", "晓来深入艳芳里，红香散，露浥在罗衣。", "盈盈巧笑咏新词。", "舞态画娇姿。", "袅娜文回迎宴处，簇神仙、会赴瑶池。"]'),
('song-ci-481','水龙吟慢・水龙吟','无名氏','宋','宋词','song-ci','水龙吟慢・水龙吟','[]','玉皇金阙长春，民仰高天欣载。',120,'宋词/ci.song.20000.json','["玉皇金阙长春，民仰高天欣载。", "年年一度定佳期，风情多感慨。", "绮罗竞交会。", "争折花枝两相对。", "舞袖翩翩歌声妙，掩粉面、斜窥翠黛。", "锦额门开彩架，球儿裳、先秀神仙队。", "融香拂席霓裳动，铿锵环珮。", "宝座巍巍五云密，欢呼争拜退。", "管弦众作欲归去，愿吾皇、万年恩爱。"]'),
('song-ci-482','太平年慢・太平年','无名氏','宋','宋词','song-ci','太平年慢・太平年','[]','皇州春满群芳丽。',53,'宋词/ci.song.20000.json','["皇州春满群芳丽。", "散异香旖旎。", "鳌宫开宴赏佳致。", "举笙歌鼎沸。", "永日迟迟和风媚。", "柳色烟凝翠。", "唯恐日西坠。", "且乐欢醉。"]'),
('song-ci-483','金殿乐慢','无名氏','宋','宋词','song-ci','金殿乐慢','[]','驾紫鸾軿。',59,'宋词/ci.song.20000.json','["驾紫鸾軿。", "乘风缥缈游仙。", "红霓蘸影，近瑶池、鹤戏芝田。", "临蕙圃、饮琼泉。", "上萧台、遥瞻九天。", "对真人蕊书亲授，已向南宫住长年。"]'),
('song-ci-484','安平乐・安平乐慢','无名氏','宋','宋词','song-ci','安平乐・安平乐慢','[]','开琼筵，庆佳辰。',71,'宋词/ci.song.20000.json','["开琼筵，庆佳辰。", "彩帟当中月华明。", "笙歌乐、如梦幻，望丹山彩凤，飞舞邃庭。", "遐艳异、寿杯同斟。", "抃舞讴歌浃欢声。", "方今永永太平。", "更衍多男，共集锦昌寿恩。"]'),
('song-ci-485','爱月夜眠迟慢','无名氏','宋','宋词','song-ci','爱月夜眠迟慢','[]','禁鼓初敲，觉六街夜悄，车马人稀。',126,'宋词/ci.song.20000.json','["禁鼓初敲，觉六街夜悄，车马人稀。", "暮天澄淡，云收雾卷，亭亭皎月如珪。", "冰轮碾出遥空，无私照临千里。", "最堪怜、有情风，送得丹桂香微。", "唯愿素魄长圆，把流霞对饮，满泛觥卮。", "醉凭栏处、赏玩不忍，辜却好景良时。", "清歌妙舞连宵，踟蹰懒入罗帏。", "任佳人、尽嗔我，爱月每夜眠迟。"]'),
('song-ci-486','惜花春起早慢','无名氏','宋','宋词','song-ci','惜花春起早慢','[]','向春来，睹林园，绣出满槛鲜萼。',123,'宋词/ci.song.20000.json','["向春来，睹林园，绣出满槛鲜萼。", "流莺海棠枝上弄舌，紫燕飞绕池阁。", "三眠细柳，垂万条、罗带柔弱。", "为思量，昨夜去看花，犹自斑驳。", "须拌尽日樽前，当媚景良辰，且恁欢谑。", "更阑夜深秉烛，对花酌、莫辜轻喏。", "邻鸡唱晓，惊觉来、连忙梳掠。", "向西园、惜群葩，恐怕狂风吹落。"]'),
('song-ci-487','千秋岁令・千秋岁引','无名氏','宋','宋词','song-ci','千秋岁令・千秋岁引','[]','想风流态，种种般般媚。',102,'宋词/ci.song.20000.json','["想风流态，种种般般媚。", "恨别离时大容易。", "香笺欲写相思意。", "相思泪滴香笺字。", "画堂深，银烛暗，重门闭。", "似当日、欢娱何日遂。", "愿早早相逢重设誓。", "美景良辰莫轻拌，鸳鸯帐里鸳鸯被。", "鸳鸯枕上鸳鸯睡。", "似恁地，长恁地，千秋岁。"]'),
('song-ci-488','风中柳令・谢池春','无名氏','宋','宋词','song-ci','风中柳令・谢池春','[]','爱鬓云长，惜眉山，寻乍相见，一时眠起。',81,'宋词/ci.song.20000.json','["爱鬓云长，惜眉山，寻乍相见，一时眠起。", "为伊尚验，未欲将言相戏。", "早樽前、会人深意。", "霎时间阻，眼儿早巴巴地。", "便也解、封题相寄。", "怎生是款曲，终成连理。", "管胜如、旧来识底。"]'),
('song-ci-489','汉宫春慢・汉宫春','无名氏','宋','宋词','song-ci','汉宫春慢・汉宫春','[]','春日迟迟。',118,'宋词/ci.song.20000.json','["春日迟迟。", "称游人、尽日赏燕芳菲。", "新荷泛水，渐入夏景云奇。", "炎光易息，又早是、零落风西。", "白露点，黄金菊蕊，朝云暮雪霏霏。", "光阴迅速如飞。", "邀酒朋共欢，且恁开眉。", "清歌妙舞，更兼玉管瑶篪。", "人生易老，遇太平、且乐嬉嬉。", "莫待解，朱颜顿觉，年来不似当时。"]'),
('song-ci-490','花心动慢・花心动','无名氏','宋','宋词','song-ci','花心动慢・花心动','[]','暑逼芳襟，甚全无因依，便教人恶。',127,'宋词/ci.song.20000.json','["暑逼芳襟，甚全无因依，便教人恶。", "赖有枕溪百尺，朱楼映日，数重香箔。", "驮冰围定犹嫌暖，红日绽、雨收残脚。", "漫试取，红绡弄雪，碎琼推削。", "妆罢低云未稤。", "叶叶地仙衣，剪轻裁薄。", "汗洒泪珠，急捧金盘，向前颗颗盛却。", "凤凰双扇相交扇，越撋就、越腰肢弱。", "待做个、青纱罩儿罩著。"]'),
('song-ci-491','行香子慢','无名氏','宋','宋词','song-ci','行香子慢','[]','瑞景光融。',119,'宋词/ci.song.20000.json','["瑞景光融。", "换中天霁烟、佳气葱葱。", "皇居崇壮丽，金碧辉空。", "彤霄外、瑶殿深处，帘卷花影重重。", "迎步辇、几簇真仙，贺庆寿新宫。", "方逢。", "圣主飞龙。", "正休盛大宁，朝野欢同。", "何妨宴赏，奉宸意慈容。", "韶音按、露觞将进，蕙炉飘馥香浓。", "长愿承颜，千秋万岁，明月清风。"]'),
('song-ci-492','雨中花慢','无名氏','宋','宋词','song-ci','雨中花慢','[]','宴阙倚栏郊外，乍别芳姿，醉登长陌。',118,'宋词/ci.song.20000.json','["宴阙倚栏郊外，乍别芳姿，醉登长陌。", "渐觉联绵离绪，淡薄秋色。", "宝马频嘶，寒蝉晚、正伤行客。", "念少年踪迹。", "风流声价，泪珠偷滴。", "从前与、酒朋花侣，镇赏画楼瑶席。", "今夜里、清风明月，水村山驿。", "往事悠悠似梦，新愁苒苒如织。", "断肠望极。", "重逢何处，暮云凝碧。"]'),
('song-ci-493','迎春乐令・迎春乐','无名氏','宋','宋词','song-ci','迎春乐令・迎春乐','[]','神州丽景春先到。',63,'宋词/ci.song.20000.json','["神州丽景春先到。", "看看是、韶光早。", "园林深处东风过，红杏里、莺声好。", "漠漠青烟远远道。", "触目是、绿杨芳草。", "莫惜醉重游，逡巡又、年华老。"]'),
('song-ci-494','西江月慢','无名氏','宋','宋词','song-ci','西江月慢','[]','烟笼细柳，映粉墙、垂丝轻袅。',133,'宋词/ci.song.20000.json','["烟笼细柳，映粉墙、垂丝轻袅。", "正岁稍暖律风和，装点后苑台沼。", "见乍开、桃若燕脂染，便须信、江南春早。", "又数枝、零乱残花，飘满地、未曾扫。", "幸到此、芳菲时渐好。", "恨间阻、佳期尚杳。", "听几声、云里悲鸿，动感怨愁多少。", "谩送目、层阁天涯远，甚无人、音书来到。", "又只恐、别有深情，盟言忘了。"]'),
('song-ci-495','游月宫令','无名氏','宋','宋词','song-ci','游月宫令','[]','当今圣主座龙楼，圣寿应天长，实钱喷香烟，玄宗游月宫。',58,'宋词/ci.song.20000.json','["当今圣主座龙楼，圣寿应天长，实钱喷香烟，玄宗游月宫。", "海晏河清，盛朝侍，群臣喜呼万岁，万人民，开乐业，愿吾皇、增福寿。"]'),
('song-ci-496','桂枝香慢・桂枝香','无名氏','宋','宋词','song-ci','桂枝香慢・桂枝香','[]','暖风迟日，正韶阳时节，淑景明媚。',124,'宋词/ci.song.20000.json','["暖风迟日，正韶阳时节，淑景明媚。", "一霎雨打红桃，花落满地。", "□闺独坐帘高卷，困春容、懒临香砌。", "自从檀郎，金门献赋，不绝朱翠。", "闻上国、才有书回，应贤良明庭，已擢高第。", "拆破香笺，离恨却成新喜。", "早教宴罢琼林苑，愿归来、永同连理。", "这回良夜，从他桂枝，香惹鸳被。"]'),
('song-ci-497','庆金枝令・庆金枝','无名氏','宋','宋词','song-ci','庆金枝令・庆金枝','[]','莫惜金缕衣。',58,'宋词/ci.song.20000.json','["莫惜金缕衣。", "劝君惜、少年时。", "花开堪折直须折，莫待折空枝。", "一朝杜宇才鸣后，便从此、歇芳菲。", "有花有酒且开眉。", "莫待满头丝。"]'),
('song-ci-498','百宝妆・新雁过妆楼','无名氏','宋','宋词','song-ci','百宝妆・新雁过妆楼','[]','一抹弦器，初宴画堂，琵琶人把当头。',132,'宋词/ci.song.20000.json','["一抹弦器，初宴画堂，琵琶人把当头。", "髻云腰素，仍占绝风流。", "轻拢慢拈，生情艳态，翠眉黛颦，无愁谩似愁。", "变新声曲，自成获索，共听一奏梁州。", "弹到遍急敲颖，分明似语，争知指面纤柔。", "坐中无语，惟断续金虬。", "曲终暗会王孙意，转步莲、徐徐卸凤钩。", "捧瑶觞，为喜知音，劝佳人、沉醉迟留。"]'),
('song-ci-499','满朝欢令','无名氏','宋','宋词','song-ci','满朝欢令','[]','未央宫阙丹霞住。',64,'宋词/ci.song.20000.json','["未央宫阙丹霞住。", "十二玉楼挥锦绣。", "云开雉扇卷珠帘，烟粉龙香添瑞兽。", "瑶觞一举箫韶奏。", "环佩千官齐拜首。", "南山翠应北华高，共献君王千万岁。"]'),
('song-ci-500','天下乐令・减字木兰花','无名氏','宋','宋词','song-ci','天下乐令・减字木兰花','[]','寿星明久。',54,'宋词/ci.song.20000.json','["寿星明久。", "寿曲高歌沉醉后。", "寿烛荧煌。", "手把金炉，燃一寿香。", "满斟寿酒。", "我意殷勤来祝寿。", "问寿如何。", "寿比南山福更多。"]'),
('song-ci-501','感恩多令・山花子','无名氏','宋','宋词','song-ci','感恩多令・山花子','[]','罗帐半垂门半开。',56,'宋词/ci.song.20000.json','["罗帐半垂门半开。", "残灯孤月照窗台。", "北斗渐移天欲曙、漏更催。", "携手劝君离别酒，泪和红粉滴金杯。", "呜咽问君今夜去、几时回。"]'),
('song-ci-502','解佩令','无名氏','宋','宋词','song-ci','解佩令','[]','脸儿端正。',84,'宋词/ci.song.20000.json','["脸儿端正。", "心儿峭俊。", "眉儿长、眼儿入鬓。", "鼻儿隆隆，口儿小、舌儿香软。", "耳垛儿、就中红润。", "项如琼玉，发如云鬓。", "眉如削、手如春笋。", "奶儿甘甜，腰儿细、脚儿去紧。", "那些儿、更休要问。"]'),
('song-ci-503','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','道过江南，泥墙粉壁，石具在前。',137,'宋词/ci.song.20000.json','["道过江南，泥墙粉壁，石具在前。", "述某州某县，某乡某里，住何人地，佃何人田。", "气象萧条，生灵憔悴，经略从来未必然。", "惟何甚，为官为已，不把人怜。", "思量几许山川。", "况土地分张又百年。", "正西蜀巉岩，云迷鸟道，两淮清野，日警狼烟。", "宰相弄权，奸人罔上，谁念干戈未息肩。", "掌大地，何须经理，万取千焉。"]'),
('song-ci-504','糖多令・唐多令','无名氏','宋','宋词','song-ci','糖多令・唐多令','[]','天上谪星班。',65,'宋词/ci.song.20000.json','["天上谪星班。", "青牛初度关。", "幻出蓬莱新院宇，花外竹，竹边山。", "轩冕傥来闲。", "人生闲最难。", "算真闲、不到人间。", "一半神仙先占取，留一半、与公闲。"]'),
('song-ci-505','长相思','无名氏','宋','宋词','song-ci','长相思','["\u897f\u6e56"]','去年秋。',44,'宋词/ci.song.20000.json','["去年秋。", "今年秋。", "湖上人家乐复忧。", "西湖依旧流。", "吴循州。", "贾循州。", "十五年前一转头。", "人生放下休。"]'),
('song-ci-506','祝英台近','无名氏','宋','宋词','song-ci','祝英台近','[]','掩琵琶，临别语，把酒泪如洗。',94,'宋词/ci.song.20000.json','["掩琵琶，临别语，把酒泪如洗。", "似恁春时，仓卒去何意。", "牡丹恰则开园，荼䕷厮句，便下得、一帆千里。", "好无谓。", "复道明日行呵，如何恋得你。", "一叶船儿，休要更沉醉。", "后梅子青时，杨花飞絮，侧耳听，喜鹊□哩。"]'),
('song-ci-507','汉宫春','无名氏','宋','宋词','song-ci','汉宫春','[]','横吹声沉，倚危楼红日，江转天斜。',118,'宋词/ci.song.20000.json','["横吹声沉，倚危楼红日，江转天斜。", "黄尘边火澒洞，何处吾家。", "胎禽怨夜，半乘风、玄露丹霞。", "先生笑，飞空一剑，东风犹自天涯。", "情知道山中好，早翠嚣含隐，瑶草新芽。", "青溪故人信断，梦逐飙车。", "乾坤星火，归来兮、煮石煎砂。", "回首处、幅巾蒲帐，云边独笑桃花。"]'),
('song-ci-508','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','握虎符，持玉节，佩金鱼。',57,'宋词/ci.song.20000.json','["握虎符，持玉节，佩金鱼。", "三十正当方面，此事世间无。", "寄语东淮父老，夺我诗书元帅，於汝抑安乎。", "早早归廊庙，天下尽欢娱。"]'),
('song-ci-509','失调名','无名氏','宋','宋词','song-ci','失调名','[]','夜深青女湿微妆。',8,'宋词/ci.song.20000.json','["夜深青女湿微妆。"]'),
('song-ci-510','失调名','无名氏','宋','宋词','song-ci','失调名','[]','曾教入夜月添白。',8,'宋词/ci.song.20000.json','["曾教入夜月添白。"]'),
('song-ci-511','失调名','无名氏','宋','宋词','song-ci','失调名','[]','自有松篁为伴侣。',8,'宋词/ci.song.20000.json','["自有松篁为伴侣。"]'),
('song-ci-512','忆秦娥','无名氏','宋','宋词','song-ci','忆秦娥','[]','烟漠漠。',56,'宋词/ci.song.20000.json','["烟漠漠。", "水天摇荡蓬莱阁。", "蓬莱阁，朱甍碧瓦，半浸寥廓。", "三山谩有长生药。", "茫茫云海风涛恶。", "风涛恶。", "仙槎不见，暮沙潮落。"]'),
('song-ci-513','失调名','无名氏','宋','宋词','song-ci','失调名','[]','汉宫梳罢女真妆，望金仙、朝朝暮暮。',17,'宋词/ci.song.20000.json','["汉宫梳罢女真妆，望金仙、朝朝暮暮。"]'),
('song-ci-514','失调名','无名氏','宋','宋词','song-ci','失调名','[]','愁烟恨粉。',5,'宋词/ci.song.20000.json','["愁烟恨粉。"]'),
('song-ci-515','失调名','无名氏','宋','宋词','song-ci','失调名','[]','三生春梦。',5,'宋词/ci.song.20000.json','["三生春梦。"]'),
('song-ci-516','减字木兰花','无名氏','宋','宋词','song-ci','减字木兰花','[]','舞台歌院。',52,'宋词/ci.song.20000.json','["舞台歌院。", "雨后西风寒翦翦。", "翠掩屏风。", "花与残霞一样红。", "宫裀隐绣。", "香软巧随莲步绉。", "不怕露寒。", "日日拼教醉画栏。"]'),
('song-ci-517','虞美人','无名氏','宋','宋词','song-ci','虞美人','["\u897f\u6e56"]','秋深犹带秋初热。',66,'宋词/ci.song.20000.json','["秋深犹带秋初热。", "未放秋香发。", "爱他楼下木芙蓉。", "妆罢三千美女、出唐宫。", "西湖虽小风光胜。", "分得钱塘景。", "这些林木这些山。", "恰似三贤堂后、凭阑干。"]'),
('song-ci-518','念奴娇','无名氏','宋','宋词','song-ci','念奴娇','[]','晓来雨过，见三点两点，催花开却。',120,'宋词/ci.song.20000.json','["晓来雨过，见三点两点，催花开却。", "满目园林如锦绣，低亚阑干西角。", "魏紫风流，姚黄妖艳，桃李皆粗俗。", "金刀翦下，燕鸳窥妒惊愕。", "雅称似玉人人，淡妆才罢，粉衬胭脂薄。", "蝉翼轻笼云鬓巧，斜插一枝红萼。", "睡足杨妃，醉沉西子，娇困铅华落。", "多情风蝶，晚来犹更随著。"]'),
('song-ci-519','望江南・忆江南','无名氏','宋','宋词','song-ci','望江南・忆江南','[]','左右字，从古不曾闻。',63,'宋词/ci.song.20000.json','["左右字，从古不曾闻。", "未必书生能点墨，安知荫子不能文。", "尔汝今朝。", "除去了，多谢圣明恩。", "既不可高谈阔论，又不敢藐视同群。", "但请换头巾。"]'),
('song-ci-520','朝中措','无名氏','宋','宋词','song-ci','朝中措','[]','与君同是饱齑盐。',57,'宋词/ci.song.20000.json','["与君同是饱齑盐。", "先达后何淹。", "任玉东西醉倒，明朝病酒厌厌。", "后年三月，凤池春满，雁塔名添。", "记取西风桂影，一枝先上银蟾。"]'),
('song-ci-521','忆秦娥','无名氏','宋','宋词','song-ci','忆秦娥','[]','花蹊侧。',56,'宋词/ci.song.20000.json','["花蹊侧。", "秦楼夜访金钗客。", "金钗客。", "江梅风韵，野棠颜色。", "尊前醉倒君休惜。", "不成去后空相忆。", "空相忆。", "山长水远，几时来得。"]'),
('song-ci-522','失调名','无名氏','宋','宋词','song-ci','失调名','[]','往来与月为俦，舒展和天也蔽。',14,'宋词/ci.song.20000.json','["往来与月为俦，舒展和天也蔽。"]'),
('song-ci-523','倚西楼','无名氏','宋','宋词','song-ci','倚西楼','[]','禁鼓初传时下打。',66,'宋词/ci.song.20000.json','["禁鼓初传时下打。", "虚过清风明月夜。", "眼如鱼目几曾乾，心似酒旗终日挂。", "银汉低垂星斗斜。", "院宇空寥烛卸。", "西楼萧洒有谁知，教我独自上来、独自下。"]'),
('song-ci-524','捣练子','无名氏','宋','宋词','song-ci','捣练子','[]','云鬓乱，晚妆残。',32,'宋词/ci.song.20000.json','["云鬓乱，晚妆残。", "带恨眉儿远岫攒。", "斜托香腮春笋懒，为谁和泪倚阑干。"]'),
('song-ci-525','长相思','无名氏','宋','宋词','song-ci','长相思','[]','花满枝。',44,'宋词/ci.song.20000.json','["花满枝。", "柳满枝。", "眼底春光似旧时。", "燕归人未归。", "泪沾衣。", "酒沾衣。", "烦恼长多欢事稀。", "此情风月知。"]'),
('song-ci-526','乌夜啼','无名氏','宋','宋词','song-ci','乌夜啼','[]','都无一点残红。',45,'宋词/ci.song.20000.json','["都无一点残红。", "夜来风。", "底事东君归去、太匆匆。", "桃花醉。", "梨花泪。", "总成空。", "断送一年春在、绿阴中。"]'),
('song-ci-527','乌夜啼','无名氏','宋','宋词','song-ci','乌夜啼','[]','一弯月挂危楼。',45,'宋词/ci.song.20000.json','["一弯月挂危楼。", "似藏钩。", "醉里不知黄叶、报新秋。", "征鸿断。", "归云乱。", "远峰愁。", "愁见绿杨凝恨、在江头。"]'),
('song-ci-528','捣练子','无名氏','宋','宋词','song-ci','捣练子','[]','林下路，水边亭。',48,'宋词/ci.song.20000.json','["林下路，水边亭。", "凉吹水面散馀酲。", "小藤床、随意横。", "暗记得、旧时经。", "翠荷闹雨做秋声。", "恁时节、不怕听。"]'),
('song-ci-529','生查子','无名氏','宋','宋词','song-ci','生查子','[]','闲倚曲屏风，试写相思字。',48,'宋词/ci.song.20000.json','["闲倚曲屏风，试写相思字。", "不道极多情，却是浑无思。", "笑近短墙阴，抛个青梅子。", "苔上印钩弯，邂逅难忘此。"]'),
('song-ci-530','贺圣朝影・添声杨柳枝','无名氏','宋','宋词','song-ci','贺圣朝影・添声杨柳枝','[]','雪满长安酒价高。',48,'宋词/ci.song.20000.json','["雪满长安酒价高。", "度寒宵。", "身轻不要鹔鹴袍。", "醉红娇。", "花月暗成离别恨，梦无憀。", "起来春信惹梅梢。", "又魂消。"]'),
('song-ci-531','莫思归・抛球乐','无名氏','宋','宋词','song-ci','莫思归・抛球乐','[]','花满名园酒满觞。',46,'宋词/ci.song.20000.json','["花满名园酒满觞。", "且开笑口对秾芳。", "秋千风暖鸾钗亸，绮陌春深翠袖香。", "莫惜黄金贵，日日须教贳酒尝。"]'),
('song-ci-532','点绛唇','无名氏','宋','宋词','song-ci','点绛唇','[]','蹴罢秋千，起来慵整纤纤手。',50,'宋词/ci.song.20000.json','["蹴罢秋千，起来慵整纤纤手。", "露浓花瘦。", "薄汗轻衣透。", "见客入来，袜剗金钗溜。", "和羞走。", "倚门回首。", "却把青梅嗅。"]'),
('song-ci-533','减字木兰花','无名氏','宋','宋词','song-ci','减字木兰花','[]','春融酒困。',52,'宋词/ci.song.20000.json','["春融酒困。", "一寸横波千里恨。", "著处芳菲。", "蝶与莺情醉自迷。", "敧云妥翠。", "冷落金屏山十二。", "低抱琵琶。", "月向黄昏日又斜。"]'),
('song-ci-534','菩萨蛮','无名氏','宋','宋词','song-ci','菩萨蛮','[]','昔年曾伴花前醉。',52,'宋词/ci.song.20000.json','["昔年曾伴花前醉。", "今年空洒花前泪。", "花有再荣时。", "人无重见期。", "故人情义重。", "不忍营新宠。", "日月有盈亏。", "妾心无改移。"]'),
('song-ci-535','谒金门','无名氏','宋','宋词','song-ci','谒金门','[]','山无数。',53,'宋词/ci.song.20000.json','["山无数。", "遮断故人何处。", "见说阑舟独系住。", "溪边红叶树。", "忆著前时欢遇。", "惹起今番愁绪。", "怎得西风吹泪去。", "阳台为暮雨。"]'),
('song-ci-536','更漏子','无名氏','宋','宋词','song-ci','更漏子','[]','解语花，断肠草。',58,'宋词/ci.song.20000.json','["解语花，断肠草。", "谙尽风流烦恼。", "欢会少，别离多。", "此情无奈何。", "帐前灯，窗间月。", "记得那□时节。", "绣被剩，画屏空。", "如今在梦中。"]'),
('song-ci-537','镜中人・相思引','无名氏','宋','宋词','song-ci','镜中人・相思引','[]','柳烟浓，梅雨润。',57,'宋词/ci.song.20000.json','["柳烟浓，梅雨润。", "芳草绵绵离恨。", "花坞风来几阵。", "罗袖沾春粉。", "独上小楼迷远近。", "不见浣溪人信。", "何处笛声飘隐隐。", "吹断相思引。"]'),
('song-ci-538','眼儿媚','无名氏','宋','宋词','song-ci','眼儿媚','[]','惨云愁雾罩江天。',58,'宋词/ci.song.20000.json','["惨云愁雾罩江天。", "呵手卷帘看。", "蒙茸柳絮，万千蝴蝶，飞过危栏。", "后庭一树瑶华缀，零乱暗香残。", "今番桂影，也应寒重，不放新弯。"]'),
('song-ci-539','眼儿媚','无名氏','宋','宋词','song-ci','眼儿媚','[]','忆从溪上得相逢。',58,'宋词/ci.song.20000.json','["忆从溪上得相逢。", "樽酒两心同。", "梅缄香雪，竹摇寒月，柳探春风。", "而今总是消魂处，冷落半床空。", "梦迷狂蝶，喜占乾鹊，愁望飞鸿。"]'),
('song-ci-540','眼儿媚','无名氏','宋','宋词','song-ci','眼儿媚','[]','平生几度怨长亭。',58,'宋词/ci.song.20000.json','["平生几度怨长亭。", "不似这番深。", "霜收水瘦，风流帆饱，怎忍轻分。", "栏干倚遍慵归去，独自个黄昏。", "荷横钗股，柳垂裙带，总是销魂。"]'),
('song-ci-541','乌夜啼','无名氏','宋','宋词','song-ci','乌夜啼','["\u897f\u6e56"]','水漫汀洲新绿，云开崦嶂微青。',56,'宋词/ci.song.20000.json','["水漫汀洲新绿，云开崦嶂微青。", "残红不见成阴后，鶗鴂寂无声。", "笑傲坡诗一梦，风流杜牧三生。", "西湖依旧人中意，来去竟难凭。"]'),
('song-ci-542','与团圆・喜团圆','无名氏','宋','宋词','song-ci','与团圆・喜团圆','[]','绞绡雾縠，没多重数，紧拟偷怜。',61,'宋词/ci.song.20000.json','["绞绡雾縠，没多重数，紧拟偷怜。", "孜孜觑着，算前生、只结得眼因缘。", "眼是心媒，心为情本，里外勾连。", "天还有意，不违人愿，与个团圆。"]'),
('song-ci-543','花前饮','无名氏','宋','宋词','song-ci','花前饮','[]','雨馀天色渐寒渗。',60,'宋词/ci.song.20000.json','["雨馀天色渐寒渗。", "海棠绽、胭脂如锦。", "告你休看书，共我花前饮。", "皓月穿帘未成寝。", "篆香透、鸳衾双枕。", "似恁天色时，你道是、好做甚。"]'),
('song-ci-544','转调贺圣朝・贺圣朝','无名氏','宋','宋词','song-ci','转调贺圣朝・贺圣朝','[]','渐觉一日，浓如一日，不比寻常。',61,'宋词/ci.song.20000.json','["渐觉一日，浓如一日，不比寻常。", "若知人、未伊瘦损，成病又何妨。", "相思到了，不成模样，收泪千行。", "把从前泪，来做水流，也流到伊行。"]'),
('song-ci-545','西江月','无名氏','宋','宋词','song-ci','西江月','[]','昨夜轺车宿处，乱山深锁邮亭。',58,'宋词/ci.song.20000.json','["昨夜轺车宿处，乱山深锁邮亭。", "烟溪霜叶颤秋声。", "不管愁人不听。", "枕冷安排难稳，衾寒重叠犹轻。", "凭谁说与那人人。", "报道衾寒枕冷。"]'),
('song-ci-546','望江南・忆江南','无名氏','宋','宋词','song-ci','望江南・忆江南','[]','这痴呆，休恁泪涟涟。',64,'宋词/ci.song.20000.json','["这痴呆，休恁泪涟涟。", "他是霸陵桥畔柳，千人攀了到君攀。", "刚甚别离难。", "荷上露，莫把作珠穿。", "水性本来无定度，这边圆了那边圆。", "终是不心坚。"]'),
('song-ci-547','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','紫陌朱轮去似流。',64,'宋词/ci.song.20000.json','["紫陌朱轮去似流。", "丁香初结小银钩。", "凭阑试问秦楼路，瞥见纤纤十指柔。", "金约腕，玉搔头。", "尽教人看却佯羞。", "欲题红叶无流水，别是桃源一段愁。"]'),
('song-ci-548','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','镇日无心扫黛眉。',64,'宋词/ci.song.20000.json','["镇日无心扫黛眉。", "临行愁见理征衣。", "樽前只恐伤郎意，阁泪汪汪不敢垂。", "停宝马，捧瑶卮。", "相斟相劝忍分离。", "不如饮待奴先醉，图得不知郎去时。"]'),
('song-ci-549','遍地花','无名氏','宋','宋词','song-ci','遍地花','[]','元是竹林旧伴侣。',66,'宋词/ci.song.20000.json','["元是竹林旧伴侣。", "去人日、偶相遇。", "笑卢同、狂怪尝茶，问子建、诗成几步。", "忆去年、乞巧同欢，把琴弦、细细与说。", "伤你爱四勾三，生下五男二女。"]'),
('song-ci-550','红窗迥','无名氏','宋','宋词','song-ci','红窗迥','[]','富春坊，好景致。',70,'宋词/ci.song.20000.json','["富春坊，好景致。", "两岸尽是、歌姬舞妓。", "引调得、上界神仙，把凡心都起。", "内有丙丁并壬癸。", "这两尊神，为你争些口气。", "火星道，我待逞些神通，不怕你是水。"]'),
('song-ci-551','小重山','无名氏','宋','宋词','song-ci','小重山','[]','络纬声残织翠丝。',70,'宋词/ci.song.20000.json','["络纬声残织翠丝。", "金风剪不断、雁来时。", "梦回缄泪寄征衣。", "寒到早，应怪寄衣迟。", "心事有谁知。", "黄昏常立尽、暗萤飞。", "秋来无处不生悲。", "情脉脉，月转辘轳西。"]'),
('song-ci-552','撷芳词','无名氏','宋','宋词','song-ci','撷芳词','[]','风摇荡，雨濛茸。',68,'宋词/ci.song.20000.json','["风摇荡，雨濛茸。", "翠条柔弱花头重。", "春衫窄。", "香肌湿。", "记得年时，共伊曾摘。", "都如梦。", "何曾共。", "可怜孤似钗头凤。", "关山隔。", "晚云碧。", "燕儿来也，又无消息。"]'),
('song-ci-553','拨棹子','无名氏','宋','宋词','song-ci','拨棹子','[]','烟姿媚，冰容薄。',74,'宋词/ci.song.20000.json','["烟姿媚，冰容薄。", "芳蕖嫩、隐映新萍池阁。", "撷英人去后，清香微绽，透真珠帘幕。", "似无语含情垂彩佩，戏芳阴，渐许纤鲜相托。", "西风直须爱惜，看看浓艳，伴秋光零落。"]'),
('song-ci-554','香山会','无名氏','宋','宋词','song-ci','香山会','[]','向神前发愿，烧香做咒。',79,'宋词/ci.song.20000.json','["向神前发愿，烧香做咒。", "断了去、娼家吃酒。", "果子钱早是遭他毒手。", "更一个、瓶儿渗漏。", "才斟两盏三盏，早斟不勾。", "又添和、薄漓半斗。", "奴哥有我，奴哥道有。", "有我时、当面荡酒。"]'),
('song-ci-555','品令','无名氏','宋','宋词','song-ci','品令','[]','急雨惊秋晓。',81,'宋词/ci.song.20000.json','["急雨惊秋晓。", "今岁较、秋风早。", "一觞一咏，更须莫负、晚风残照。", "可惜莲花已谢，莲房尚小。", "汀苹岸草。", "怎称得、人情好。", "有些言语，也待醉折，荷花向道。", "道与荷花，人比去年总老。"]'),
('song-ci-556','御街行','无名氏','宋','宋词','song-ci','御街行','[]','霜风渐紧寒侵被。',97,'宋词/ci.song.20000.json','["霜风渐紧寒侵被。", "听孤雁、声嘹唳。", "一声声送一声悲，云淡碧天如水。", "披衣起。", "告雁儿略住，听我些儿事。", "塔儿南畔城儿里。", "第三个、桥儿外。", "濒河西岸小红楼，门外梧桐雕砌。", "请教且与，低声飞过，那里有、人人无寐。"]'),
('song-ci-557','惜寒梅','无名氏','宋','宋词','song-ci','惜寒梅','[]','看尽千花，爱寒梅暗与、雪期霜约。',121,'宋词/ci.song.20000.json','["看尽千花，爱寒梅暗与、雪期霜约。", "雅态香肌，迥有天然淡泊。", "五侯园囿姿游乐。", "凭阑处、重开绣幕。", "秦娥妆罢，遥相纵，艳过京洛。", "天涯再见素萼。", "似凝然向人，玉容寂寞。", "江上飘零，怎把芳心付托。", "那堪风雨夜来恶。", "便减动、一分瘦削。", "直须沉醉，尤香殢云，莫待改落。"]'),
('song-ci-558','古阳关・阳关引','无名氏','宋','宋词','song-ci','古阳关・阳关引','[]','渭城朝雨，一霎浥轻尘。',126,'宋词/ci.song.20000.json','["渭城朝雨，一霎浥轻尘。", "更洒遍、客舍青青。", "弄柔凝、千缕柳色新。", "更洒遍，客舍青青，千缕柳色新。", "休烦恼。", "劝君更尽一杯酒，人生会少。", "自古富贵功名有定分。", "莫遣容仪瘦损。", "休烦恼，劝君更尽一杯酒，只恐怕、西出阳关，旧游如梦，眼前无故人。", "祗恐怕、西出阳关，眼前无故人。"]'),
('song-ci-559','永遇乐','无名氏','宋','宋词','song-ci','永遇乐','[]','孤衾不暖，静闻银漏，敧枕难稳。',128,'宋词/ci.song.20000.json','["孤衾不暖，静闻银漏，敧枕难稳。", "细想多情，多才多貌，总是多愁本。", "而今幽会难成，佳期顿阻，只恁萦方寸。", "知他莫是，今生共伊，此欢无分。", "寻思断肠肠断，珠泪搵了，依前重搵。", "终待临岐，分明说与，我这厌厌闷。", "得伊知后，教人成病。", "万种断也无限。", "只恐他、恁不分晓，谩劳瘦损。"]'),
('song-ci-560','一萼红','无名氏','宋','宋词','song-ci','一萼红','[]','断云漏日，青阳布，渐入融和天气。',134,'宋词/ci.song.20000.json','["断云漏日，青阳布，渐入融和天气。", "糁缀夭桃，金绽垂杨，妆点亭台佳致。", "晓露染、风裁雨晕，是牡丹、偏称化工美。", "向此际会，未教一萼，红开鲜蕊。", "迤逦。", "渐成春意。", "放秀色妖艳，天真难比。", "粉惹蝶翅，香上蜂须，忍把芳心萦碎。", "争似便，移归深院，将绿盖青帏护风日。", "恁时节，占断与、偎红倚翠。"]'),
('song-ci-561','霜叶飞','无名氏','宋','宋词','song-ci','霜叶飞','[]','故宫秋晚馀芳尽，轻阴闲淡池阁。',134,'宋词/ci.song.20000.json','["故宫秋晚馀芳尽，轻阴闲淡池阁。", "凤泥银暗玳纹花，卷断肠帘幕。", "渐砌菊、遗金谢却，芙蓉才共清霜约。", "半弄蕊、冰绡波浅，拂胭脂、翠琼连并雕萼。", "应是曾倚东君，纵艳姿轻盈，映损丹杏红药。", "旋成深妒，判与西风，任从开落。", "况衰晚、渊明意薄。", "重阳羞对吟酌。", "待说与江梅，早傅粉匀香，慰伊萧索。"]'),
('song-ci-562','檐前铁','无名氏','宋','宋词','song-ci','檐前铁','[]','悄无人，宿雨厌厌，空庭乍歇。',88,'宋词/ci.song.20000.json','["悄无人，宿雨厌厌，空庭乍歇。", "听檐前、铁马戛叮当，敲破梦魂残结。", "丁年事，天涯恨，又早在心头咽。", "谁怜我、绮帘前，镇日鞋儿双跌。", "今番也、石人应下千行血。", "拟展青天，写作断肠文，难尽说。"]'),
('song-ci-563','娇木笪・木笪','无名氏','宋','宋词','song-ci','娇木笪・木笪','[]','酒入愁肠，谁信道、都做泪珠儿滴。',34,'宋词/ci.song.20000.json','["酒入愁肠，谁信道、都做泪珠儿滴。", "又怎知道恁他忆。", "再相逢、瘦了才信得。"]'),
('song-ci-564','小品','无名氏','宋','宋词','song-ci','小品','[]','正天气凄凉，鸣幽砌，向枕畔、偏恼愁心，尽夜苦吟。',24,'宋词/ci.song.20000.json','["正天气凄凉，鸣幽砌，向枕畔、偏恼愁心，尽夜苦吟。"]'),
('song-ci-565','小品','无名氏','宋','宋词','song-ci','小品','[]','戴花殢酒，酒泛金樽，花枝满帽。',26,'宋词/ci.song.20000.json','["戴花殢酒，酒泛金樽，花枝满帽。", "笑歌醉拍手，戴花殢酒。"]'),
('song-ci-566','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','全似丹青搵染成。',64,'宋词/ci.song.20000.json','["全似丹青搵染成。", "更将何物斗轻盈。", "雪因舞态羞频下，云为歌声不忍行。", "螺髻小，凤鞋轻。", "天边斗柄又斜横。", "水晶庭柱琉璃帐，客去同谁看月明。"]'),
('song-ci-567','甘露滴乔松','无名氏','宋','宋词','song-ci','甘露滴乔松','[]','沙堤露近，喜五年相遇，朱颜依旧。',119,'宋词/ci.song.20000.json','["沙堤露近，喜五年相遇，朱颜依旧。", "尽道名世半千，公望三九。", "是今日、富民侯。", "早生聚、考堂户口。", "谁欤兼致，文章燕许，歌辞苏柳。", "更饶万卷图书，把藤笈芸编，遍题青镂。", "一经传得，旧事韦平先后。", "试衮衮、数英游。", "问好事、如今能否。", "曲车正满，自酌太和春酒。"]'),
('song-ci-568','满江红','无名氏','宋','宋词','song-ci','满江红','[]','雪共梅花，念动是、经年离拆。',114,'宋词/ci.song.20000.json','["雪共梅花，念动是、经年离拆。", "重会面、玉肌真态，一般标格。", "谁道无情应也妒，暗香埋没教谁识。", "却随风、偷入傍妆台，萦帘额。", "惊醉眼，朱成碧。", "随冷暖，分青白。", "叹朱弦冻折，高山音息。", "怅望关河无驿使，剡溪兴尽成陈迹。", "见似枝而喜对杨花，须相忆。"]'),
('song-ci-569','念奴娇','无名氏','宋','宋词','song-ci','念奴娇','[]','天工谬巧，恁平地、推出崚嶒岩壁。',120,'宋词/ci.song.20000.json','["天工谬巧，恁平地、推出崚嶒岩壁。", "虎跃龙骧飞凤翥，疑道补天馀石。", "洞壑穿云，来今往古，知是谁开辟。", "千年兰若，林峦隐映金碧。", "我兴邱壑尤长，朅来此境，惯蹑登山屐。", "适意人生随处好，何必岘南阳峄。", "谢傅东山，裴公绿野，俯仰俱陈迹。", "何如轻举，廓寥云外横笛。"]'),
('song-ci-570','秦楼月・忆秦娥','梁意娘','宋','宋词','song-ci','秦楼月・忆秦娥','[]','春宵短。',56,'宋词/ci.song.20000.json','["春宵短。", "香闺寂寞愁无限。", "愁无限。", "一声窗外，晓莺新啭。", "起来无语成娇懒。", "柔肠易断人难见。", "人难见。", "这些心绪，如何消遣。"]'),
('song-ci-571','茶瓶儿','梁意娘','宋','宋词','song-ci','茶瓶儿','[]','满地落花铺绣。',65,'宋词/ci.song.20000.json','["满地落花铺绣。", "春色著人如酒。", "晓莺窗外啼杨柳。", "愁不奈、两眉频皱。", "关山杳。", "音尘悄。", "那堪是、昔年时候。", "盟言辜负知多少。", "对好景、顿成消瘦。"]'),
('song-ci-572','西江月','越娘','宋','宋词','song-ci','西江月','[]','一自东君去后，几多恩爱暌离。',58,'宋词/ci.song.20000.json','["一自东君去后，几多恩爱暌离。", "频凝泪眼望乡畿。", "客路迢迢千里。", "顾我风情不薄，与君驿邸相随。", "参军虽死不须悲。", "幸有连枝同气。"]'),
('song-ci-573','西江月','张师师','宋','宋词','song-ci','西江月','[]','一种何其轻薄，三眠情意偏多。',58,'宋词/ci.song.20000.json','["一种何其轻薄，三眠情意偏多。", "飞花舞絮弄春和。", "全没些儿定个。", "踪迹岂容收拾，风流无处消磨。", "依依接取手亲挼。", "永结同心向我。"]'),
('song-ci-574','西江月','钱安安','宋','宋词','song-ci','西江月','[]','谁道词高和寡，须知会少离多。',58,'宋词/ci.song.20000.json','["谁道词高和寡，须知会少离多。", "三家本作一家和。", "更莫容他别个。", "且恁眼前同乐，休将饮里相磨。", "酒肠不奈苦揉挼。", "我醉无多酌我。"]'),
('song-ci-575','南乡子','张商英','宋','宋词','song-ci','南乡子','[]','向晚出京关。',66,'宋词/ci.song.20000.json','["向晚出京关。", "细雨微风拂面寒。", "杨柳堤边青草岸，堪观。", "只在人心咫尺间。", "酒饮盏须乾。", "莫道浮生似等闲。", "用则逆理天下事，何难。", "不用云中别有山。"]'),
('song-ci-576','南乡子','张商英','宋','宋词','song-ci','南乡子','[]','瓦钵与磁瓯。',66,'宋词/ci.song.20000.json','["瓦钵与磁瓯。", "闲伴白云醉后休。", "得失事常贫也乐，无忧。", "运去英雄不自由。", "彭越与韩侯。", "盖世功名一土丘。", "名利有饵鱼吞饵，轮收。", "得脱那能更上钩。"]'),
('song-ci-577','人娇','徐都尉','宋','宋词','song-ci','人娇','[]','小苑藏春，信道游人未见。',84,'宋词/ci.song.20000.json','["小苑藏春，信道游人未见。", "花脸嫩、柳腰娇软。", "停觞缓引，正夕阳将晚。", "莺误入，蹴损海棠花片。", "只怅春心，当时露见，小楼外、曾劳目断。", "灯前料想。", "也肌心饱眼。", "从此去，萦心有人可惯。"]'),
('song-ci-578','最高楼','崔木','宋','宋词','song-ci','最高楼','[]','蹇驴缓跨，迢递至京城。',103,'宋词/ci.song.20000.json','["蹇驴缓跨，迢递至京城。", "当此际，正芳春。", "芹泥融暖飞雏燕，柳条摇曳韵鹂庚。", "更那堪，迟日暖，晓风轻。", "算费尽、主人歌与酒，更费尽、青楼𥱧与筝。", "多少事，绊牵情。", "愧我品题无雅句，喜君歌咏有新声。", "愿从今，鱼比目，凤和鸣。"]'),
('song-ci-579','虞美人','崔木','宋','宋词','song-ci','虞美人','[]','春来秋往何时了。',66,'宋词/ci.song.20000.json','["春来秋往何时了。", "心事知多少。", "深深庭院悄无人。", "独自行来独坐、若为情。", "双旌声势虽云贵。", "终是谁存济。", "今宵已幸得人言。", "拟待劳烦神女、下巫山。"]'),
('song-ci-580','虞美人','黄舜英','宋','宋词','song-ci','虞美人','[]','一从骨肉相抛了。',66,'宋词/ci.song.20000.json','["一从骨肉相抛了。", "受了多多少。", "溪山风月属何人。", "到此思量、因甚不关情。", "而今虽道王孙贵。", "有事凭谁济。", "自从今夜得媒言。", "相见佳期无谓、隔关山。"]'),
('song-ci-581','南乡子','贾奕','宋','宋词','song-ci','南乡子','[]','闲步小楼前。',66,'宋词/ci.song.20000.json','["闲步小楼前。", "见个佳人貌类仙。", "暗想圣情浑似梦，追欢。", "执手兰房恣意怜。", "一夜说盟言。", "满掬沉檀喷瑞烟。", "报道早朝归去晚，回銮。", "留下鲛绡当宿钱。"]'),
('song-ci-582','鹧鸪天','窃杯女子','宋','宋词','song-ci','鹧鸪天','[]','灯火楼台处处新。',64,'宋词/ci.song.20000.json','["灯火楼台处处新。", "笑携郎手御街行。", "回头忽听传呼急，不觉鸳鸯两处分。", "天表近，帝恩荣。", "琼浆饮罢脸生春。", "归来恐被儿夫怪，愿赐金杯作证明。"]'),
('song-ci-583','念奴娇','窃杯女子','宋','宋词','song-ci','念奴娇','[]','桂魄澄辉，禁城内、万盏花灯罗列。',121,'宋词/ci.song.20000.json','["桂魄澄辉，禁城内、万盏花灯罗列。", "无限佳人穿绣径，几多妖艳奇绝。", "凤烛交光，银灯相射，奏箫韶初歇。", "鸣鞘响处，万民瞻仰宫阙。", "妾自闺门给假，与夫携手，共赏元宵节。", "误到玉皇金殿砌，赐酒金杯满设。", "量窄从来，红凝粉面，尊见无凭说。", "假王金盏，免公婆责罚臣妾。"]'),
('song-ci-584','鹧鸪天','刘','宋','宋词','song-ci','鹧鸪天','[]','竹引牵牛花满街。',64,'宋词/ci.song.20000.json','["竹引牵牛花满街。", "疏篱茅舍月光筛。", "琉璃盏内茅柴酒，白玉盘中簇豆梅。", "休懊恼，且开怀。", "平生赢得笑颜开。", "三千里地无知己，十万军中挂印来。"]'),
('song-ci-585','菩萨蛮','陈义','宋','宋词','song-ci','菩萨蛮','[]','平生只被今朝误。',52,'宋词/ci.song.20000.json','["平生只被今朝误。", "今朝却把平生补。", "重午一年期。", "斋僧只待时。", "主人恩义重。", "两载蒙恩宠。", "清净得为僧。", "幽闲度此生。"]'),
('song-ci-586','菩萨蛮','陈义','宋','宋词','song-ci','菩萨蛮','[]','包中香黍分边角。',52,'宋词/ci.song.20000.json','["包中香黍分边角。", "彩丝剪就交绒索。", "樽俎泛菖蒲。", "年年五月初。", "主人恩义重。", "对景承欢宠。", "何日玩山家。", "葵蒿三四花。"]'),
('song-ci-587','苏幕遮','净端','宋','宋词','song-ci','苏幕遮','[]','遇荒年，每常见。',76,'宋词/ci.song.20000.json','["遇荒年，每常见。", "就中今年，洪水皆淹遍。", "父母分离无可恋。", "幸望豪民，救取庄家汉。", "最堪伤，何忍见。", "古寺禅林，翻作悲田院。", "日夜烧香频□□，祷告皇天，救护开方便。"]'),
('song-ci-588','浪淘沙','善珍','宋','宋词','song-ci','浪淘沙','[]','相对两衰翁。',64,'宋词/ci.song.20000.json','["相对两衰翁。", "身似枯蓬。", "分飞吹聚谢天风。", "零落交游无一个，五十年中。", "生客语藏锋。", "不答阳聋。", "心期难话与儿童。", "共结庵招猿鹤侣，烟锁云封。"]'),
('song-ci-589','浪淘沙','善珍','宋','宋词','song-ci','浪淘沙','[]','七十二年翁。',64,'宋词/ci.song.20000.json','["七十二年翁。", "曾客吴中。", "清游占断水晶宫。", "几度藕花归棹晚，月渚烟钟。", "追记已陈踪。", "回首空濛。", "恁高荒草夕阳同。", "欲问谢公歌舞地，落叶鸣蛩。"]'),
('song-ci-590','望梅词・望梅','善珍','宋','宋词','song-ci','望梅词・望梅','[]','寸阴堪惜。',132,'宋词/ci.song.20000.json','["寸阴堪惜。", "趁身强健去，结茅苍壁。", "错料事、临老方知，国师与高僧，二途俱失。", "识字吟诗，数不得、死生何益。", "看寒山着语，李杜也输，莫道元白。", "千年过如瞬息。", "共飞鸿缥缈，沉没空碧。", "问懒瓒、因甚遭逢，芋魁亦联翩，著名金石。", "遗臭流芳，老子勿、许多心力。", "旋消磨、数百瓮齑，掩关入寂。"]'),
('song-ci-591','渔歌・渔父','李彭','宋','宋词','song-ci','渔歌・渔父','[]','南院嫡孙唯此个。',36,'宋词/ci.song.20000.json','["南院嫡孙唯此个。", "西河狮子当门坐。", "绢扇清凉随手簸。", "君知麽。", "无端吃棒休寻过。"]'),
('song-ci-592','渔歌・渔父','李彭','宋','宋词','song-ci','渔歌・渔父','[]','掌握千差都照破。',36,'宋词/ci.song.20000.json','["掌握千差都照破。", "石霜这汉难关锁。", "水出高源酬佛陀。", "哩棱逻。", "须弥作舞虚空和。"]'),
('song-ci-593','渔歌・渔父','李彭','宋','宋词','song-ci','渔歌・渔父','[]','孤硬云峰无计较。',36,'宋词/ci.song.20000.json','["孤硬云峰无计较。", "大愚滩上曾垂钓。", "佛法何曾愁烂了。", "桶箍爆。", "通身汗出呵呵笑。"]'),
('song-ci-594','渔歌・渔父','李彭','宋','宋词','song-ci','渔歌・渔父','[]','万古黄龙真夭矫。',36,'宋词/ci.song.20000.json','["万古黄龙真夭矫。", "斩新勘破台山媪。", "佛手驴蹄人不晓。", "无关窍。", "胡家一曲非凡调。"]'),
('song-ci-595','渔歌・渔父','李彭','宋','宋词','song-ci','渔歌・渔父','[]','宝觉禅河波浩浩。',36,'宋词/ci.song.20000.json','["宝觉禅河波浩浩。", "五湖衲子来求宝。", "忽坚拳头宜速道。", "茫然讨。", "难逃背触君须到。"]'),
('song-ci-596','渔歌・渔父','李彭','宋','宋词','song-ci','渔歌・渔父','[]','贬剥诸方真净老。',36,'宋词/ci.song.20000.json','["贬剥诸方真净老。", "顶门眼正形枯槁。", "一点深藏人莫造。", "由来妙。", "光明烜赫机锋峭。"]'),
('song-ci-597','渔歌・渔父','李彭','宋','宋词','song-ci','渔歌・渔父','[]','积翠十年丹风穴。',36,'宋词/ci.song.20000.json','["积翠十年丹风穴。", "当时亲得黄龙钵。", "掣电之机难把撮。", "真奇绝。", "分明水底天边月。"]'),
('song-ci-598','渔歌・渔父','李彭','宋','宋词','song-ci','渔歌・渔父','[]','骂佛骂人新孟八。',36,'宋词/ci.song.20000.json','["骂佛骂人新孟八。", "是非窟里和身拶。", "不惜眉毛言便发。", "门庭滑。", "红炉大韛能生效。"]'),
('song-ci-599','渔歌・渔父','李彭','宋','宋词','song-ci','渔歌・渔父','[]','绝唱灵源求和寡。',36,'宋词/ci.song.20000.json','["绝唱灵源求和寡。", "先牛寻得西家马。", "顾陆笔端难拟画。", "千林谢。", "吟风摆雪真萧洒。"]'),
('song-ci-600','渔歌・渔父','李彭','宋','宋词','song-ci','渔歌・渔父','[]','选佛堂中川藞苴。',36,'宋词/ci.song.20000.json','["选佛堂中川藞苴。", "衲僧卑孔头垂下。", "独秀握来无一把。", "杖头挂。", "从教四海禅徒讶。"]'),
('song-ci-601','渔家傲','无际道人','宋','宋词','song-ci','渔家傲','[]','七坐道场三奉诏。',72,'宋词/ci.song.20000.json','["七坐道场三奉诏。", "空花水月何时了。", "小玉声中曾悟道。", "真堪笑。", "从来漫得儿孙好。", "辩涌海潮声浩浩。", "明如皓月当空照。", "飞锡西归云杳渺。", "巴猿啸。", "大家唱起还乡调。"]'),
('song-ci-602','解佩令','张伯端','宋','宋词','song-ci','解佩令','[]','修行之士，功勤不小。',84,'宋词/ci.song.20000.json','["修行之士，功勤不小。", "识五行、逆顺颠倒。", "妙理玄玄，玉炉中、龙蟠虎踞，金鼎内、炼成至宝。", "阳神雕体，杳杳冥冥，刹那间、游遍三岛。", "出入纯熟，按捺住、别寻玄妙。", "合真空，太虚是了。"]'),
('song-ci-603','齐天乐','朱涣','宋','宋词','song-ci','齐天乐','[]','白云封断仙岩路，重重洞深窈。',121,'宋词/ci.song.20000.json','["白云封断仙岩路，重重洞深窈。", "翠竹笼烟，苍崖溅瀑，古木阴森回抱。", "坛空不老。", "锁一片莓苔，几丝莎草。", "试把桃源，较量风景是谁好。", "乘鸾人去已久，只今惟有，鹤飞猿啸。", "树拥香幢，泉敲玉佩，疑是群仙重到。", "尘氛可笑。", "久志慕丹台，梦思蓬岛。", "愿挹英游，细参梨与枣。"]'),
('song-ci-604','满江红','陈纪','宋','宋词','song-ci','满江红','[]','揽辔埋轮，算不负、苍髯如戟。',115,'宋词/ci.song.20000.json','["揽辔埋轮，算不负、苍髯如戟。", "人争看、横秋一鹗，轩然健翼。", "只手为天行日月，寸怀与物同苏息。", "到于今、天定瘴云开，伊谁力。", "云霄路，金门客。", "念往事，情可极。", "把行藏细说，应无惭色。", "虹气上横牛斗剑，梅花不软心肠石。", "愿此行、珍重不赀躯，无瑕璧。"]'),
('song-ci-605','念奴娇','陈纪','宋','宋词','song-ci','念奴娇','[]','凭高眺远，见凄凉海国，高秋云物。',120,'宋词/ci.song.20000.json','["凭高眺远，见凄凉海国，高秋云物。", "岛屿沉洋萍几点，漠漠天垂四壁。", "粟粒太虚，蜉蝣天地，怀抱皆冰雪。", "清风明月，坐中看我三杰。", "为爱暮色苍寒，天光上下，舣棹须明发。", "一片玻璃秋万顷，天外去帆明灭。", "招手仙人，拍肩居士，散我骑鲸发。", "钓鳌台上，叫云吹断残月。"]'),
('song-ci-606','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','抛却功名弃却诗。',65,'宋词/ci.song.20000.json','["抛却功名弃却诗。", "从教身染气球泥。", "侵晨打�捌朐苹幔�际暮演筹落魄归。", "园苑里，粉墙西。", "佳人偷揭绣帘窥。", "高侵云汉垂肩久，低拂花梢下脚迟。"]'),
('song-ci-607','西江月','无名氏','宋','宋词','song-ci','西江月','[]','健体安身可美，喜笑化食堪夸。',58,'宋词/ci.song.20000.json','["健体安身可美，喜笑化食堪夸。", "更言一事实为佳。", "肥风瘦痨都罢。", "兼且时光似箭，更加景色难赊。", "名园等处乐奢华。", "一任佳人玩耍。"]'),
('song-ci-608','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','不贪名利乐优游。',64,'宋词/ci.song.20000.json','["不贪名利乐优游。", "收转心猿踢气球。", "日享三餐朋友饭，夜眠一宿玉人缕。", "真快活，度春秋。", "从他乌兔走无休。", "或时戏耍名园里，或把长竿湖上游。"]'),
('song-ci-609','西江月','无名氏','宋','宋词','song-ci','西江月','[]','蹴踘场中年少，秋千架上佳人。',58,'宋词/ci.song.20000.json','["蹴踘场中年少，秋千架上佳人。", "三三两两趁芳辰。", "玩赏风光美景。", "日暖风和明媚，更加花草香馨。", "红颜移步出闺门，偷揭绣帘相认。"]'),
('song-ci-610','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','虎掌葵花一锭银。',64,'宋词/ci.song.20000.json','["虎掌葵花一锭银。", "全凭巧匠弄精神。", "里膁外跨知高下，逼拐挑尖月一轮。", "欺强汉，灭村人。", "其间奥妙岂堪论。", "不问贵戚并公子，曾与区区并马行。"]'),
('song-ci-611','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','巧匠园缝异样花。',64,'宋词/ci.song.20000.json','["巧匠园缝异样花。", "身轻体健实堪夸。", "能令公子精神爽，善诱王孙礼义加。", "宜富贵，逞奢华。", "一团和气遍天涯。", "宋祖昔日皆曾习，占断风流第一家。"]'),
('song-ci-612','西江月','无名氏','宋','宋词','song-ci','西江月','[]','请知诸郡子弟，尽是湖海高朋。',58,'宋词/ci.song.20000.json','["请知诸郡子弟，尽是湖海高朋。", "今年神首赛齐云。", "别是一般风韵。", "来时向前参圣，然后疏上挥名。", "香金留下仿花人，必定气球取胜。"]'),
('song-ci-613','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','轩辕起置号齐云。',64,'宋词/ci.song.20000.json','["轩辕起置号齐云。", "社祖西川妙道君。", "□□亲自裁成就，万古流传作玩珍。", "江湖客，听原因。", "今朝出狱见其真。", "来到圣前必撞案，诚将实艺向前呈。"]'),
('song-ci-614','苏幕遮','无名氏','宋','宋词','song-ci','苏幕遮','[]','水中金，冲牛斗。',76,'宋词/ci.song.20000.json','["水中金，冲牛斗。", "玉锁金关，护法灵童守。", "赤水丹台龙虎走。", "万象森罗，勃勃投珠口。", "饮灵源，明火候。", "太乙炉开，丹熟神光透。", "浮名浮利终不久。", "下手速修。", "穷取无中有。"]'),
('song-ci-615','满庭芳','毕大节','宋','宋词','song-ci','满庭芳','[]','玉笋京华，紫荷香润，宴闲密侍西清。',118,'宋词/ci.song.20000.json','["玉笋京华，紫荷香润，宴闲密侍西清。", "碧幢金节，仍尹凤皇城。", "须信千龄庆遇，丹霄上、重叠恩荣。", "时多暇，湖山丽景，许酒乐升平。", "新春。", "逢诞日，莺花渐好，初过烧灯。", "想笙歌丛里，醉赏瑶觥。", "占尽人间福寿，行看取、稳赞机衡。", "貂蝉映，朱颜绿鬓，沙路马蹄轻。"]'),
('song-ci-616','满庭芳','毕大节','宋','宋词','song-ci','满庭芳','[]','井络储精，岷江锺秀，挺生名世真贤。',118,'宋词/ci.song.20000.json','["井络储精，岷江锺秀，挺生名世真贤。", "充闾佳气，非雾亦非烟。", "况值小春时候，蓂背下、八荚争妍。", "馀波在，九华父老，歌颂轓喧嗔。", "三年。", "书治最，南唐重赋，一旦俱蠲。", "此恩垂不朽，刻石流传。", "愿借沧溟为寿，玳筵上、满吸长川。", "从兹去，鸾坡凤阁，平步稳登仙。"]'),
('song-ci-617','蝶恋花','寇准','宋','宋词','song-ci','蝶恋花','[]','四十年来身富贵。',70,'宋词/ci.song.20000.json','["四十年来身富贵。", "游处烟霞，步履如平地。", "紫府丹台仙籍里，皆知独擅无双美。", "将相兼荣谁敢比。", "彩凤徊翔，重浴荀池水。", "位极人臣功济世，芬芳天下歌桃李。"]'),
('song-ci-618','渔家傲','庞籍','宋','宋词','song-ci','渔家傲','[]','儒将不须躬甲胄。',72,'宋词/ci.song.20000.json','["儒将不须躬甲胄。", "指挥玉麈风云走。", "战罢挥毫飞捷奏。", "倾贺酒。", "三杯遥献南山寿。", "草软沙平春日透。", "萧萧下马长川逗。", "马上醉中山色秀。", "光一一。", "旌戈矛戟山前后。"]'),
('song-ci-619','蝶恋花','晏殊','宋','宋词','song-ci','蝶恋花','[]','紫府群仙名籍秘。',70,'宋词/ci.song.20000.json','["紫府群仙名籍秘。", "五色班龙，暂降人间世。", "海变沧田都不记。", "蟠桃一熟三千岁。", "露滴彩旌云绕秋，谁信壶中，别有笙歌地。", "门外落花随水逝。", "相看莫惜尊前醉。"]'),
('song-ci-620','诉衷情','晏殊','宋','宋词','song-ci','诉衷情','[]','幕天席地斗豪奢。',54,'宋词/ci.song.20000.json','["幕天席地斗豪奢。", "歌妓捧红牙。", "从他醉醒醒醉，斜插满头花。", "车载酒，解貂贳。", "尽繁华。", "儿孙贤俊，家道荣昌，祝寿无涯。"]'),
('song-ci-621','诉衷情','晏殊','宋','宋词','song-ci','诉衷情','[]','喧天丝竹韵融融。',54,'宋词/ci.song.20000.json','["喧天丝竹韵融融。", "歌唱画堂中。", "玲女世间希有，烛影夜摇红。", "一同笑，饮千锺。", "兴何穷。", "功成名遂，富足年康，祝寿如松。"]'),
('song-ci-622','南乡子','沈唐','宋','宋词','song-ci','南乡子','[]','朝觐俯尧阶。',66,'宋词/ci.song.20000.json','["朝觐俯尧阶。", "宠拜新恩天上回。", "欢动边城十万户，民怀。", "荣见旌旗却再来。", "清晓敞铃齐。", "庭下鸣鼍绮宴开。", "红袖两行频捧劝，金□。", "利市应销十二钗。"]'),
('song-ci-623','蝶恋花','周起','宋','宋词','song-ci','蝶恋花','[]','岳佐星储生佐圣。',70,'宋词/ci.song.20000.json','["岳佐星储生佐圣。", "真道宏才，济世功名盛。", "久践机衡宣密命。", "逢时力赞无为政。", "明主得贤朝野庆。", "昼按从容，帝宠何人并。", "早晚紫垣持国柄。", "民瞻共荷三台正。"]'),
('song-ci-624','醉蓬莱','杨绘','宋','宋词','song-ci','醉蓬莱','[]','对亭台幽雅，水竹清虚，嫩凉轻透。',120,'宋词/ci.song.20000.json','["对亭台幽雅，水竹清虚，嫩凉轻透。", "碧沼红蕖，送香风盈袖。", "白首冯唐，诞辰同庆，上百分仙酎。", "鳌禁词垣，乌台谏省，昔游俱旧。", "千里长沙，五年湓浦，近捧丝纶，更藩移守。", "桂苑馀芳，有孙枝新秀。", "罗绮雍容，管弦松脆，愿拜延椿寿。", "岁岁年年，今朝启宴，欢荣良久。"]'),
('song-ci-625','长寿乐','苏氏','宋','宋词','song-ci','长寿乐','[]','微寒应候。',135,'宋词/ci.song.20000.json','["微寒应候。", "望日远六远，阶蓂初秀。", "爱景欲挂扶桑，漏残银箭，杓回瑶斗。", "庆高闳此际，掌上一颗明珠剖。", "有令容淑德，归逢佳偶。", "到如今，昼锦满堂贵胄。", "荣耀，久步禁，一一金章绿绶。", "更值棠棣连阴，虎符熊轼，夹河分守。", "况青云咫尺，朝暮入承明后*看彩衣争献，兰盈玉酎。", "祝千龄，共指松椿比寿。"]'),
('song-ci-626','万年欢','苏氏','宋','宋词','song-ci','万年欢','[]','日暖霜红，画戟门开，锦筵歌振梁尘。',123,'宋词/ci.song.20000.json','["日暖霜红，画戟门开，锦筵歌振梁尘。", "正是慈闱熙熙，庆诞佳辰。", "象服鱼轩灿烂，喜高年、福禄长新。", "承颜处，朱紫相将，更兼华胄诜诜。", "家声未论王谢，有禁中颇牧，江左机云。", "雁字鸳行，雍容高步金门。", "况有子孙侍列，拥阶庭、玉洁兰薰。", "持芳醑，满酌瑶觞，竞祝遐寿千春。"]'),
('song-ci-627','减字木兰花','王观','宋','宋词','song-ci','减字木兰花','[]','寿星明久。',52,'宋词/ci.song.20000.json','["寿星明久。", "寿曲高歌沉醉后。", "寿烛荣煌。", "手把金炉爇寿香。", "满斟寿酒。", "我意殷勤来祝寿。", "问寿如何。", "寿比南山福更多。"]'),
('song-ci-628','减字木兰花','王观','宋','宋词','song-ci','减字木兰花','[]','花筵布巧。',52,'宋词/ci.song.20000.json','["花筵布巧。", "绿绕红□花枝闹。", "朵朵风流。", "好向尊前插满头。", "此花妖艳。", "愿得年年长相见。", "满劝金锺。", "祝寿如花岁岁红。"]'),
('song-ci-629','减字木兰花','王观','宋','宋词','song-ci','减字木兰花','[]','天之美禄。',52,'宋词/ci.song.20000.json','["天之美禄。", "会饮思量平生福。", "一硕刘伶，五斗将来且解酲。", "百年长解。", "三万六千能几日。", "劝饮瑶觞。", "祝寿不如岁月长。"]'),
('song-ci-630','减字木兰花','王观','宋','宋词','song-ci','减字木兰花','[]','红牙初展。',52,'宋词/ci.song.20000.json','["红牙初展。", "象板如云遮娇面。", "曲按宫商。", "声遏行云绕画梁。", "正当衮遍。", "休唱阳关人肠断。", "劝饮流霞。", "祝寿千年转更加。"]'),
('song-ci-631','减字木兰花','王观','宋','宋词','song-ci','减字木兰花','[]','多愁早老。',52,'宋词/ci.song.20000.json','["多愁早老。", "着甚由来闲烦恼。", "休管浮名。", "安乐身康似宝珍。", "酒逢知己，好向尊前朝日醉。", "满劝瑶觥。", "祝寿如山岁岁青。"]'),
('song-ci-632','减字木兰花','王观','宋','宋词','song-ci','减字木兰花','[]','今晨佳宴。',52,'宋词/ci.song.20000.json','["今晨佳宴。", "昨夜南极星光现。", "鹤舞青霁，丹凤呈祥瑞气飘。", "仙书来诏。", "绿鬓朱颜长不老。", "满劝香醪。", "祝寿如云转转高。"]'),
('song-ci-633','减字木兰花','王观','宋','宋词','song-ci','减字木兰花','[]','角声三品。',52,'宋词/ci.song.20000.json','["角声三品。", "银漏更残将欲尽。", "盏盏华筵。", "玉粒琼瓯散又圆。", "知君洪量。", "不用推辞须一上。", "满劝殷勤。", "祝寿如同福禄星。"]'),
('song-ci-634','减字木兰花','王观','宋','宋词','song-ci','减字木兰花','[]','新秋气肃。',52,'宋词/ci.song.20000.json','["新秋气肃。", "此时仙翁曾诞育。", "禀赋应遍。", "绿□朱颜似少年。", "阶庭兰玉。", "行见儿孙俱曳绿。", "更祝遐龄。", "愿比壮椿过八千。"]'),
('song-ci-635','减字木兰花','王观','宋','宋词','song-ci','减字木兰花','[]','百年能几。',52,'宋词/ci.song.20000.json','["百年能几。", "似数巡环无了日。", "有限时光。", "玉兔金鸟晓夜忙。", "幸逢清世。", "最好排筵斟绿蚁。", "满捧金蕉。", "祝寿如松永不凋。"]'),
('song-ci-636','减字木兰花','王观','宋','宋词','song-ci','减字木兰花','[]','三皇五帝。',52,'宋词/ci.song.20000.json','["三皇五帝。", "古代英雄闲争气。", "勇猛韩彭。", "十大功劳空有名。", "休谈人我。", "大限催煎如何亸。", "前酌觥舡。", "祝寿如同海月圆。"]'),
('song-ci-637','减字木兰花','王观','宋','宋词','song-ci','减字木兰花','[]','春光景媚。',52,'宋词/ci.song.20000.json','["春光景媚。", "花褪残红炎天气。", "蝉噪高枝。", "雁叫长空雪乱飞。", "四时如箭。", "八节忙忙频改换。", "满捧金彝。", "祝寿如同海岳齐。"]'),
('song-ci-638','减字木兰花','王观','宋','宋词','song-ci','减字木兰花','[]','才鸣□鼓。',52,'宋词/ci.song.20000.json','["才鸣□鼓。", "曲奏仙音如乐府。", "美似梨园。", "一派箫韶列玳筵。", "使人清耳。", "满尘宾朋皆欢喜。", "劝饮金荷。", "祝寿延长福更多。"]'),
('song-ci-639','沁园春','苏轼','宋','宋词','song-ci','沁园春','[]','情若连环，恨如流水，甚时是休。',143,'宋词/ci.song.20000.json','["情若连环，恨如流水，甚时是休。", "也不须惊怪，沈郎易瘦，也不须惊怪，潘鬓先愁。", "总是难禁，许多魔难，奈好事教人不自由。", "空追想，念前欢杳杳，后会悠悠。", "凝眸。", "悔上层楼。", "谩惹起、新愁与旧愁。", "向彩笺写遍，相思字了，重重封卷，密寄书邮。", "料到伊行，时时开看，一看一回和泪收。", "须知道，□这般病染，两处心头。"]'),
('song-ci-640','人娇','无名氏','宋','宋词','song-ci','人娇','[]','解了痴绦，泼煞闷火。',77,'宋词/ci.song.20000.json','["解了痴绦，泼煞闷火。", "眉尖上、放闲愁锁。", "高来不可，低来不可，莫是人间剩我一个。", "富贵谩人，功名赚我。", "且舞个采莲曲破。", "红裙腰细，醁醅盏大，须占取、名花艳中醉卧。"]'),
('song-ci-641','定风波','无名氏','宋','宋词','song-ci','定风波','[]','痛饮形骸骑蹇驴。',72,'宋词/ci.song.20000.json','["痛饮形骸骑蹇驴。", "葛巾不整倩人扶。", "笑指桃源泥样醉。", "三睡。", "诗魔长是泣穷途。", "画手也知仙骨瘦。", "□□崑山玉水点银须。", "天地不能容此老。", "笑傲。", "一竿风月钓江湖。"]'),
('song-ci-642','玉女摇仙佩','黄庭坚','宋','宋词','song-ci','玉女摇仙佩','[]','宫梅弄粉，御柳摇金，又喜皇州春早。',170,'宋词/ci.song.20000.json','["宫梅弄粉，御柳摇金，又喜皇州春早。", "盛世生贤，真仙应运，当日来从三岛。", "车马喧清晓。", "看千锺赐饮，中人传诏。", "最好是、芝兰并砌，鸣珮腰金，彩衣相照。", "炉烟袅。", "高堂半卷珠帘，神仙缥缈。", "须信槐庭荫美，凤沼波澄，屈指十年三到。", "九叙重歌，元圭再锡，已把成功来告。", "四海瞻仪表。", "庆君臣会集，诗符天保。", "况自有、仙风道骨，玉函金篆，阴功须报。", "方知道。", "八千岁月椿难老。"]'),
('song-ci-643','瑶台第一层','黄庭坚','宋','宋词','song-ci','瑶台第一层','[]','阆苑归来，因醉上、瑶台第一层。',121,'宋词/ci.song.20000.json','["阆苑归来，因醉上、瑶台第一层。", "洞天深处，年年不夜，日日长春。", "万花妆烂锦，散异香，馥郁留人。", "便乘兴，命玉龙吟笛，彩凤吹笙。", "身轻。", "先逢瑞景，众中先识董双成。", "珮环声丽，舞腰袅袅，浓艳腾腾。", "翠屏金缕枕，绣被软，梦冷槐清。", "乐蓬瀛。", "愿南山同寿，北斗齐龄。"]'),
('song-ci-644','永遇乐','晁端礼','宋','宋词','song-ci','永遇乐','[]','雪霁千岩，春回万壑，和气如许。',128,'宋词/ci.song.20000.json','["雪霁千岩，春回万壑，和气如许。", "今古稽山，风流人物，真是生申处。", "儿童竹马，欢迎夹道，争为使君歌舞。", "道当年、蓬莱朵秀，又来作蓬莱主。", "一编勋业，家传几世，自是赤松仙侣。", "青琐黄堂，等闲游戏，又问乘槎路。", "银河耿耿，使星今夜，应与老人星聚。", "要知他、秋羹消息，早梅初吐。"]'),
('song-ci-645','满庭芳','仲殊','宋','宋词','song-ci','满庭芳','[]','晓日迎凉，烟华生翠，玉麟香转风轻。',118,'宋词/ci.song.20000.json','["晓日迎凉，烟华生翠，玉麟香转风轻。", "细丝钧管，罗绮拥芝庭。", "竞折蟠桃献寿，雨露罩，春下仙瀛。", "碧池上，龟游鹤舞，一曲奏长生。", "当年。", "嘉庆会，兰江秀气，星昴光灵。", "奄奕世馀徽，同降元精。", "此日中吴太守，看看秉、廊庙钧衡。", "麒麟阁，功名第一，从此入丹青。"]'),
('song-ci-646','踏莎行','仲殊','宋','宋词','song-ci','踏莎行','[]','德感元精，岳方孕秀。',68,'宋词/ci.song.20000.json','["德感元精，岳方孕秀。", "才明渊智神兼授。", "飞鸣早应舜韶来，五符千骑难淹久。", "熊梦开祥，龟文献寿。", "龙香卷雾摇东斗。", "南天为现老人暑，一时顶礼抬双神。"]'),
('song-ci-647','满庭芳','仲殊','宋','宋词','song-ci','满庭芳','[]','三月迟迟，牡丹时节，算来淑景方融。',117,'宋词/ci.song.20000.json','["三月迟迟，牡丹时节，算来淑景方融。", "板舆闲暇，香雾锁花宫。", "曾侍瑶池宴席，三千女，深浅匀红。", "轻含笑，尊前认得，阿母旧慈容。", "倾心。", "齐献寿，一时倾倒，春在杯中。", "戏彩衣间作，喜气重重。", "更有天仙寄语，教皓鹤、双舞云空。", "人长命，花枝长在，岁又东风。"]'),
('song-ci-648','醉蓬莱','仲殊','宋','宋词','song-ci','醉蓬莱','[]','报一阳初动，二五蓂疏，履长时候。',120,'宋词/ci.song.20000.json','["报一阳初动，二五蓂疏，履长时候。", "大昴星精，宛分灵储秀。", "早运钧衡，亟还貂衮，向载歌成后。", "书展仪形，承华羽翼，恩深惟旧。", "天眷难留，片帆归去，縠水柯山，故人携手。", "枕月眠云，老华胥闲昼。", "夕宴朝欢，况当加庆，献我公眉寿。", "五福千祥，山长水远，一樽芳酒。"]'),
('song-ci-649','减字木兰花','仲殊','宋','宋词','song-ci','减字木兰花','[]','英花万蕊。',52,'宋词/ci.song.20000.json','["英花万蕊。", "醒□丹房玄石髓。", "烟驾来时。", "一勺仙翁手自随。", "旋煎松火。", "始觉醍醐直可可。", "扶起精神。", "洞里天闲日月新。"]'),
('song-ci-650','鹊踏枝・蝶恋花','仲殊','宋','宋词','song-ci','鹊踏枝・蝶恋花','[]','一霎雕栏疏雨罢。',70,'宋词/ci.song.20000.json','["一霎雕栏疏雨罢。", "三月十三，曾是寒食夜。", "尽日暖香熏柏麝。", "西施醉起留归驾。", "酒满玻璃花艳冶。", "莫负春心，快饮千锺罢。", "春在燕堂帘幕下。", "年芳不问东君借。"]'),
('song-ci-651','醉花阴','仲殊','宋','宋词','song-ci','醉花阴','[]','一双鹤绕蟠桃戏。',51,'宋词/ci.song.20000.json','["一双鹤绕蟠桃戏。", "说人间千岁。", "昨夜降元精，蓬矢桑弧，又报千家喜。", "绮罗庭院笙歌沸。", "拥玳簪珠履。", "五福一……。"]'),
('song-ci-652','永同欢','仲殊','宋','宋词','song-ci','永同欢','[]','绣帘卷，沉烟细。',34,'宋词/ci.song.20000.json','["绣帘卷，沉烟细。", "燕堂深，玳筵初启。", "庭下芝兰，劝金卮，有多少雍容和气。"]'),
('song-ci-653','柳垂金','仲殊','宋','宋词','song-ci','柳垂金','[]','中春天气禁烟暖。',69,'宋词/ci.song.20000.json','["中春天气禁烟暖。", "馀七叶，丹蓂未卷。", "海岳灵辉储庆远。", "降非熊，运符亨旦。", "宝雾香凝，非锦筵红荐。", "永算金尊屡满，酒里千年春烂漫。", "共朱颜，镇长相见。"]'),
('song-ci-654','西江月','仲殊','宋','宋词','song-ci','西江月','[]','耐老花间的子，长生海里明珠。',58,'宋词/ci.song.20000.json','["耐老花间的子，长生海里明珠。", "南天星象降真符。", "五福同行同住。", "秀骨养成犀顶，被人唤作龙驹。", "传家事业有诗书。", "富贵功名看取。"]'),
('song-ci-655','西江月','仲殊','宋','宋词','song-ci','西江月','[]','乙未河清九曲，神霄瑞降群仙。',58,'宋词/ci.song.20000.json','["乙未河清九曲，神霄瑞降群仙。", "唯公殊宠最华年。", "高侍玉皇香案。", "富贵鹏程九万，康宁鹤算三千。", "功成拔宅上青天，愿厕庭中鸡犬。"]'),
('song-ci-656','念奴娇','仲殊','宋','宋词','song-ci','念奴娇','[]','延陵福绪，蔼遗芳馀庆，直至如今。',119,'宋词/ci.song.20000.json','["延陵福绪，蔼遗芳馀庆，直至如今。", "帝锡朋龟曾献策。", "早揖丹桂华簪。", "一代荣名，三州遗爱，留入歌吟。", "归来湖山付得，依旧闲心。", "延赏报德推封。", "名迁书监，喜天恩垂临。", "拜舞龙香还注想，丹阙拖紫垂金。", "酒满霞觞，期君眉寿，千岁与披衿。", "年年风月，两行门外桐阴。"]'),
('song-ci-657','步蟾宫','仲殊','宋','宋词','song-ci','步蟾宫','["\u957f\u6c5f"]','仙郎心似长江阔。',72,'宋词/ci.song.20000.json','["仙郎心似长江阔。", "妾意如、波间明月。", "相随定、一带向东流，共宴乐、无时暂歇。", "长生只在长欢悦。", "除此外、总应虚设。", "笙歌里、身住几何年，十字儿、头边下撇。"]'),
('song-ci-658','步蟾宫','仲殊','宋','宋词','song-ci','步蟾宫','[]','笙歌喜庆争催晓。',72,'宋词/ci.song.20000.json','["笙歌喜庆争催晓。", "篆烟舞、龙鸾缥缈。", "香罗上、不尽寿仙人，献一段、长生寿草。", "一心一意同欢笑。", "两心事、卒难得了。", "教传语、天上太白星，剩借取、几千年好。"]'),
('song-ci-659','步蟾宫','仲殊','宋','宋词','song-ci','步蟾宫','[]','凤帘舞带花铺绣。',70,'宋词/ci.song.20000.json','["凤帘舞带花铺绣。", "水沉暖、祥烟迷昼。", "凤衔灯照蕊珠筵，韵双琯、钧声已奏。", "绮罗人劝千秋寿。", "吉祥满、十分芳酒。", "愿人间、嘉庆一千年，共南极、东华长久。"]'),
('song-ci-660','醉蓬莱','仲殊','宋','宋词','song-ci','醉蓬莱','[]','过灵香一炷，燕馆清虚，晚窗风细。',120,'宋词/ci.song.20000.json','["过灵香一炷，燕馆清虚，晚窗风细。", "雨入园林，荡凝烟摇曳。", "天上春融，暖移残腊，早信音来至。", "宫粉龙香，一时拈入，江梅轻蕊。", "人在瑶山，九仙书府，静与羲皇，淡然相对。", "锦琴无声，鼓一轩和气。", "丹枝高枝，旧香芬馥，惹赐袍春翠。", "再揖文章，声名定与，渊云相继。"]'),
('song-ci-661','步蟾宫','仲殊','宋','宋词','song-ci','步蟾宫','[]','长庚星驭重来日，结灵秀、东阳清骨。',72,'宋词/ci.song.20000.json','["长庚星驭重来日，结灵秀、东阳清骨。", "过中秋，两夜月犹圆，五福降、先宫第一。", "鹤书新自金门出。", "乍受得、王宫缨绂。", "更登仙、箓上与长年，倩东斗、真人按笔。"]'),
('song-ci-662','醉蓬莱','仲殊','宋','宋词','song-ci','醉蓬莱','[]','骤西风凄惨，秋昊平分，晚收清昼。',120,'宋词/ci.song.20000.json','["骤西风凄惨，秋昊平分，晚收清昼。", "素月潜生，倚危墙时候。", "渐照芳樽，前中孤影，喜暂时为友。", "醉学吴儿，狂歌乱拍，蹁跹双袖。", "堪叹从来，误了词赋，进取才能，桂枝难勾。", "纵得虚名，与平生相负。", "缰锁尘埃，愿怀圭组，强剑眉低首。", "平地神仙，清凉世界，君曾知否。"]'),
('song-ci-663','瑞鹧鸪','仲殊','宋','宋词','song-ci','瑞鹧鸪','[]','融融十月小春天。',53,'宋词/ci.song.20000.json','["融融十月小春天。", "翼翼清都降圣贤。", "大抵龙飞云必动，请观二十七年前。", "方今龙又当天德，即日云将拥地仙。", "富（下缺）"]'),
('song-ci-664','醉蓬莱','仲殊','宋','宋词','song-ci','醉蓬莱','[]','望金华真界，宝婺星垣，瑞符玄动。',120,'宋词/ci.song.20000.json','["望金华真界，宝婺星垣，瑞符玄动。", "羽葆莱游，有八鸾环拥。", "日在龙房，下弦平月，见崧岳生申。", "天上三奇，人间五福，一齐景宠。", "骞树七台，紫微金简，授箓延年，大椿腾颂。", "玉液称觞，引长生歌送。", "彩雾笼云，舞香花萼，降蕊珠仙众。", "太史多才，功成异日，鸣箫双凤。"]'),
('song-ci-665','沁园春','毛滂','宋','宋词','song-ci','沁园春','[]','左元仙伯，旧从当日，太一下生。',140,'宋词/ci.song.20000.json','["左元仙伯，旧从当日，太一下生。", "念道尊德贵，体隆貌重，盖天勋业，出世才名。", "父子一时，君臣千载，侍宴通宵留太清。", "衣冠盛事，满床象简，隔坐云屏。", "年年此夜寒轻。", "正在东风下，不夜城。", "看御杯重劝，宸章屡赐，盛传歌舞，高会簪缨。", "桃李玉姬，芝兰子舍，尽向三台瞻寿星。", "从今去，愿千春献祝，午夜观灯。"]'),
('song-ci-666','沁园春','毛滂','宋','宋词','song-ci','沁园春','[]','秀禀元精，灵锺崧岳，命世大贤。',141,'宋词/ci.song.20000.json','["秀禀元精，灵锺崧岳，命世大贤。", "自飞英任路，承流百里，郎官星彩，辉映经躔。", "劲柏凌霜，香梅娇雪，珪月弯弯新上弦。", "垂弧节庆，麒麟古梦，此夜初圆。", "罗川。", "父老欣然。", "算善政、古来谁与肩。", "念桃阴浓密，瓜期咫尺，双凫难驻，便欲朝天。", "争把丹青，绘成芝宇，立作生祠千载传。", "仍知道，看它时画像，别有凌烟。"]'),
('song-ci-667','念奴娇','赵鼎臣','宋','宋词','song-ci','念奴娇','[]','嫦娥伴侣，降人世，天与长生仙箓。',120,'宋词/ci.song.20000.json','["嫦娥伴侣，降人世，天与长生仙箓。", "五色云开浮瑞霭，中有西真眉目。", "贤德家风，艳容天赋，占尽人间福。", "长庚明月，誓同千古相逐。", "开宴香蔼华堂，金杯休诉，好醉蟠桃熟。", "子子孙孙同上寿，有个人人同祝。", "雨鬓春风，一钗香雾，长与瑶池绿。", "更祈眉寿，愿如南山松竹。"]'),
('song-ci-668','小重山','吴则礼','宋','宋词','song-ci','小重山','[]','鹤舞青青雪里松。',70,'宋词/ci.song.20000.json','["鹤舞青青雪里松。", "冰门龟在藻，绿蒙茸。", "一成不见蕊珠宫。", "蟠桃熟，犹待几东风。", "玉酒紫金锺。", "非烟罗幕暖，宝□浓。", "赠君春色腊寒中。", "君留取，长伴脸边红。"]'),
('song-ci-669','东风第一枝','吴则礼','宋','宋词','song-ci','东风第一枝','[]','经国谋猷，补天气力，岳祗来佐兴运。',123,'宋词/ci.song.20000.json','["经国谋猷，补天气力，岳祗来佐兴运。", "王当华阙春融，共仰相门地峻。", "清台占象，见壁月、珠星明润。", "对一百五日风光，二十四番花信。", "勋共德、继增篆鼎。", "今共古、问谁比并。", "广乐初出，层霄寿斝，旋颁紫叶，湘桃浓杏。", "映彩服、朱颜青鬓。", "看千岁，桀阁飞楼，燕赏太平光景。"]'),
('song-ci-670','绛都春','吴则礼','宋','宋词','song-ci','绛都春','[]','馀寒尚峭。',118,'宋词/ci.song.20000.json','["馀寒尚峭。", "早凤沼冻开，芝田春到。", "茂对诞期，天与公春向廊庙。", "元功开物争春妙。", "传与秾华多少。", "召还和气，拂开霁色，未妨谈笑。", "缥缈。", "五云乱处，种雕胡自熟，蟠桃犹小。", "雨露在门，光彩充闾乌亦好。", "宝熏郁雾城西道。", "天自锡公难老。", "看公身任安危，二十四考。"]'),
('song-ci-671','绛都春','吴则礼','宋','宋词','song-ci','绛都春','[]','韶华渐好。',117,'宋词/ci.song.20000.json','["韶华渐好。", "报锦里又是，春风来早。", "昴宿降萧，崧岳生申符英表。", "三朝倖望人倾祷。", "寿与长城俱老。", "碧油红旆，高牙大纛一时荣耀。", "矫矫。", "甘泉旧德，少年日，翰苑玉堂曾到。", "润饰帝谟，粉泽皇猷文章妙。", "主盟经济尊吾道。", "早晚促归岩庙。", "愿同海内苍生，伫看凤诏。"]'),
('song-ci-672','多丽','吴则礼','宋','宋词','song-ci','多丽','[]','听新蝉，舜琴初弄清弦。',172,'宋词/ci.song.20000.json','["听新蝉，舜琴初弄清弦。", "伴薰风、匆匆佳气，锺希世英贤。", "正芳蓂、更馀九荚，况强仕，犹待三年。", "笔下烟云，胸中岩壑，玉峰凛凛映人寒。", "公不见、清潭宝剑，九彩动星躔。", "浑疑是，风雷变化，落在人间。", "驻东阳、清谭终日，种成桃李森然。", "向庭闱、彩衣有庆，更华萼、棠棣相鲜。", "骥足难留，牛刀暂屈，匪朝伊夕步花砖。", "自今往、掀天扶地，声迹寄凌烟。", "它时事，赤松共约，携手骖鸾。"]'),
('song-ci-673','点绛唇','吴则礼','宋','宋词','song-ci','点绛唇','[]','柏叶春醅，为君亲酌玻璃盏。',50,'宋词/ci.song.20000.json','["柏叶春醅，为君亲酌玻璃盏。", "玉箫牙管。", "人意如春暖。", "绿鬓长留，不使韶华晚。", "春无限。", "碧桃花畔。", "笑看蓬莱浅。"]'),
('song-ci-674','点绛唇','吴则礼','宋','宋词','song-ci','点绛唇','[]','何处君家，蟠桃花下瑶池畔。',50,'宋词/ci.song.20000.json','["何处君家，蟠桃花下瑶池畔。", "日迟风暖。", "占得春长远。", "几见花开，一任年光换。", "今年见。", "明年再见。", "春色如人面。"]'),
('song-ci-675','玉楼春','吴则礼','宋','宋词','song-ci','玉楼春','[]','今朝何以为公寿。',64,'宋词/ci.song.20000.json','["今朝何以为公寿。", "极贵长年公素有。", "庭阶不乏长芝兰，少翁又是庭臣右。", "三能粲粲依魁秀。", "八柱巍巍蟠地厚。", "皇家卜册万斯年，年光长转洪钧手。"]'),
('song-ci-676','玉楼春','吴则礼','宋','宋词','song-ci','玉楼春','[]','我公两器兼文武。',64,'宋词/ci.song.20000.json','["我公两器兼文武。", "谈笑岩廊无治古。", "经颜绿发已官高，赤儿绣裳今仲父。", "我欲形容无妙识。", "颂穆清风须吉甫。", "望公聊比太山云，岁岁年年天下雨。"]'),
('song-ci-677','清平乐','吴则礼','宋','宋词','song-ci','清平乐','[]','娟娟月满。',54,'宋词/ci.song.20000.json','["娟娟月满。", "冉冉梅花暖。", "春意初长寒力浅。", "渐拟芳菲满眼。", "当时吉梦重重。", "间生天子三公。", "付与人间桃李，年年管领春风。"]'),
('song-ci-678','清平乐','吴则礼','宋','宋词','song-ci','清平乐','[]','瀛洲春酒。',54,'宋词/ci.song.20000.json','["瀛洲春酒。", "满酌公眉寿。", "月照沙堤春榜柳，恩暖朝天衮绣。", "东君着意丁宁。", "芳酸先许梅英。", "要就升平滋味，待公来后和羹。"]'),
('song-ci-679','清平乐','吴则礼','宋','宋词','song-ci','清平乐','[]','雪馀寒退。',54,'宋词/ci.song.20000.json','["雪馀寒退。", "惟有青松在。", "春不加荣寒不悴。", "用舍如公都耐。", "流肪磊落龟蛇。", "会留红日西斜。", "欲助我公寿骨，蟠桃等见桃花。"]'),
('song-ci-680','清平乐','吴则礼','宋','宋词','song-ci','清平乐','[]','晨辉初转。',54,'宋词/ci.song.20000.json','["晨辉初转。", "拜舞金銮殿。", "想见对敭符睿春，天语丁宁见晚。", "雍容玉笋班聊，功名早上凌烟。", "金鼎刀圭莫惜，愿随鸡犬升仙。"]'),
('song-ci-681','清平乐','吴则礼','宋','宋词','song-ci','清平乐','[]','庆锺华胄。',54,'宋词/ci.song.20000.json','["庆锺华胄。", "人物朝端秀。", "朝罢章华骄马骤。", "十万人家举手。", "后房桃李娟娟。", "有谁云雨恩偏。", "看取晚春时候，兰芽玉茁争妍。"]'),
('song-ci-682','西江月','吴淑虎','宋','宋词','song-ci','西江月','[]','门被五王德泽，家承七帝恩光。',58,'宋词/ci.song.20000.json','["门被五王德泽，家承七帝恩光。", "古今富贵迥无双。", "多少公卿将相。", "久蕴腾空气宇，行看平步岩廊。", "更祈王母寿而康。", "真个人间天上。"]'),
('song-ci-683','水调歌头','吴叔虎','宋','宋词','song-ci','水调歌头','["\u9ec4\u6cb3"]','清澈黄河底，乙未政和年。',114,'宋词/ci.song.20000.json','["清澈黄河底，乙未政和年。", "坤珍阐瑞，运符五百间生贤。", "日暖曲江花柳，鼎沸韶春弦管，尺五是青天。", "殊宠逢熙载，吉梦送真仙。", "承盛德，公故国，庆双全。", "行看旌钺紫泥，丹诏下苕川。", "多祝多男多寿，长愿长安长乐，剑履玉宸前。", "蕙炷紫琳馆，丹笔蕊珠篇。"]'),
('song-ci-684','水调歌头','张伯寿','宋','宋词','song-ci','水调歌头','[]','天地有英气，盘结在名山。',114,'宋词/ci.song.20000.json','["天地有英气，盘结在名山。", "储精孕秀，诞生豪杰向人间。", "早拾巍科甲第，归作日边仙客，眷注不容间。", "讲道桥门暇，戏作彩衣欢。", "振斯文，回巨浸，遏狂澜。", "玉阶三尺，好扶经济侍天颜。", "把取昪平事业，趁取河清桃熟，十载付金銮。", "草却登封检，双鬓未曾斑。"]'),
('song-ci-685','临江仙','张伯寿','宋','宋词','song-ci','临江仙','[]','天上姮娥元不老，人间紫府长春。',70,'宋词/ci.song.20000.json','["天上姮娥元不老，人间紫府长春。", "朱颜鹤发更清新。", "观音常自在，水月净无尘。", "有子飘飘麟阁像，有孙庭下诜诜。", "他年看取递成名。", "进封加上国，荣拜太夫人。"]'),
('song-ci-686','临江仙','张伯寿','宋','宋词','song-ci','临江仙','[]','吴越家声传铁券，当年功指山河。',70,'宋词/ci.song.20000.json','["吴越家声传铁券，当年功指山河。", "公侯衮衮后来多。", "休符锺俊杰，气宇禀冲和。", "磊落胸襟清庙器，鹏程背可天摩。", "他时帝里笑鸣珂。", "双椿犹鹤算，二女已鸾坡。"]'),
('song-ci-687','临江仙','张伯寿','宋','宋词','song-ci','临江仙','[]','家住清湘云外窟，肯随玉笋同班。',70,'宋词/ci.song.20000.json','["家住清湘云外窟，肯随玉笋同班。", "竹林风味正相联。", "独高霜外节，微露管中斑。", "吏隐丛祠聊寄傲，胸襟半是湖山。", "此君端可助跻攀。", "支颐供鹤立，拱膝看鳌翻。"]'),
('song-ci-688','临江仙','张伯寿','宋','宋词','song-ci','临江仙','[]','龙首凤池家鼎贵，庆传仙李芬芳。',70,'宋词/ci.song.20000.json','["龙首凤池家鼎贵，庆传仙李芬芳。", "凛然冰雪照闺房。", "诞弥当此日，佳气满华堂。", "锦袖新封开大国，诏书急欲徵黄。", "莫辞沉醉九霞觞。", "蟠桃看子实，地久与天长。"]'),
('song-ci-689','临江仙','张伯寿','宋','宋词','song-ci','临江仙','[]','瑞气薰城春色早，光生帘幕飞浮。',70,'宋词/ci.song.20000.json','["瑞气薰城春色早，光生帘幕飞浮。", "五陵应是产风流。", "冰清兼玉润，轩冕一时游。", "已得长生元妙术，庄椿不数春秋。", "徐卿一醉百无忧。", "但知从此去，衮衮出公侯。"]'),
('song-ci-690','临江仙','张伯寿','宋','宋词','song-ci','临江仙','[]','爆竹声残天未晓，金炉细爇沉烟。',70,'宋词/ci.song.20000.json','["爆竹声残天未晓，金炉细爇沉烟。", "儿孙戏彩映芳鲜。", "共倾元日酒，同祝大椿年。", "我愿儿孙如我寿，高低富贵随缘。", "不须厚禄与多田。", "诗书为世业，清白是家传。"]'),
('song-ci-691','喜迁莺','曹宰','宋','宋词','song-ci','喜迁莺','[]','岁华将近。',125,'宋词/ci.song.20000.json','["岁华将近。", "得昨夜一枝，江南佳信。", "建水城中，武夷峰上，恰属老人星分。", "间世挺生贤哲，贾马文章清俊。", "推太守，想区区百里，难淹良骏。", "舆论怀报也，暂把玉山，寄与丹青晕。", "寿旦方临，祠堂其立，底事古今谁胜。", "自有养生妙诀，赢得朱颜芳鬓。", "犹更好，佩金鱼宝带，凌烟优选。"]'),
('song-ci-692','喜迁莺','曹宰','宋','宋词','song-ci','喜迁莺','[]','皇都春早，正媚景霁色，融和时候。',125,'宋词/ci.song.20000.json','["皇都春早，正媚景霁色，融和时候。", "宿霭初收，祥烟新布，桃李满林惟绣。", "挺生垩朝哲辅，风采独居人右。", "世希有，看陈思名族，平阳革裔。", "眷厚知已久，近辅名藩，符竹频分剖。", "一节趋朝，神京作镇，高掩昔年贤守。", "芝检异恩才下，玉笋清班须簉。", "寿龄远，与湖山同永，松椿同寿。"]'),
('song-ci-693','喜迁莺','曹宰','宋','宋词','song-ci','喜迁莺','[]','梅含春信，冒北律严寒，南枝先暖。',125,'宋词/ci.song.20000.json','["梅含春信，冒北律严寒，南枝先暖。", "月上初弦，萱开九叶，嵩岳诞生英俊。", "冰玉丰姿莹彻，锦绣文章焕烂。", "人歌赞，是今朝卓鲁，他年伊旦。", "犹羡瓜期近，课春九重，优陟公卿选。", "列鼎鸣钟，乘轩袭冕。", "直把功名占断。", "好是宾僚会宴，争捧觥觞频劝。", "重重愿，与青青松柏，岁寒难变。"]'),
('song-ci-694','满庭芳','王子容','宋','宋词','song-ci','满庭芳','[]','台衮筹边，京师蒙福，两淮谈笑尘清。',118,'宋词/ci.song.20000.json','["台衮筹边，京师蒙福，两淮谈笑尘清。", "正銗筒无讼，桴鼓亦稀鸣。", "阅武分弓角射，催春事、亲劝农耕。", "何须付，寻花问柳，小队出郊坰。", "功名。", "今已就，九重近天，好去辞荣。", "算人间极贵，何似长生。", "刺占梅山日月，观二妙，玉纹抨。", "休辞醉，洛阳花信，香到露华亭。"]'),
('song-ci-695','满庭芳','王子容','宋','宋词','song-ci','满庭芳','["\u897f\u6e56"]','瑞霭腾空，长庚入梦，挺生名世真贤。',118,'宋词/ci.song.20000.json','["瑞霭腾空，长庚入梦，挺生名世真贤。", "荐膺宸眷，移镇日华边。", "千里民谣载路，薰和气、俱作春妍。", "须知道，西湖草木，亦自肃成权。", "黄堂。", "开雅宴，酒浮云液，歌倚湘弦。", "□赐金增秩，入侍甘泉。", "且向露桃花底，拚沉醉，频举觥舡。", "祈难老，鬓随柳绿，官共早莺迁。"]'),
('song-ci-696','满庭芳','王子容','宋','宋词','song-ci','满庭芳','[]','蓬海移春，卿云约月，庆传王母骖鸾。',118,'宋词/ci.song.20000.json','["蓬海移春，卿云约月，庆传王母骖鸾。", "九仙福地，不减玉龟山。", "况是莱儿绣斧，都衬得、彩舞斓斑。", "瑶觞举，平反一笑，功行足三十。", "木天。", "来瑞节，行封两国，宫锦蝉联。", "更孙枝满座，兰畹芝田。", "中诏肩舆上殿，称万寿，椒掖欢颜。", "黄锺数，从新九九，巧历演长年。"]'),
('song-ci-697','感皇恩','叶景山','宋','宋词','song-ci','感皇恩','[]','十月小春时，蓂舒六翠。',81,'宋词/ci.song.20000.json','["十月小春时，蓂舒六翠。", "天佑皇家诞贤裔。", "熊罴协梦，疑是麒麟分瑞。", "世间无限事，都如意。", "粉阵香围，香娇玉媚。", "春酒争持泛琼蚁，笙歌缭绕，同祝我公千岁。", "他年陪绿野，拚酣醉。"]'),
('song-ci-698','临江仙','叶景山','宋','宋词','song-ci','临江仙','[]','清晓于门开寿宴，绮罗香袅芳丛。',70,'宋词/ci.song.20000.json','["清晓于门开寿宴，绮罗香袅芳丛。", "红娇绿软媚光风。", "绣屏金翡翠，锦帐玉芙蓉。", "珠履争驰千岁酒，葡萄满泣金锺。", "人生福寿古难逢。", "好将家庆事，写入画图中。"]'),
('song-ci-699','临江仙','叶景山','宋','宋词','song-ci','临江仙','[]','杨柳池塘桃李径，华堂寿宴初开。',71,'宋词/ci.song.20000.json','["杨柳池塘桃李径，华堂寿宴初开。", "香团翠幕舞风回。", "东山携妓女，北海罄樽罍。", "玉笋轻敲红象板，金荷潋潋传杯。", "笙歌缭绕宴春台。", "华阳闲日日月，绿野醉蓬莱。"]'),
('song-ci-700','感皇恩','叶景山','宋','宋词','song-ci','感皇恩','[]','春水满池塘，春风吹柳。',81,'宋词/ci.song.20000.json','["春水满池塘，春风吹柳。", "春草茸茸媚晴昼。", "春烟骀荡，春色着人如旧。", "春光无限好，花时候。", "春院宴开，春屏环绣。", "春酒争持介眉寿。", "春衫春暖，春回遏云声透。", "春年常不老，松筠茂。"]'),
('song-ci-701','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','昭代数人物，谁似我公贤。',114,'宋词/ci.song.20000.json','["昭代数人物，谁似我公贤。", "平生礌礌磊磊，常以义为先。", "广立湖中义学，盛集陕西义社，良法自家传。", "阴德有如此，眉寿不须言。", "圣天子，方右武，复宗文。", "诗书马上，看君父子共争先。", "伫听天山三箭，还共秋闱一举，相继凯歌旋。", "金印大如斗，富贵出长年。"]'),
('song-ci-702','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','云海漾空阔，风露凛高寒。',114,'宋词/ci.song.20000.json','["云海漾空阔，风露凛高寒。", "仙翁鹤驾羽节，缥缈下天端。", "指点虚无征路，时见双凫飞舞，挥斥隘尘寰。", "吹笛向何处，海上有三山。", "彩衣新，鱼服丽，映朱颜。", "蟠桃未熟，千岁容与旦人间。", "早晚金泥封诏，归侍紫皇香案，踵武列仙班。", "玉骨自不老，未用九还丹。"]'),
('song-ci-703','醉蓬莱','李商英','宋','宋词','song-ci','醉蓬莱','[]','庆朋良相遇，夷夏均欢，福沾绵宇。',117,'宋词/ci.song.20000.json','["庆朋良相遇，夷夏均欢，福沾绵宇。", "扶日勋高，更补天力巨。", "学造渊微，文赓三圣，被褒语。", "来自丹台，生逢华旦，身登仙路。", "衮绣归来，水晶宫里，燕处超然，去天尺五。", "绿发朱颜，照青春如故。", "一粒刀圭，五更丹灶，与赤松游处。", "只恐看着蒲轮，趣上沙堤归去。"]'),
('song-ci-704','醉蓬莱','李商英','宋','宋词','song-ci','醉蓬莱','[]','庆长庚协梦，仙李蟠根，挺生名世。',120,'宋词/ci.song.20000.json','["庆长庚协梦，仙李蟠根，挺生名世。", "粉省收声，早云霄自致。", "凤掖鸾坡，荷囊簪笔，久要津历试。", "红旆班春，碧油开府，出分忧寄。", "均逸真祠，右弧开宴，宵月光澄，玉炉烟细。", "漆发冰眸，揽浮丘仙袂。", "伫见九重，迂驰三节，诏促还丹陛。", "槐府凉生，榴樽香泛，年年欢醉。"]'),
('song-ci-705','洞仙歌','李商英','宋','宋词','song-ci','洞仙歌','[]','腊残寒峭，渐近新正际。',103,'宋词/ci.song.20000.json','["腊残寒峭，渐近新正际。", "喜溢门阑霭佳气。", "遇昌辰，符吉梦，岳渎呈祥瑞。", "知是天诞人间奇瑞。", "文章推晁董，学擅卿云，高揭声猷缙绅里。", "上瀛洲册府，师表宗藩，华要地，俱是宸衷注意。", "又何止看看便持荷，更寿为崆峒，广成同岁。"]'),
('song-ci-706','洞仙歌','李商英','宋','宋词','song-ci','洞仙歌','[]','霓旌降节，缥缈蓬瀛里。',103,'宋词/ci.song.20000.json','["霓旌降节，缥缈蓬瀛里。", "前是骖鸾在人世。", "云衢沾圣泽，两地疏封，须信道，不减瑶台富贵。", "兰帏称寿日，朱紫盈门，碧藕蟠桃奉甘旨。", "更何须，求大药饵服还丹，长不老，鹤骨仙标无比。", "况壶天日月自延长，看几度人间，百年千岁。"]'),
('song-ci-707','胜胜慢・声声慢','李商英','宋','宋词','song-ci','胜胜慢・声声慢','[]','笙簧缭绕，书鼓声喧，佳人对舞绣帘前。',117,'宋词/ci.song.20000.json','["笙簧缭绕，书鼓声喧，佳人对舞绣帘前。", "高卷铺衬，广列华筵。", "人人献香祝寿，捧流霞，永庆高年。", "名香爇，睹重重华盖，金兽喷烟。", "一愿皇恩频降，松柏对龟鹤，彭祖齐肩。", "二愿子子孙孙，尽贡三元。", "石崇富贵也休夸，陆地神仙。", "更三愿，愿年年佳庆，永保团圆。"]'),
('song-ci-708','木兰花慢','李商英','宋','宋词','song-ci','木兰花慢','[]','喜琼筵乍启，似王母、宴瑶池。',122,'宋词/ci.song.20000.json','["喜琼筵乍启，似王母、宴瑶池。", "正珠履骈肩，群仙间坐，冰玉交辉。", "新词更兼旧曲，听歌声、宛转绕屏帏。", "一缕龙香水麝，满堂如彩云飞。", "金卮主献宾酬。", "无算数醉如泥。", "诮不管山翁，霜髯皓鬓，为插花枝。", "更阑带花归去，有馀香、冉冉惹人衣。", "一枕华胥梦觉，恍然身在桃溪。"]'),
('song-ci-709','胜胜慢・声声慢','李商英','宋','宋词','song-ci','胜胜慢・声声慢','[]','香浮椒柏，暖入酴酥，非烟晓生帘幕。',119,'宋词/ci.song.20000.json','["香浮椒柏，暖入酴酥，非烟晓生帘幕。", "绛阙真仙，来自五云楼阁。", "青霁路岐游遍，排冠归、水晶城郭。", "萧散处，有壶中日月，故园猿鹤。", "好是朱颜难老，嬉游处，不减少年行乐。", "正好寻春，莫负燕期莺约。", "沉沉洞天向晚，按官商、重调音乐。", "愿岁岁，听新声，笙歌院落。"]'),
('song-ci-710','水调歌头','马伯升','宋','宋词','song-ci','水调歌头','[]','瑞应杉溪县，光动极星宫。',115,'宋词/ci.song.20000.json','["瑞应杉溪县，光动极星宫。", "人间盛事此日，岳降自高嵩。", "庆兆三阳开泰，散作一团和气，无地不春风。", "眉寿八千岁，今代黑头公。", "听剑履，上星辰，此行中。", "况金瓯姓字，当路那已达宸聪。", "管取凤池新命，来自虎关上阙，明日到花封。", "王室要师保，叔父勿居东。"]'),
('song-ci-711','满江红','马伯升','宋','宋词','song-ci','满江红','[]','人品如君，人尽道，士林横绝。',114,'宋词/ci.song.20000.json','["人品如君，人尽道，士林横绝。", "那更是、关西流庆，三山英杰。", "欣遇当年神降日，又逢初度阳生月。", "把八千馀岁祝君龄，为君说。", "君自有，封侯骨。", "君不是，栖鸾客。", "况如今东阁，正收人物。", "坦腹素知王逸少，求贤不必商岩说。", "便明朝、有诏自天来，君王礼。"]'),
('song-ci-712','水调歌头','马伯升','宋','宋词','song-ci','水调歌头','[]','和气应鼙鼓，喜色上辕门。',114,'宋词/ci.song.20000.json','["和气应鼙鼓，喜色上辕门。", "貔貅万骑，争相庆主将佳晨。", "遥望九霄上阙，霭霭庆云澄处，一点将星明。", "天瑞不虚应，人杰岂虚生。", "况君家，名将旧，有元勋。", "上方拊髀，要资颇牧作长城。", "管取斋坛入拜，会见凯歌归奏，振起旧家声。", "与国同休语，王府又重盟。"]'),
('song-ci-713','西江月','陈克','宋','宋词','song-ci','西江月','[]','捣玉扬珠万户，膴眉高髻千峰。',58,'宋词/ci.song.20000.json','["捣玉扬珠万户，膴眉高髻千峰。", "佳辰清寿黑头公，老稚扶携欢动。", "借问优游黄倚，何如强健夔龙。", "斝舡一棹百分空，浇泼胸中云梦。"]'),
('song-ci-714','鹧鸪天','陈克','宋','宋词','song-ci','鹧鸪天','[]','风露绢绢玉井莲，霓旌绛节会中元。',64,'宋词/ci.song.20000.json','["风露绢绢玉井莲，霓旌绛节会中元。", "鬓头未学功名晚，金紫由来称长年。", "青作穗，酒如泉。", "蓬莱方丈自飞仙。", "黄麻敕胜长生箓，早送夔龙到日边。"]'),
('song-ci-715','南歌子','陈克','宋','宋词','song-ci','南歌子','[]','凤斝飞醇酎，龙筵喷异香。',62,'宋词/ci.song.20000.json','["凤斝飞醇酎，龙筵喷异香。", "又还仁还祝延长。", "正对金风玉露、爽秋光。", "一种庄椿老，五杸仙桂芳。", "当年天产窦家郎。", "须信来春同此、赋高唐。"]'),
('song-ci-716','南歌子','陈克','宋','宋词','song-ci','南歌子','[]','爱日烘晴昼，轻寒护晓霜。',62,'宋词/ci.song.20000.json','["爱日烘晴昼，轻寒护晓霜。", "小春庭院绕天香。", "仙风珊珊来自、五云乡。", "庭下芝兰秀，壶中日月长。", "要看发绿与瞳方。", "一笑人间千岁、饮淋浪。"]'),
('song-ci-717','新荷叶','李清照','宋','宋词','song-ci','新荷叶','[]','薄露初零，长宵共、永昼分停。',104,'宋词/ci.song.20000.json','["薄露初零，长宵共、永昼分停。", "绕水楼台，高耸万丈蓬瀛。", "芝兰为寿，相辉映、簪笏盈庭。", "花柔玉净，捧觞别有娉婷。", "鹤瘦松青，精神与、秋月争明。", "德行文章，素驰日下声名。", "东山高蹈，虽卿相、不足为荣。", "安石须起，要苏天下苍生。"]'),
('song-ci-718','寿星明・沁园春','莫蒙','宋','宋词','song-ci','寿星明・沁园春','[]','翠樾阴浓，见嵩山洛水，紫薇光聚。',119,'宋词/ci.song.20000.json','["翠樾阴浓，见嵩山洛水，紫薇光聚。", "鷟雏华飞，黄驹骏天下，夜擎香露奋身许玉斧，来作明堂一柱。", "试看人间，谁能具此，神峰眉宇。", "烟缕摇曳暗雾。", "想高正簇清歌妍舞。", "黑蚌生珠，蟠桃结子，从此几回相遇。", "去天尺五，人望城南韦杜，画戟衣翻，门施行马，行看开府。"]'),
('song-ci-719','瑞庭花引','莫蒙','宋','宋词','song-ci','瑞庭花引','[]','对画帘卷，正钩挂虾须细锦幄。',106,'宋词/ci.song.20000.json','["对画帘卷，正钩挂虾须细锦幄。", "展凤屏。", "开朱户。", "初启宝兽，香飘龙麝，袅袅烟成穗。", "神仙宴满座，瑞色笼金翠。", "□□□窈窕，秦娥唱，行云散，梁□坠。", "花满帽，酒盈樽，长富长贵。", "唯愿如松似□，永保千秋岁。", "红日晚笙歌，拥入瑶池醉。"]'),
('song-ci-720','江城子','莫蒙','宋','宋词','song-ci','江城子','[]','博山香暖衬江云。',86,'宋词/ci.song.20000.json','["博山香暖衬江云。", "舞飞琼。", "拜双成。", "雾鬓风鬟，不改旧时青。", "滟滟金船罗袖劝，齐祝寿，比松椿。", "照人冰雪自天真。", "翠绡轻。", "下蓬瀛。", "却笑乘鸾，奔月望长生。", "曾侍瑶池王母宴，犹认得，佩环声。"]'),
('song-ci-721','江城子','莫蒙','宋','宋词','song-ci','江城子','[]','秋堂风露月初弦。',86,'宋词/ci.song.20000.json','["秋堂风露月初弦。", "望灵源。", "隐珠躔。", "曾许东皇，游戏了尘缘。", "四海声名收不得，麾玉节，下清关。", "相逢只说好江山。", "紫宸班。", "待公还。", "压帽黄花，喜映两眉间。", "袖里春风医国手，应不惜，紫金丹。"]'),
('song-ci-722','念奴娇','宝月','宋','宋词','song-ci','念奴娇','[]','延陵福绪，蔼遗芳馀庆，直至如今。',119,'宋词/ci.song.20000.json','["延陵福绪，蔼遗芳馀庆，直至如今。", "帝锡朋龟曾献策，早揖丹桂华簪。", "一代荣名，三州遗爱，留入歌吟。", "归来湖山付得，依旧闲心。", "延赏报德推封。", "名迁书监，喜天恩重临。", "拜舞龙香还注想，丹阙拖紫垂金。", "酒满霞觞，期君眉寿，千岁与披衿。", "年年风月，两行门外桐阴。"]'),
('song-ci-723','菩萨蛮','邓肃','宋','宋词','song-ci','菩萨蛮','[]','乳羝属国归来早。',52,'宋词/ci.song.20000.json','["乳羝属国归来早。", "知君胆大身犹小。", "一节不须论。", "功名看致君。", "镇西楼上酒。", "父老为君寿。", "更寿太夫人。", "年年封诏新。"]'),
('song-ci-724','水龙吟','曾','宋','宋词','song-ci','水龙吟','[]','去年看月诗成，援毫曾寄鄞江守。',125,'宋词/ci.song.20000.json','["去年看月诗成，援毫曾寄鄞江守。", "流传乐府，惭非宾客，竹枝杨柳。", "今岁江楼，载勤歌扇，青蛾应奏。", "况铃斋初驻，凉生燕寝，有香雾凝清昼。", "遥想十洲三岛，对冰轮、寒光依旧。", "主人来自，清都碧落，天香满袖。", "寄语嫦娥，剩留清照，时为公寿。", "恐明光诏下，翩然归去，试为霖手。"]'),
('song-ci-725','洞仙歌','严抑','宋','宋词','song-ci','洞仙歌','[]','云车鹤盖，三岛朝元后。',101,'宋词/ci.song.20000.json','["云车鹤盖，三岛朝元后。", "绿意红情在梅柳。", "想仙风从碧落次，吹得春来甘泉，喜见颜红宇秀。", "承明厌直，小憩苹洲，箫鼓行春此时候。", "华堂深苍耸，天女遥闻，凭细问，应得年长视久。", "喜苕霅邦人咏恩波，原有酒如渑，与公为寿。"]'),
('song-ci-726','鹧鸪天','沈长卿','宋','宋词','song-ci','鹧鸪天','[]','瑞气氤氲入绛纱。',64,'宋词/ci.song.20000.json','["瑞气氤氲入绛纱。", "水沉香荐碧流霞。", "疏梅欲破风前蕊，冷菊犹开霜后花。", "销粉黛，减铅华。", "药炉经卷好生涯。", "络滨侍从他年贵，便是蟠桃王母家。"]'),
('song-ci-727','南乡子','张浚','宋','宋词','song-ci','南乡子','[]','迟日惠风柔。',66,'宋词/ci.song.20000.json','["迟日惠风柔。", "桃李成阴绿渐稠。", "把酒樽前逢盛旦，凝眸。", "十里松湖瑞气浮。", "功业古难侔。", "宜在凌烟更上头。", "已向眉间浮喜气，风流。", "千岁三分万户侯。"]'),
('song-ci-728','水龙吟','胡寅','宋','宋词','song-ci','水龙吟','[]','玉梅冲腊传香，瑞蓂秀荚开三四。',126,'宋词/ci.song.20000.json','["玉梅冲腊传香，瑞蓂秀荚开三四。", "莲花沉漏，熊罴占应，洛阳名裔。", "岁比甘罗，便疏同队，累棋观志。", "向修文寓直，仙楼侍宴，梁王宝、真难俪。", "多少襟怀未试，暂超然、壶中游戏。", "行看献策，归瞻旒藻，常勋斿记。", "歌畔巫云，舞回邹管，金钗扶醉。", "有阴功不乞，丹砂十纪，寿祺全畀。"]'),
('song-ci-729','满庭芳','鲁','宋','宋词','song-ci','满庭芳','[]','坐啸蓬宫，移旌天府，往来三岛十洲。',117,'宋词/ci.song.20000.json','["坐啸蓬宫，移旌天府，往来三岛十洲。", "况瑞霭当年，初下琼楼。", "自是长生伴侣，那堪更河润神州。", "人争叹，威名福寿，衮衮压潮头。", "金瓯。", "须满泛，天厨禁脔，相酝□□。", "□□□□日，此会风流。", "正是湖山春媚，千秋岁、□□民猷。", "还知道，金瓯未拜，先拜富民侯。"]'),
('song-ci-730','雨中花・夜行船','陆凝之','宋','宋词','song-ci','雨中花・夜行船','["\u5cb3\u9633\u697c"]','三百年间，青史几多人物，俱委埃尘。',117,'宋词/ci.song.20000.json','["三百年间，青史几多人物，俱委埃尘。", "独先生斯世，炼气成神。", "将我一支丹桂，换他千载青春。", "岳阳楼上，纱巾羽扇，谁识天人。", "千山短褐，掬水擎花，为君增祝灵椿。", "遥想望、吹笙坐殿，奏舞鸾裀。", "凤驭云帲不散，碧桃紫李长新。", "愿分馀沥，九霞光里，相继朝真。"]'),
('song-ci-731','满庭芳','鮦阳居士','宋','宋词','song-ci','满庭芳','[]','良月霜清，小春寒浅，瑞庭蓂荚双飞。',117,'宋词/ci.song.20000.json','["良月霜清，小春寒浅，瑞庭蓂荚双飞。", "岭梅香度，初发向南枝。", "此际高门袭庆，真金降、金璧生辉。", "传瀛海向歆父子，相继大名垂。", "广寒，山藉在，笔驱造化，夕照虹霓。", "暂徘徊、莲幕名誉交驰。", "行继夔龙步武，蓬山静、玉宇春迟。", "当清夜，神交大一，相对熟青藜。"]'),
('song-ci-732','醉蓬莱','赵士','宋','宋词','song-ci','醉蓬莱','[]','正春风初扇，梅蕊飘香，雨馀晴昼。',120,'宋词/ci.song.20000.json','["正春风初扇，梅蕊飘香，雨馀晴昼。", "箫鼓声中，麝烟喷金兽。", "幕府宾僚，杜诗韩笔，竟吐奇争秀。", "共指乔松，同瞻峻岳，祝公眉寿。", "汉相功勋，陈思文藻，奕世风流，迥居人右。", "持节分符，屡试经邦手。", "天府剧烦，雍容谈笑，令闻光前后。", "君相恩隆，公圭金印，一时亲授。"]'),
('song-ci-733','庆清朝','李朴','宋','宋词','song-ci','庆清朝','[]','晓庭天离，擎香肖紫，严瑞气满春彰。',118,'宋词/ci.song.20000.json','["晓庭天离，擎香肖紫，严瑞气满春彰。", "勋门旧擎，从来功在江南。", "二百岁中阴德去，今天府享潭潭。", "遵画一，记得那时，□□□□。", "且趁东风解冻，向柳梢青处，□□□□。", "□□听满，此夕何惜醺酣。", "醉挹寿卿春色，一帘花影转微蟾。", "千秋岁，愿祝算数□，多似彭聃。"]'),
('song-ci-734','少年游','温镗','宋','宋词','song-ci','少年游','[]','东风先报上林春。',60,'宋词/ci.song.20000.json','["东风先报上林春。", "枝上晓莺新。", "凌虹御气，鞭鸾翳凤，来辅玉晨君。", "稳步丹墀青云路，金鼎侍调羹。", "南极光中，五云多处，长伴老人星。"]'),
('song-ci-735','少年游','温镗','宋','宋词','song-ci','少年游','[]','谢家庭槛晓无尘。',60,'宋词/ci.song.20000.json','["谢家庭槛晓无尘。", "芳宴启良辰。", "风流妙舞，樱桃清唱，依约驻行云。", "榴花一盏浓香满，为寿百千春。", "岁岁年年，共同劝乐，喜庆与时新。"]'),
('song-ci-736','少年游','温镗','宋','宋词','song-ci','少年游','[]','芙蓉花发去年枝。',60,'宋词/ci.song.20000.json','["芙蓉花发去年枝。", "双燕欲归飞。", "兰堂风软，金炉香暖，新曲动帘帷。", "家人拜上千春寿，深意满琼卮。", "绿鬓朱颜，道家装束。", "长似少年时。"]'),
('song-ci-737','折丹桂','温镗','宋','宋词','song-ci','折丹桂','[]','秋风秋露清秋节。',68,'宋词/ci.song.20000.json','["秋风秋露清秋节。", "秋雨过、秋香初发。", "二仙生值好秋天，气却与、秋霜争烈。", "秋霄开宴群仙列。", "秋娘唱、秋云低遏。", "寿杯双劝祝千秋，镇长对、中秋皓月。"]'),
('song-ci-738','念奴娇','芮烨','宋','宋词','song-ci','念奴娇','[]','化工着意，向柳稍梅萼，偷回春色。',120,'宋词/ci.song.20000.json','["化工着意，向柳稍梅萼，偷回春色。", "蓂叶双飞政天上，一点文星初谪。", "发藻儒林，当年荣耀，四海声名白。", "谪仙飞貌，澹然物外踪迹。", "且与笑傲瀛洲，风流词翰，自是西垣客。", "异日功成辞富贵，却与赤松游剧。", "一曲清歌，三千珠履，不愧非潘璧。", "满斟芳醑，仰称遐寿千百。"]'),
('song-ci-739','蓦山溪','傅自得','宋','宋词','song-ci','蓦山溪','[]','洪钧转处，都在薰陶内。',102,'宋词/ci.song.20000.json','["洪钧转处，都在薰陶内。", "瑞世得奇才，赞化工，协调和气。", "雄词健笔，谈笑斡千钧，馀闲手，尹王畿，治行称尤异。", "雍容儒雅，早合登高位。", "天路踏骅骝，看峨冠，羽仪班缀。", "东风骀荡，王斝酒鳞红，春不老，寿难穷，莫惜今朝醉。"]'),
('song-ci-740','洞仙歌','李鼐','宋','宋词','song-ci','洞仙歌','[]','馀寒未展，帘幕新来燕。',104,'宋词/ci.song.20000.json','["馀寒未展，帘幕新来燕。", "杨柳梢头嫩黄染。", "小溪山缭绕，别是风烟，春澹澹，谁道蓬莱路远。", "冰姿人不老，长伴春闲，环珮声中度芳宴。", "宝屏开，烟袅袅，金鸭吹香，欢笑处，烛影花光共暖。", "便莫惜瑶觞醉如泥，占岁岁东风，舞衣歌扇。"]'),
('song-ci-741','渔家傲','李鼐','宋','宋词','song-ci','渔家傲','[]','日借嫩黄初看柳。',72,'宋词/ci.song.20000.json','["日借嫩黄初看柳。", "池塘冰泮游鱼透。", "庭馆匆匆佳气候。", "□山透。", "膺时贤佐生天佑。", "寿者康宁还德厚。", "功名富贵须长久。", "从此安排千岁酒。", "常祝寿。", "一年一献黄金酎。"]'),
('song-ci-742','鹧鸪天','李鼐','宋','宋词','song-ci','鹧鸪天','[]','种得门阑五福全。',64,'宋词/ci.song.20000.json','["种得门阑五福全。", "常珍初喜庆华筵。", "王环醉拍春衫舞，今见康强九九年。", "神爽朗，骨清坚。", "壶天日月旧因缘。", "从今把定春风笑，且作人间长寿仙。"]'),
('song-ci-743','鹧鸪天','李鼐','宋','宋词','song-ci','鹧鸪天','[]','珍重高人阎右丞。',64,'宋词/ci.song.20000.json','["珍重高人阎右丞。", "胸中丘壑富丹青。", "暂从天下分轺使，来向人间作寿星。", "凉日挂，暑风轻。", "一番秋思十分清。", "细倾鹦鹉休辞劝，烂醉葡菊不用醒。"]'),
('song-ci-744','一井金','李鼐','宋','宋词','song-ci','一井金','[]','绿阴清昼。',50,'宋词/ci.song.20000.json','["绿阴清昼。", "两茸茸、梅子黄时侯。", "华堂金兽。", "香润炉烟透。", "舞燕回轻袖。", "歌凤翻新奏。", "院静人稀，永日迟迟花漏。"]'),
('song-ci-745','一井金','李鼐','宋','宋词','song-ci','一井金','[]','一杯为寿。',55,'宋词/ci.song.20000.json','["一杯为寿。", "笑捧处、自传织手钗头。", "况有瑞草，齐眉偕老，应难比效。", "鸳鸾镇日于飞，惟愿一百二十岁，永同欢，如鱼似水。"]'),
('song-ci-746','风入松','李鼐','宋','宋词','song-ci','风入松','[]','翠烟笼日上花梢。',84,'宋词/ci.song.20000.json','["翠烟笼日上花梢。", "花外楼高。", "海犀不动帘栊静，昼长人懒莺娇。", "宝篆浓薰沉水，清商低按擅槽。", "画堂深处燕蟠桃。", "亲见仙曹。", "雾鬟不改朱颜好，年年长被春饶。", "一品疏封它日，十分沉醉今朝。"]'),
('song-ci-747','玉蝴蝶','李鼐','宋','宋词','song-ci','玉蝴蝶','[]','望处水寒云绕，倚栏千里，澹荡晴晖。',123,'宋词/ci.song.20000.json','["望处水寒云绕，倚栏千里，澹荡晴晖。", "梦燕门阑，和气喜动帘帏。", "舞裀重、花明彩凤，歌扇小、香暖金猊。", "漏声迟。", "洞天秋晓，风露霏霏。", "嘉时。", "谪仙高宴，华分玉蜡，艳列文姬。", "玉树临风，自然老月中枝。", "酒肠宽、胸容云梦，词源壮、笔勇助溪。", "且追随。", "伫看飞诏，稳步沙堤。"]'),
('song-ci-748','满庭芳','李鼐','宋','宋词','song-ci','满庭芳','[]','腊雪溶酥，春冰浮玉，素蟾三五才过。',118,'宋词/ci.song.20000.json','["腊雪溶酥，春冰浮玉，素蟾三五才过。", "晓来庭户，何事五云多。", "尽道九天麟坠，╆环珮、袅袅鸣珂。", "风标爽、胸中嵬磊，豪气挽天河。", "平生，横溯志，指挥夷虏，平定干戈。", "看它年功业，还让廉颇。", "且对江山难老，金樽满、鲸海翻波。", "歌声转，玉人扶处，拚取醉颜酡。"]'),
('song-ci-749','鹧鸪天','韩元吉','宋','宋词','song-ci','鹧鸪天','[]','雨歇云如隔座屏。',64,'宋词/ci.song.20000.json','["雨歇云如隔座屏。", "薰风摇动一天青。", "今年五十平头过，又喜清歌洗耳听。", "浮世事，绝曾经。", "此生应直斗牛星。", "且倾田舍黄鸡酒，敢望君家白玉庭。"]'),
('song-ci-750','鹧鸪天','韩元吉','宋','宋词','song-ci','鹧鸪天','[]','万古光寒太白精。',64,'宋词/ci.song.20000.json','["万古光寒太白精。", "直宜分作两郎星。", "不然安得难兄弟，先后尧蓂三荚生。", "霜月冷，斗杓横。", "老人今夜已齐明。", "他年莫作郎星看，两两台躔拱太清。"]'),
('song-ci-751','满庭芳','张抡','宋','宋词','song-ci','满庭芳','[]','威彻冰河，兵严玉帐，济时人在壶天。',118,'宋词/ci.song.20000.json','["威彻冰河，兵严玉帐，济时人在壶天。", "妙龄谈笑，图画上凌烟。", "但见勋书鼎鼐，谁知道、名列高仙。", "风云会，钩陈羽卫，绿鬓影貂蝉。", "绵绵。", "流庆远，芝兰秀发，折桂争先。", "占盛一门，文武更双全。", "已饵琼英绛雪，灵龟寿、何止千年。", "年年看，笙歌丛里，金盏倒垂莲。"]'),
('song-ci-752','鹧鸪天','张抡','宋','宋词','song-ci','鹧鸪天','[]','鹤驭来从玉席前。',64,'宋词/ci.song.20000.json','["鹤驭来从玉席前。", "笑谈勋业照凌烟。", "心游物外都无碍，春在壶中别有天。", "香似雾，酒如泉。", "华堂冰雪映神仙。", "灵椿不老青松健，花里年年醉管弦。"]'),
('song-ci-753','鹧鸪天','张抡','宋','宋词','song-ci','鹧鸪天','[]','彩舞萱堂喜气新。',64,'宋词/ci.song.20000.json','["彩舞萱堂喜气新。", "年年今日庆生辰。", "碧凝香雾笼清晓，红入桃花媚小春。", "须酩酊，莫逡巡。", "九霞杯冷又重温。", "壶天自是人难老，长拥笙歌醉洞云。"]'),
('song-ci-754','鹧鸪天','张抡','宋','宋词','song-ci','鹧鸪天','[]','五福仙娥月殿来。',64,'宋词/ci.song.20000.json','["五福仙娥月殿来。", "依稀微步彩云随。", "一从别有瑶池宴，不见蟠桃几度开。", "歌宛转，舞徘徊。", "碧梧秋意满池台。", "年年玉露收残暑，长送新凉入寿杯。"]'),
('song-ci-755','鹧鸪天','张抡','宋','宋词','song-ci','鹧鸪天','[]','消息枝头梅子黄。',64,'宋词/ci.song.20000.json','["消息枝头梅子黄。", "两宫恩意酿湖光。", "长庚自是文章瑞，好伴前星烛万方。", "金鸭暖，玉杯香。", "换鹅笔墨醉淋浪。", "只将名字为公祝，便合千秋佐玉皇。"]'),
('song-ci-756','鹧鸪天','张抡','宋','宋词','song-ci','鹧鸪天','[]','福善天应锡寿祺。',64,'宋词/ci.song.20000.json','["福善天应锡寿祺。", "人生七十古来稀。", "我翁更有椿龄在，馀庆堂前玉树辉。", "传世业，长孙枝。", "捧杯欢见老莱衣。", "一阳渐近门多喜，百禄争迎好事归。"]'),
('song-ci-757','画堂春','张抡','宋','宋词','song-ci','画堂春','[]','月娥来自广寒宫。',55,'宋词/ci.song.20000.json','["月娥来自广寒宫。", "步摇环珮丁东。", "戏鸾双舞驾天风。", "雪满云空。", "一剪玉梅花小，九霞琼醴杯浓。", "凤箫千载莫匆匆。", "且醉壶中。"]'),
('song-ci-758','望仙门','张抡','宋','宋词','song-ci','望仙门','[]','玉池波浪碧如鳞。',51,'宋词/ci.song.20000.json','["玉池波浪碧如鳞。", "露莲新。", "新歌一曲翠眉嚬。", "舞乖裀。", "满酌兰英酒，须知献寿千春。", "太平无事荷君恩，齐唱望仙门。"]'),
('song-ci-759','望仙门','张抡','宋','宋词','song-ci','望仙门','[]','玉京清漏起微凉。',51,'宋词/ci.song.20000.json','["玉京清漏起微凉。", "好秋光。", "金杯潋滟酌琼浆。", "会仙乡。", "新曲调丝管，新声更飐霓裳。", "博山炉暖泛浓香。", "为寿百千长。"]'),
('song-ci-760','望仙门','张抡','宋','宋词','song-ci','望仙门','[]','紫微枝上露华浓。',51,'宋词/ci.song.20000.json','["紫微枝上露华浓。", "起秋风。", "管弦声细出帘栊。", "象筵中。", "仙酒斟云液，山歌转绕梁虹。", "此时佳会庆相逢。", "欢醉且从容。"]'),
('song-ci-761','水调歌头','侯置','宋','宋词','song-ci','水调歌头','["\u6d1e\u5ead\u6e56"]','白鹤到时节，霜信满南州。',114,'宋词/ci.song.20000.json','["白鹤到时节，霜信满南州。", "金盘露重，银潢波浪载天流。", "岳渎千龄锺秀，赋出人间英气，清照洞庭秋。", "烈日严霜操，竹简万年留。", "苏属国，二千秩，若为酬。", "杜园阴密，未央前席动宸旒。", "入践紫薇郎省，擢赞绿槐公位，指日凤池游。", "千顷玉芝熟，准备饭青牛。"]'),
('song-ci-762','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','八月秋欲半，后夜月将圆。',114,'宋词/ci.song.20000.json','["八月秋欲半，后夜月将圆。", "天潢当日流润，□派落人寰。", "尘扫长淮千里，威振南蛮八郡，梓里绣衣还。", "芳毓燕山桂，庆衍谢庭兰。", "小山阴，长松下，白云间。", "壶中自有天地，闻早挂逢冠。", "笑指横空丹壑，闲倚拿云竹杖，佳处日跻攀。", "山色既无尽，公寿亦如山。"]'),
('song-ci-763','水龙吟','赵彦端','宋','宋词','song-ci','水龙吟','["\u897f\u6e56"]','两山空翠烟霏，几□又入东君□。',126,'宋词/ci.song.20000.json','["两山空翠烟霏，几□又入东君□。", "□□但见，肉红染杏，眉黄着柳。", "彩燕风轻，宝灯月满，欢连清昼。", "是香山行处，苏仙座上，春不老，人依旧。", "闻道新骑白凤，过章台、天香满袖。", "英姿不向，通明宫殿，人间未有。", "况是从来，爱留南国，名高北斗。", "看君恩，却与西湖涨绿，作长生酒。"]'),
('song-ci-764','菩萨蛮','芮辉','宋','宋词','song-ci','菩萨蛮','[]','晴云低蘸湖光湿。',52,'宋词/ci.song.20000.json','["晴云低蘸湖光湿。", "新凉远带江声入。", "风影逼中秋。", "移樽月在楼。", "蓝田栽竹手。", "借竹为君寿。", "苍翠一年年。", "长承雨露边。"]'),
('song-ci-765','虞美人','芮辉','宋','宋词','song-ci','虞美人','[]','翠屏罗幕遮前后。',66,'宋词/ci.song.20000.json','["翠屏罗幕遮前后。", "舞袖翻长寿。", "紫髯冠珮御炉香。", "看取明年归奉、万年觞。", "今宵池上蟠桃席。", "咫尺长安日。", "宝烟飞焰万花浓。", "试看中间白鹤、驾仙风。"]'),
('song-ci-766','念奴娇','刘季裴','宋','宋词','song-ci','念奴娇','[]','三光五岳，震乾坤英彩，非金非玉。',120,'宋词/ci.song.20000.json','["三光五岳，震乾坤英彩，非金非玉。", "赫赫岩岩真相种，来跨横空仙鹄。", "十万儿童，和丰堂下，齐把梅山祝。", "黑头难老，岁寒苍桧修竹。", "须信自有家传，中庸一卷，是长生真箓。", "借问河阳公去后，几度桃开桃熟。", "十九年间，梦回天上，又见棠阴绿。", "看看促觐，喜传沙路新筑。"]'),
('song-ci-767','满庭芳','姜特立','宋','宋词','song-ci','满庭芳','[]','丹染吴枫，青环越岫，镜天霁色凝鲜。',117,'宋词/ci.song.20000.json','["丹染吴枫，青环越岫，镜天霁色凝鲜。", "华堂珊珮，非务拥神仙。", "天遣澄清海岳，亲曾授黄石奇编。", "兴王略，智名俱泯，功业妙难言。", "翩翩。", "真迥立，香飘绣衮，色映貂蝉。", "有清诗千首，美酒如川。", "长与嫦娥共约，放冰轮，今夕先圆。", "中秋月，从今屈指，更借一千年。"]'),
('song-ci-768','促拍满路花','徐叔至','宋','宋词','song-ci','促拍满路花','[]','人间秋正好，天上月才圆。',102,'宋词/ci.song.20000.json','["人间秋正好，天上月才圆。", "玉霄人不老，对婵娟。", "五龙护日，一笑着貂蝉。", "禁殿开金钥，宝炬宫壶，诏催移下钓天。", "昴奎分秀采，箕翼与长年。", "华堂歌宛转，舞蹁跹。", "醉围红袖，妙墨起风烟。", "回首恩波地，身在江湖，为公一赋新篇。"]'),
('song-ci-769','鹧鸪天','徐叔至','宋','宋词','song-ci','鹧鸪天','[]','两两台符映昴躔，南熏披拂寿炉烟。',64,'宋词/ci.song.20000.json','["两两台符映昴躔，南熏披拂寿炉烟。", "宝图继统千龄会，金铉调元一相贤。", "兰玉满，庆蝉联。", "天教世有鲁山川。", "霞觞更对瑶池佲，共看蟠桃着子年。"]'),
('song-ci-770','鹧鸪天','范成大','宋','宋词','song-ci','鹧鸪天','[]','仗下仪客笔下文。',64,'宋词/ci.song.20000.json','["仗下仪客笔下文。", "天风驾鹤住仙真。", "榴花三日迎端午，蕉叶千春纪诞辰。", "经圀志，立朝身。", "暂烦高手活吴民。", "明朝莫遣书丹篆，怕引新符刻玉麟。"]'),
('song-ci-771','洞仙歌','范成大','宋','宋词','song-ci','洞仙歌','[]','碧城风物，有湖中天地。',99,'宋词/ci.song.20000.json','["碧城风物，有湖中天地。", "长笑羲娥不停轨。", "记蟠桃枝上，金母嗔尝，回首处，还又三千岁矣。", "料仙人拊顶，曾授长生，名在云琼赐书里。", "懒上郁萧台，应厌高寒，飘然下，赤城游戏。", "且山泽留连作臞仙，不要管蓬莱海中尘起。"]');
